INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(18, 'BRASIER CORRECTOR DE POSTURA CON COPAS PREHORMADAS SIN ARCO', '11936L', 'mujer', 'leonisa', '¡Este bra es buenísimo para muchas cosas, igual que tú! Una capa doble de DuraFit® en forma de X, lleva tus hombros hacia atrás y te ayuda a sentarte con la espalda recta. Este innovador estilo, puede aliviar tus dolores de espalda al corregir tu postura. Sus copas prehormadas, cuentan con doble capa de DuraFit®, dándole más soporte a tu busto, excelente cubrimiento y perfecta modelación. Las cargaderas anchas, suaves y graduables de este brasier, te ayudan a soportar el peso del busto y así, reducir el dolor en los hombros. ¿Sientes que ya lo conocías? Es porque nace de nuestro Corrector de postura original (011473), ¡pruébate los dos!', 'Usos recomendados:\r\n- Postquirúrgico: este bra comprime y da soporte cómodamente mientras te recuperas de tu cirugía\r\n- Puede ayudarte a reducir los dolores de espalda\r\n- Perfecto para todos los días: es tan cómodo, que vas a olvidar que lo llevas puesto\r\n- Para practicar deportes: sin importar qué hagas, este bra te da todo el soporte que buscas\r\n- Para lactancia: tiene un broche frontal que lo hace muy fácil de usar', 473.28, 'si'),
(19, 'Brasier de gran cubrimiento: Deep Coverage Bra', '11995', 'mujer', 'leonisa', '- Brasier de copas triangulares de muy buen cubrimiento del busto.\r\n- Arcos para dar excelente soporte.\r\n- Copas en espuma que se adaptan a la forma del busto dando una modelación natural.\r\n- Delicado encaje en las copas y la base que le dan look más moderno y romántico (el encaje que recibas - puede tener un cambio sutil en el diseño con respecto a la foto).\r\n- Cargaderas anchas muy cómodas y acolchadas. No removibles y graduables.', 'Siente toda la comodidad y el soporte con este brasier diseñado para busto mediano y grande. Sus copas triangulares cubren completamente el busto; además, su cubrimiento en sisa y espalda lo hace ideal para aquellas mujeres que buscan disimular y ocultar los rollitos en esta zona. Cuenta con arcos para dar un excelente soporte. Sus copas en espuma suave y liviana, sin realce incorporado, se adapta a la forma de tu busto brindándote una modelación mucho más natural. Sus cargaderas anchas y acolchadas no se sienten ni incomodan los hombros. El encaje en base, copas y cargaderas lo hacen más romántico y femenino.', 501.12, 'si'),
(20, 'BUSTIER DE ESCOTE PROFUNDO CON ARCO Y DOBLE REALCE', '11873', 'mujer', 'leonisa', 'Brasier con escote superprofundo y copas que centran y aumentan dos tallas de copa para darte un realce extremo. Al ser estilo bustier, estiliza la parte alta de tu abdomen y sus laterales. Las copas tienen incorporada una espuma liviana que tiene la capacidad de volver a su forma original y se adaptan a la forma de tu busto con total comodidad. Cubre el contorno de la base del busto con delicados toques de encaje SmartLace®, haciendo de esta prenda una de las más sensuales que vas a encontrar.', 'Bustier de doble realce con escote profundo.\r\nIdeal para busto pequeño y regular.\r\nCopas con espuma suave incorporada que aumenta, levanta y centra el busto.\r\nArco interno para dar excelente soporte.\r\nComposición: poliamida 81%, elastano 19%.\r\nEspalda de tul con el encaje SmartLace® bordado que genera transparencias.\r\nCargaderas removibles para usar de forma convencional, cruzado o halter.\r\nColores en contraste, con hilos de dos tonos que dan un toque muy femenino.', 452.4, 'si'),
(21, 'PIJAMA PANTALÓN', '2560062', 'mujer', 'touche', 'Pijama camisa manga corta en poliéster y straplesS en lycra nylon. Pantalón largo en viscosa.', 'Un estilo donde comodidad y elegancia no riñen, sino que se complementan. Las pijamas se convierten en tus aliadas perfectas para mantener siempre viva la llama de la pasión, el proceso de la conquista se construye día a día. La clave es saber escoger la pijama adecuada para cada ocasión o momento de tu relación.', 501.12, 'si'),
(22, 'CHALECO COMPRESIVO CORRECTOR DE POSTURA', '11173PLUS ', 'mujer', 'fajate', 'Faja de uso diario de alta compresión y total cubrimiento de espalda. 3 medidas de broches. Con varillas internas para mayor firmeza y corrección de postura. \r\n', 'Esta es una de nuestras fajas de uso diario, reductoras de fuerte compresión y espalda alta. sus broches tienen tres posiciones que se ajustan a tu medida. Es busto libre. Para uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.\r\nCuenta con 3 varillas internas para brindar mayor firmeza, telas con componentes VivelTex, que nutren, regeneran e hidratan la pie.\r\n', 675.12, 'si'),
(23, 'BRASIER POSTQUIRÚRGICO Y CORRECTOR DE POSTURA', '11065', 'mujer', 'fajate', 'Brasier postquirúrgico, elaborado en una tela elástica y compresiva, de alto cubrimiento y control en la espalda para una mejor postura.', 'CARACTERISTICAS\r\nColor: Café\r\nGénero: Mujer\r\nNivel de control: Media\r\nZona de control: Busto\r\nMecanismos de ajuste: Broche\r\nMaterial: spandex\r\n\r\nCuidados de la prenda\r\n? El lavado: preferiblemente A MANO. Evite el uso de secadora. \r\n? Utilizar preferiblemente el Jabón Fajate\r\n? Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) \r\n? Lavar separadamente \r\n? Secar a la sombra\r\n? No utilizar blanqueadores', 417.6, 'si'),
(25, 'BRASIER POSTQUIRÚRGICO ', '11181', 'mujer', 'fajate', 'Brasier postquirúrgico, con broches frontales y tiros ajustables.\r\n', 'Es un brasier postquirúrgico para mamoplastía, realza y moldea el busto naturalmente. Copas prohormadas, sin varillas. Tiene broches centrales y control de espalda.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.\r\n', 403.68, 'si'),
(26, 'BRASIER POSTQUIRÚRGICO', '11027', 'mujer', 'fajate', 'Este brasier con copas prehormadas sin varillas es perfecto durante la etapa de recuperación. Su broche central facilita la postura y da la compresión justa, ayuda a centrar el busto y mejora el proceso de desinflamación.', 'Nivel de control\r\nMedio\r\nZona de moldeo\r\nBusto\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nspandex\r\nBeneficios\r\n? Brasier con copas prehormadas sin varillas. ? La base del busto es ancha para brindar mayor soporte. ? Cubrimiento alto en busto. ? Elaborado en una tela elástica y compresiva para dar control con suavidad. • Elaborado con telas con componentes Viveltex. •Broches centrales para mayor ajustes.\r\nCuidados de la prenda\r\nLava preferiblemente a mano. Evita el uso de secadora. Utiliza jabón suave, preferiblemente el jabón especial para prendas Fájate. Lava separadamente. Seca a la sombra y no utilices blanqueadores. Al ponértela, evita usar accesorios que puedan dañar la prenda (anillos, pulseras y uñas largas).', 403.68, 'si'),
(27, 'BRASIER MATERNO X', '11057', 'mujer', 'fajate', 'Este es un brasier especial para el periodo de lactancia, elaborado en  algodón, con broches en la unión de las copas para mayor comodidad y funcionalidad. sus costuras elásticas son ultraplanas, suaves al contacto con la piel.', 'Nivel de control\r\nMedio\r\nUsos recomendados\r\nMaterna\r\nZona de moldeo\r\nBusto\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nspandex\r\nBeneficios\r\n? Elaborado en algodón para cuidar la piel sensible. • Práctico broche que facilitan la lactancia • Tipo top, discreto y versátil. • Elástico en la base del busto para dar soporte.\r\nCuidados de la prenda\r\n• El lavado: preferiblemente A MANO. Evite el uso de secadora. • Utilizar preferiblemente el Jabón Fajate• Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) • Lavar separadamente • Secar a la sombra• No utilizar blanqueadores.', 334.08, 'si'),
(28, 'TOP POSTQUIRÚRGICO FIT 360', '11348', 'mujer', 'fajate', 'Brasier postquirúrgico y deportivo de la colección FIT 360. Prenda que ayuda a tu postura y moldea tu torso superior, desarrollado en tela elástica y compresiva, de alto cubrimiento en la espalda, costados y en el molesto gordito del \"brasier\". Cuenta con Abrochadura en hombro y frente, para fácil colocación.', 'Nivel de control\r\nMedio\r\nZona de moldeo\r\nBustoEspalda\r\nMecanismos de ajuste\r\nBroche\r\nBeneficios\r\n? Top con talle mas largo que el 065, especial para realzar tu figura y mejora tu postura. ? Prenda post-quirurgica de facil uso. ? Levante busto, y control adicional en laterales y el molesto gordito del brasier. ? Refuerzo en \"X\" que brinda un excelente soporte de espalda. ? Broches en hombros e 3 hileras para graduar de acuerdo a tu necesidad y a tus medidas. ? Esta prenda esta  diseñada con costuras planas y lisas que impide que se note con tu ropa. • Tejidos cómodos que apenas notaras que la llevas puesta. • Cuenta con molde especial y materiales compresivos y elativos para un fit perfecto . • Forro con tejido espandex y tratamientos especiales que brindan total suavidad. • Es un brasier post quirúrgico, deportivo y uso diario, con copas sin varillas con mejor cubrimiento., • Perfecto moldeo de cintura alta, que afina tu silueta superior 360 grados. • Ofrece mejor soporte incluso haciendo deportes de alto impacto.\r\n', 445.44, 'si'),
(29, 'BRASIER POSTQUIRURGICO PARA BUSTO Y BRAZOS  ', '11377', 'mujer', 'fajate', 'Brasier postquirúrgico sin arcos, multifuncional para cirugías de busto. Su diseño incluye un refuerzo en X en la espalda, proporcionando ajuste y postura mejorada. Con cubrimiento del busto y abrochadura frontal de 9 ganchos para facilitar la postura. Recomendado por médicos tras cirugías de busto y brazos para evitar inflamación. Ofrece soporte alto y comodidad, con banda elástica e', '- Brasier que facilita la postura, con espalda elaborada en tela powernet de alta compresión y refuerzo en X para \r\n  mayor ajuste.\r\n- Ideal como postquirúrgico: controla y da soporte al busto, brazos y espalda, ajustándose perfectamente.\r\n- Cubre los laterales de la sisa para disimular los rollitos en esta zona.\r\n- Tela con microcápsulas que benefician la piel y ayudan a reducir la inflamación por retención de líquidos.\r\n- Incluye banda en la base del busto que ofrece excelente soporte, copas con cubrimiento total y modelación natural.', 570.72, 'si'),
(30, 'BRASIER ESSENTIAL', '15078', 'mujer', 'fajate', 'Este brasier es ideal para aquellas mujeres que buscan definir y estilizar los rollitos que se encuentran entre la zona axilar y la espalda. Su alto cubrimiento en copas, sisa y espalda, mantiene el busto en su lugar. Es un aliado y complemento perfecto para el uso de la faja ya que logran una definición total.', 'Zona de moldeo\r\nBusto\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\npowernetspandex\r\nCuidados de la prenda\r\nLava a mano y por separado con un jabón suave, preferiblemente con nuestro jabón para el cuidado de prendas Fájate. No utilices blanqueador, no exprimas, ni planches. No retuerzas la prenda, puede dañarse la copa. Seca a la sombra. Al momento de ponertela evita usar accesorios como anillos, pulseras o uñas largas.', 515.04, 'si'),
(31, 'BRASIER SALVIA', '15152', 'mujer', 'fajate', 'Bra Salvia sin copa, cuenta con forro de tela interno que da mayor cobertura en busto y espalda evitando que se formen rollitos en la espalda. Sus delicados detalles en encaje te harán lucir hermosa.', 'Color\r\nBlanco\r\nNivel de control\r\nMedio\r\nUsos recomendados\r\nUso-diario\r\nZona de moldeo\r\nBustoEspalda\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nLycra control\r\nBeneficios\r\nRealza el busto. Sin copas . Control y moldeo en el torso. Prenda versátil para todo uso. Tela suave y fresca.\r\nCuidados de la prenda\r\nLavar a mano y por separado con jabón suave, preferiblemente de Fájate. No utilizar blanqueador, no exprimir, ni planchar. No retorcer ya que se puede dañar la copa. Secar a la sombra. Al momento de ponerla evite usar accesorios como anillos, pulseras o uñas largas.', 668.16, 'si'),
(32, 'BRASIER RUBI', '15167', 'mujer', 'fajate', 'Resalta tu sensualidad con nuestro Bra Rubí, para mujeres seguras, versátiles y románticas, este Bra es perfecto para lucirlo con escotes profundos. Cubre perfectamente busto y espalda, tiene copas push up y un delicado encaje. Cargaderas fijas adelante y graduables atrás para ajustarlo a tu medida. Base ancha que brinda mayor control y soporte, evitando que se te formen rollitos en la zona de las axilas y la espalda. Varillas laterales para una mayor compresión y ajuste. ', 'Nivel de control\r\nMedio\r\nUsos recomendados\r\nUso-diario\r\nZona de moldeo\r\nBustoEspalda\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nLycra control\r\nBeneficios\r\nRealza tu busto - Prenda versátil para todo uso - Control y moldeo en el torso - Con copas - Suave al tacto y fresco.\r\nCuidados de la prenda\r\nLava a mano y por separado con jabón suave, preferiblemente de Fájate. No utilices blanqueador, no lo exprimas, ni aplanches. No lo retuerzas ya que se puede dañar la copa. Seca a la sombra. Al momento de ponértelo evita usar accesorios como anillos, pulseras o uñas largas.', 696, 'si'),
(33, 'BRASIER TAHITÍ', '15183', 'mujer', 'fajate', 'Hermoso brasier en lycra y encaje con escote en V y base ancha para evitar bultos en la espalda.  Cuenta además, con varillas laterales para una mayor compresión en el torso. ', 'Color\r\nAzul\r\nNivel de control\r\nMedio\r\nUsos recomendados\r\nUso-diario\r\nZona de moldeo\r\nBustoEspalda\r\nMaterial\r\nLycra control\r\nBeneficios\r\nRealza tu busto. Prenda versátil para todo uso. Control y moldeo en abdomen y espalda. Con copa.\r\nCuidados de la prenda\r\nLava preferiblemente a mano. Evita el uso de secadora. Utiliza jabón suave, preferiblemente el jabón especial para prendas Fájate. Lava por separado. Seca a la sombra y no utilices blanqueadores. Al ponértela, evita usar accesorios que puedan dañar la prenda (anillos, pulseras y uñas largas).', 696, 'si'),
(41, 'FAJA DE ALTA COMPRESION DE MEDIA PIERNA', '11111', 'mujer', 'fajate', 'Faja de alta compresión post quirúrgica, post parto o de uso diario de media pierna, controla las caderas y realza naturalmente los glúteos. Con busto libre, cubrimiento de espalda,corrige la postura y tiene 3 medidas de broches y doble refuerzo abdominal.\r\n\r\n', 'Faja de alta compresión post quirúrgica, post parto o de uso diario, con 3 medidas de broches frontales y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos.\r\nLos broches frontales brindan un ajuste más firme en el área abdominal, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.', 1057.92, 'si'),
(42, 'Panty Faja Postparto con Mayor Cubrimiento de Abdomen', '12885', 'mujer', 'leonisa', 'Este panty faja crea control en tu cintura y abdomen de una forma práctica. Tiene un sistema de ajuste con velcro en los laterales que te permiten graduarlo al ajuste que deseas. El panel delantero está elaborado en PowerSlim® y DuraFit®, esta combinación de materiales produce el efecto de control garantizándote mayor comodidad', 'Panty de silueta clásica que ofrece control para el abdomen alto, medio y bajo.\r\nIdeal como postparto: te ayuda a recuperar la figura después del embarazo.\r\nAlto cubrimiento en abdomen alto, medio, bajo, cintura y glúteos.\r\nLaterales graduables en velcro para ajustar según el nivel de control que prefieras.\r\nTela elástica lisa DuraFit®, muy suave al contacto con la piel.\r\nPanel delantero en doble capa de PowerSlim® que reduce abdomen.\r\nAbrochadura inferior con tres broches, cuatro niveles de ajuste y refuerzo en algodón.\r\nComposición de la tela: poliamida 86.00%, elastano 14.00%, Composición Forro: poliamida 85.00%, elastano .', 528.96, 'si'),
(44, 'FAJA ESTILO BODY DE CONTROL FUERTE QUE REALZA LOS GLÚTEOS', '18678N', 'mujer', 'leonisa', '-Control fuerte en cintura y abdomen alto, medio y bajo\r\n-Cortes y costuras especiales que realzan, moldean y afinan los glúteos\r\n-Elaborado en PowerSlim: un material de alta resistencia y durabilidad\r\n-Forro interno de DuraFit: tela lisa ultradelgada, fresca y cómoda\r\n-Cierre delantero ultraplano con tres broches internos que facilitan la postura\r\n-Cómodas cargaderas termofusionadas, graduables y removibles\r\n-Abertura inferior para mayor comodidad\r\n-Toques de encaje en las piernas con ajuste suave\r\n-Composición: poliamida 85.00%, elastano 15.00%, Composición Forro: poliamida 74.00%, elastano 21.00%, ALGODÓN 5.00%.', 'Está especialmente diseñada para moldear y controlar zonas específicas de tu cuerpo como: el abdomen, la cintura, la cadera y los glúteos. Tiene costuras especiales que ayudan a darle una forma estilizada a tu figura, especialmente a tus glúteos. Una capa de PowerSlim en la parte exterior, ayuda a controlar tu cuerpo y tiene una capa interna de DuraFit: una tela más suave y fresca. Es una faja cómoda, con cargaderas elásticas removibles, un cierre delantero ultraplano que no se marca en la piel ni en la ropa con tres broches internos para facilitar su postura. Es una prenda que puedes usar todos los días o después de un parto.', 800.4, 'si'),
(45, 'Mentonera postquirúrgica facial con soporte ajustable y compresión', '11513', 'mujer', 'fajate', '- Acelera el proceso de cicatrización\r\n- Ayuda a reafirmar y tonificar los tejidos del rostro\r\n- Sirve como un reductivo de papada y cuello\r\n- Su diseño lo vuelve muy fácil de usar\r\n- Minimiza la inflamación\r\n- Detiene la pérdida de sangre', 'Mentonera postquirúrgica ideal para procedimientos faciales como estiramiento de rostro, levantamiento de cejas, liposucción en cara y cuello, cirugía maxilofacial, y más. Su diseño con ajuste de velcro en la parte superior permite un control personalizado según tus necesidades.\r\n\r\nElaborada en powernet 100% con forro de algodón, esta mentonera ofrece soporte mejorado para mayor comodidad. Es ligera, transpirable y duradera, manteniéndote fresco y cómodo durante todo el día.', 473.28, 'si'),
(46, 'FAJA DE CONTROL TOTAL', '11010', 'mujer', 'fajate', 'Faja postquirúrgica o de uso diario de alto control con cierre lateral, cuenta con brasier incluido, cubrimiento de espalda y doble refuerzo abdominal.', '\"Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme. Ayuda a que las áreas tratadas duelan mucho menos, gracias a la compresión perfecta que brinda al cuerpo. Acelera el proceso de desinflamación, ayudando a una recuperación mas rápida. Acelera el proceso de cicatrización gracias a los componentes impregnados en las telas patentadas (Gingko Biloba, Vitamina E, Algas Marinas, Cosmacol Emi). Ayuda a que la piel se adhiera mas firme al músculo , evitando la retención de líquidos y la formación de fibrosis. Contribuye al drenaje linfático de los tejidos inflamados.Cuenta también con una abertura perineal, para poder ir al baño sin necesidad de quitarse toda la faja.', 480.24, 'si'),
(47, 'Panty short moldeador de control medio con realce de glúteos y efecto adelgazante', '11510', 'mujer', 'fajate', 'Short de control medio que estiliza la figura y disimula la celulitis. Ideal para pantalones ajustados, vestidos o faldas, brinda comodidad y control con su tejido bidireccional. El tiro alto y la pretina de doble capa controlan el abdomen bajo y la cintura.', '- Tejido bidireccional que controla y brinda comodidad.\r\n- Doble capa de tela fusionada que controla el abdomen medio y bajo.\r\n- Delicado encaje que se adhiere y permite una perfecta sujeción.\r\n- Disimula la celulitis y evita el roce de los muslos.\r\n- Elástico recogido en el centro que genera un efecto de glúteos más redondeados.\r\n- Pretina doble fusionada que moldea y estiliza el derrier.\r\n- Moldea los glúteos, los centra, realza y define.', 675.12, 'si'),
(49, 'CAMISETA DE CONTROL - UNA FIGURA MOLDEADA AL INSTANTE', '15824', 'mujer', 'leonisa', '¡Tu aliada perfecta para todos los días! Siente el control y la comodidad con esta camiseta de control fuerte, que gracias a su poder doble capa de DuraFit® PowerSlim®, moldea y controla abdomen alto, medio, cintura y espalda. Además, corrige la postura, realza el busto y elimina esos molestos rollitos que bordean los brazos. Es ideal para que la uses como una prenda interior o exterior, y cuello redondo o en V; póntela como quieras, tú eliges la forma del escote.', '-Increíble camiseta de control fuerte, que te ayuda a mantener una buena postura\r\n-¡Todo bajo control! Controla abdomen alto, medio, bajo, cintura y espalda\r\n-Moldea tu busto y crea un escote irresistible\r\n-Estiliza tu torso gracias a su poder doble capa: DuraFit® PowerSlim®\r\n-¡Elige el escote que más te gusta! Con cuello en v o cuello redondo\r\n-¡Perfecta todo el día! No se enrolla ni se sube en la cintura\r\n-Úsala como ropa interior o como parte de tu atuendo exterior', 341.04, 'si'),
(50, 'BODY REDUCTOR CON EFECTO LEVANTACOLAS', '18676', 'mujer', 'leonisa', 'Faja estilo body reductora de medidas, con cubrimiento hasta la rodilla, cortes y costuras especiales que le dan una forma curvilínea a tu cuerpo ejerciendo compresión en diferentes zonas. Su diseño especial ayuda a levantar la cola naturalmente para que tengas una figura estilizada y femenina. Está elaborada con tela reductora PowerSlim.', '-Faja body levantacola\r\n-Reducción en cintura, pierna, espalda, abdomen alto, medio y bajo\r\n-Diseño con derriere descubierto que te da un efecto levantacolas con excelente modelación\r\n-Busto libre que permite el uso de tu brasier favorito\r\n-Cargaderas graduables y removibles\r\n-Cierre delantero con tres broches internos que facilitan el uso\r\n-Poder doble capa: PowerSlim? DuraFit? para mayor comodidad y suavidad\r\n-Abertura en la parte inferior para mayor comodidad', 626.4, 'si'),
(51, 'FAJA MASCULINA POSTQUIRÚRGICA', '11016', 'hombre', 'fajate', 'Faja postquirúrgica o de uso diario , estilo sisa y espalda alta que mejora la postura. Su cierre central permite mayor ajuste. Ejerce control y reducción en abdomen y piernas.', 'Faja de control total, postquirúrgica o de uso diario, estilo sisa y espalda alta que mejora la postura. Su cierre central permite mayor ajuste. Ejerce control y reducción en abdomen y piernas.\r\nLuego de una intervención quirúrgica, ayuda a que las áreas tratadas duelan mucho menos, gracias a la compresión perfecta que brinda al cuerpo. Acelera el proceso de desinflamación, ayudando a una recuperación mas rápida. Acelera el proceso de cicatrización gracias a los componentes impregnados en las telas patentadas (Gingko Biloba, Vitamina E, Algas Marinas, Cosmacol Emi). Ayuda a que la piel se adhiera mas firme al músculo , evitando la retención de líquidos y la formación de fibrosis. Contribuye al drenaje linfático de los tejidos inflamados.', 1148.4, 'si'),
(52, 'BRASILERA CON TUL TRANSPARENTE', '131073', 'mujer', 'ellipse', 'Brasilera en tul elastico transparente con aplique cortado a laser, con sesgos en terciopelo.', 'Brasilera en tul elastico transparente con aplique cortado a laser, con sesgos en terciopelo.\r\n\r\n', 180.96, 'si'),
(53, 'CINTURÓN DEPORTIVO LÁTEX', '11206', 'mujer', 'fajate', 'Cinturón deportivo, cintura de avispa de alto rendimiento.\r\n\r\n', 'Cinturón látex alto rendimiento, cuenta con una tela exterior que recubre el látex para conservar una mejor apariencia, cuenta con elásticos y velcro para garantizar un ajuste perfecto en la cintura, cuida tu zona lumbar a la hora de levantar peso.\r\nLa función del látex es elevar la temperatura corporal, eliminar líquidos, toxinas y favorecer la eliminación de tejidos adiposos, además de combatir la celulitis.\r\nTelas elaboradas con látex 100% natural e hipoalergénico, se recomienda usar máximo entre 6 a 8 horas diarias.\r\n', 417.6, 'si'),
(54, 'BRASIER AIYANA', '15193', 'mujer', 'fajate', 'Delié tiene las prendas perfectas para elevar tu feminidad a otro nivel, nuestro brasier Aiyana te dará la sensualidad y seguridad que tanto buscas con su hermoso encaje en el centro de las copas, la base delantera y la parte posterior para brindarte un estilo más elegante, además con su excelente cubrimiento de busto y espalda por su base ancha evitarás que se formen rollitos y te veas mucho mejor, su diseño con cargaderas graduables y varillas laterales te ayudarán a tener una mayor compresión y ajuste de la prenda.', 'Nivel de control\r\nMedio\r\nUsos recomendados\r\nUso-diario\r\nZona de moldeo\r\nBusto\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nLycra control\r\nBeneficios\r\nRealza tu busto. Control y moldeo en abdomen y espalda.\r\nCuidados de la prenda\r\nLava a mano y por separado con jabón suave, preferiblemente de Fájate. No utilices blanqueador, no lo exprimas, ni aplanches. No lo retuerzas ya que se puede dañar la copa. Seca a la sombra. Al momento de ponértelo evita usar accesorios como anillos, pulseras o uñas largas.', 696, 'si'),
(56, 'FAJA PANTY ', '11197', 'mujer', 'fajate', 'Faja tipo panty de mediana compresión, para control de abdomen que trabaja como faja moldeadora y realza los glúteos de forma natural.\r\n', 'Faja Panty de mediana compresión, que ayuda a difinir las curvas, controla el abdomen, caderas y también moldea los glúteos.\r\nNo tiene broches ni cierres, lo que la vuelve prácticamente invisible bajo la ropa exterior.\r\nSe considera una prenda interior.\r\nDisponible en color cocoa, beige, blanco y negro.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel. ', 556.8, 'si'),
(57, 'FAJA BODY MOLDEADORA TIPO CACHETERO', '11046', 'mujer', 'fajate', 'Faja de uso diario busto libre, estilo cachetero, con cierre lateral, moldea y realza la figura brindando alto control en la zona deseada. ', 'Es una faja que deja el busto libre, tiene una cremallera lateral con broches internos que permite un mayor ajuste. Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda,moldea y levanta los glúteos,con control de espalda. Cuenta con una abertura prineal para poder ir baño sin necesidad de quitarse toda la faja. ', 946.56, 'si'),
(59, 'FAJA DE ALTA COMPRESION LIPO REDUCTORA', '11047', 'mujer', 'fajate', 'Faja postquirúrgica o post parto, con refuerzo abdominal, 3 medidas de broches, moldea glúteos, controla piernas y caderas, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.', '\"Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel,permite que la piel se contraiga y se adhiera firmemente al musculo, disminuye la incomodidad y la sensación de vacío del abdomen, ayuda a que los órganos internos regresen a su posición, corrige la postura aliviando los dolores de espalda. Controla y moldea glúteos y piernas. Tiene 3 medidas de broches regulables y abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja. \r\nTejidos con Viveltex (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi); una combinación de componentes que hidratan, nutren, regeneran, cicatrizan y tonifican la piel, éstos se liberan con el contacto con la piel.\"', 1113.6, 'si'),
(60, 'FAJA DE ALTA COMPRESION LIPO REDUCTORA', '11047PLUS', 'mujer', 'fajate', 'Faja postquirúrgica o post parto, con refuerzo abdominal, 3 medidas de broches, moldea glúteos, controla piernas y caderas, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.', '\"Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel,permite que la piel se contraiga y se adhiera firmemente al musculo, disminuye la incomodidad y la sensación de vacío del abdomen, ayuda a que los órganos internos regresen a su posición, corrige la postura aliviando los dolores de espalda. Controla y moldea glúteos y piernas. Tiene 3 medidas de broches regulables y abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja. \r\nTejidos con Viveltex (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi); una combinación de componentes que hidratan, nutren, regeneran, cicatrizan y tonifican la piel, éstos se liberan con el contacto con la piel.\"', 1155.36, 'si'),
(61, 'FAJA BUSTO LIBRE DE MEDIA PIERNA', '11048', 'mujer', 'fajate', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral, busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. ', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nSu cierre lateral hace que sea prácticamente invisible bajo la ropa, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.  ', 1273.68, 'si'),
(62, 'FAJA BUSTO LIBRE DE MEDIA PIERNA', '11048PLUS', 'mujer', 'fajate', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral, busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. ', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nSu cierre lateral hace que sea prácticamente invisible bajo la ropa, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.', 1141, 'si'),
(63, 'FAJA POSTQUIRÚRGICA DE ALTA COMPRESIÓN ', '11052', 'mujer', 'fajate', 'Faja post quirúrgica, post parto o de uso diario con brasier incorporado. Su diseño ofrece una perfecta compresión  en el abdomen, control de espalda y moldeo de senos, glúteos y piernas, cuenta con 3 niveles de broches y abertura perineal.', 'Cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.Acelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética. ', 1274, 'si'),
(64, 'FAJA POSTQUIRÚRGICA DE ALTA COMPRESIÓN ', '11052PLUS', 'mujer', 'fajate', 'Faja post quirúrgica, post parto o de uso diario con brasier incorporado. Su diseño ofrece una perfecta compresión  en el abdomen, control de espalda y moldeo de senos, glúteos y piernas, cuenta con 3 niveles de broches y abertura perineal.', 'Cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.Acelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética. ', 1322.4, 'si'),
(65, 'FAJA MOLDEADORA TIPO CACHETERO', '11053', 'mujer', 'fajate', 'Faja de uso diario, con brasier incluido, cierre lateral, estilo cachetero, con encaje siliconado anti deslizante.', 'Faja postquirúrgica o de uso diario de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nAcelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos además de ser un aliado en el uso diario.\r\nTelas con componentes VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que ayudan a nutrir, regenerar, hidratar, cicatrizar y tonificar la piel. ', 1071.84, 'si'),
(66, 'FAJA BODY REDUCTORA TIPO CACHETERO', '11066', 'mujer', 'fajate', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre con control de espalda y moldeo natural de glúteos.\r\nCuenta con 3 medidas de broches para ir regulando según se vaya reduciendo medidas. \r\n\r\n', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada.\r\nDe busto libre y 3 medidas de broches para ir ajustando según se reduce medidas, tiene doble refuerzo abdominal que ayuda aplanar el vientre y recuperar la figura luego del parto, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda. Estilo cachetero, con encaje siliconado que no se marca bajo la ropa, es anti deslizante y tiene abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervención quirúrgica o estética.', 946.56, 'si'),
(67, 'FAJA BODY REDUCTORA TIPO CACHETERO', '11066PLUS', 'mujer', 'fajate', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre con control de espalda y moldeo natural de glúteos.\r\nCuenta con 3 medidas de broches para ir regulando según se vaya reduciendo medidas. \r\n', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada.\r\nDe busto libre y 3 medidas de broches para ir ajustando según se reduce medidas, tiene doble refuerzo abdominal que ayuda aplanar el vientre y recuperar la figura luego del parto, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda. Estilo cachetero, con encaje siliconado que no se marca bajo la ropa, es anti deslizante y tiene abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervención quirúrgica o estética.\r\n', 1002.24, 'si'),
(68, 'FAJA MOLDEADORA STRAPPLES TIPO CACHETERO', '11068', 'mujer', 'fajate', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre, con cierre lateral y abertura perineal, moldea y levanta los glúteos, disimula la flacidez y da firmeza a la piel, \r\n', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, con cierre lateral que la hace menos visible bajo la ropa exterior, tiene broches internos para brindar mayor firmeza, cuenta con una abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja.\r\nEs strapless, puede usarse sin tiros y cuenta con una silicona que hace que se adhiera a la piel y no se baje, levanta los glúteos, disimula la flacidez y da firmeza a la piel.\r\nEs estilo cachetero, tiene un encaje siliconado que no se marca bajo la ropa y es antideslizante para que no se arrolle. \r\nEl uso diario ayuda a moldear la figura y reducir medidas.\r\n\r\n', 946.56, 'si'),
(69, 'FAJA INVISIBLE DE CONTROL MEDIO', '11084', 'mujer', 'fajate', 'Faja de mediana compresión de uso portquirúrgico o diario, controla y moldea glúteos y piernas.\r\n', 'Faja de mediana compresión, en el uso postquirúrgico, se utiliza en los primeros 10 días del post operatorio, ya que ejerce un moldeo suave, es también ideal para dormir en este proceso, ya que no tiene cierres ni broches que puedan causar alguna molestia y al ser de mediana compresión permite la correcta circulación y oxigenación de la sangre, permitiendo así un mejor descanso.\r\nPara el uso diario, es ideal para usar bajo vestidos o prendas ajustadas, ya que al no tener broches ni cierres, la hace invisible bajo la ropa. Está elaborada con una tela suave que simula la textura de la piel.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n', 696, 'si'),
(70, 'FAJA POSTQUIRÚRGICA TIPO CACHETERO', '11086', 'mujer', 'fajate', 'Faja postquirúrgica, post parto o de uso diario, tipo cachetero con brasier incluido. Ajustable en 3 niveles de broches.\r\n\r\n', 'Faja liporeductora, estilo cachetero con brasier y abertura perineal. Su diseño con broches te permite ajustarla a tres niveles. De alto control con cubrimiento en espalda que beneficia la región lumbar, alivia y evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n\r\n', 1009.2, 'si'),
(71, 'FAJA POSTQUIRÚRGICA TIPO CACHETERO', '11086PLUS', 'mujer', 'fajate', 'Faja postquirúrgica, post parto o de uso diario, tipo cachetero con brasier incluido. Ajustable en 3 niveles de broches.\r\n', 'Faja liporeductora, estilo cachetero con brasier y abertura perineal. Su diseño con broches te permite ajustarla a tres niveles. De alto control con cubrimiento en espalda que beneficia la región lumbar, alivia y evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n', 1050.96, 'si'),
(72, 'FAJA ESTILO CACHETERO STRAPLESS', '11106', 'mujer', 'fajate', 'Faja tipo strapless, reductor con encaje siliconado. Con 3 medidas de broches. Moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel. \r\n', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, tiene tres medidas de broches, cuenta con una abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja.\r\nEs senos libres, strapless, puede usarse sin tiros y cuenta con una silicona que hace que se adhiera a la piel y no se baje, levanta los glúteos, disimula la flacidez y da firmeza a la piel.\r\nEs estilo cachetero, tiene un encaje siliconado en la pierna que no se marca bajo la ropa y es antideslizante para que no se arrolle. \r\nEl uso diario ayuda a moldear la figura y reducir medidas.\r\n\r\n', 932.64, 'si'),
(73, 'FAJA DE ALTA COMPRESION DE MEDIA PIERNA', '11111PLUS', 'mujer', 'fajate', 'Faja de alta compresión post quirúrgica, post parto o de uso diario de media pierna, controla las caderas  y realza naturalmente los glúteos. Con busto libre, cubrimiento de espalda,corrige la postura y tiene 3 medidas de broches y doble refuerzo abdominal.\r\n', 'Faja de alta compresión post quirúrgica, post parto o de uso diario, con 3 medidas de broches frontales y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nLos broches frontales brindan un ajuste más firme en el área abdominal, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.\r\n', 1099.68, 'si'),
(74, 'CINTURILLA STRAPLESS', '11006', 'mujer', 'fajate', 'Faja cinturilla de uso diario con diseño strapless, tiene tres niveles de broches regulables que definen tu cintura. Contiene varillas internas a los costados para mayor firmeza y mejor definición de la cintura.', 'CARACTERÍSTICAS\r\nColor: Cocoa\r\nGénero: Mujer\r\nNivel de control: Alta\r\nZona de control: Abdominal\r\nMecanismos de ajuste: Broche\r\nMaterial: powernet, spandex\r\n\r\nCuidados de la prenda\r\n? El lavado: preferiblemente A MANO. Evite el uso de secadora. \r\n? Utilizar preferiblemente el Jabón Fajate\r\n? Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) \r\n? Lavar separadamente \r\n? Secar a la sombra\r\n? No utilizar blanqueadores\r\n', 570.72, 'si'),
(75, 'FAJA A LA RODILLA CON CUBRIMIENTO  DE BUSTO Y BRAZOS', '11008', 'mujer', 'fajate', 'Faja postquirúrgica con brasier y cobertura completa de espalda y brazos, ideal para postoperatorios de brazos, espalda y busto.\r\n', 'BENEFICIOS:\r\n- Detalle de encaje delicado en el ruedo de la pierna.\r\n- Broches que separan el torso para lactancia o asepsia en cirugías. \r\n- Forrada en lycra con microcápsulas que liberan vitaminas y componentes para realzar y definir glúteos.\r\n- Costuras planas para mayor comodidad y control.\r\n- Uso postquirúrgico, postparto o diario.\r\n', 1294.56, 'si'),
(76, 'FAJA CHALECO MASCULINO ', '11017', 'hombre', 'fajate', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches.', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches para poder ir ajustando según baja la inflamación luego de una intervención quirúrgica.Ideal también para uso diario. \r\nTelas con componentes que se activan al contacto con la piel (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi), ayudando a regenerar, cicatrizar, humectar y nutrir la piel.\r\n', 932.64, 'si'),
(77, 'FAJA CHALECO MASCULINO (PLUS)', '11017PLUS', 'hombre', 'fajate', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches.\r\n', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches para poder ir ajustando según baja la inflamación luego de una intervención quirúrgica.Ideal también para uso diario. \r\nTelas con componentes que se activan al contacto con la piel (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi), ayudando a regenerar, cicatrizar, humectar y nutrir la piel.', 974.4, 'si'),
(78, 'MENTONERA POSTQUIRÚRGICA CON CUBRIMIENTO DE CUELLO ', '11029', 'mujer', 'fajate', 'Accesorio Postquirúrgico para la recuperación de traumas por cirugías de mentón o de cara.\r\n', 'MENTONERA POSTQUIRURGICA CON CUBRIMIENTODE CUELLO Y ROSTRO PARA LA RECUPERACION DE TRAUMA POR CIRUGIA  DE MENTON O DE CARA. \r\n', 431.52, 'si'),
(79, 'PRENDA COMPRESIVA CARA', '11031', 'mujer', 'fajate', 'Faja postquirúrgica para mentón y orejas.', 'Faja postquirúrgica para mentón y orejas. Ayuda a la recuperación tras una intervención quirúrgica.Brinda el ajuste adecuado para aliviar dolores y contribuir con los buenos resultados de la cirugía. ', 250.56, 'si'),
(80, 'MANGAS INDIVIDUALES DE USO QUIRÚRGICO', '11034', 'mujer', 'fajate', 'Accesorio postquirúrgico para brazos con sistema de broches que se adhieren al brasier.\r\n', 'Accesorio postquirúrgico para brazos con sistema de broches que se adhieren al brasier.\r\n', 153.12, 'si'),
(81, 'BANDA DE BUSTO FAJATE ', '11037', 'mujer', 'fajate', 'Accesorio para el Busto, ideal en los procesos y cuidados postquirúrgicos\r\n', 'Accesorio para el Busto, ideal en los procesos y cuidados postquirúrgicos \r\n', 313.2, 'si'),
(82, 'FAJA MATERNA ', '11044', 'mujer', 'fajate', 'Faja materna tipo cachetero, brinda soporte en espalda y abdomen bajo que ayuda a sostener el peso del vientre y previene los dolores lumbares.', 'Faja materna, diseñada para brindar comodidad y seguridad en el proceso de gestación, se recomienda usar a partir de la semana 25 del embarazo, debido a que previene el dolor e inflamación de los pies al proporcionar un soporte en el abdomen bajo que ayuda a sostener el peso del vientre, previene los dolores lumbares y el desgarro de la piel.\r\nTelas inteligentes, con componentes activos que al contacto con la piel liberan Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi, éstos ayudan a nutrir, hidratar y regenerar la piel.\r\n', 626.4, 'si'),
(83, 'BRASIER POSTQUIRÚRGICO CON CONTROL DE BRAZOS', '11055', 'mujer', 'fajate', 'Brasier postquirúrgico elaborado con una tela elástica de compresión y copas prehormadas sin varillas. Ofrece cubrimiento de espalda y brazos, mientras realza naturalmente y centra el busto.', 'Brasier postquirúrgico elaborado con una tela elástica de compresión y copas prehormadas sin varillas. Ofrece control de espalda y brazos, realza naturalmente y centra el busto.\r\nTelas patentadas, impregnadas con componentes del grupo VivelTex, que al contacto con la piel liberan Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi, componentes que hidratan, nutren, regenera, cicatrizan y tonifican la piel.  ', 459.36, 'si'),
(84, 'FAJA INVISIBLE TIPO CACHETERO', '11075', 'mujer', 'fajate', 'Faja de mediana compresión, para uso diario o postquirúrgico, tipo cachetero con realce de glúteos y abertura perineal.\r\n', 'Faja de mediana compresión, en el uso postquirúrgico, se utiliza en los primeros 10 días del post operatorio, ya que ejerce un moldeo suave, es también ideal para dormir en este proceso, ya que no tiene cierres ni broches que puedan causar alguna molestia y al ser de mediana compresión permite la correcta circulación y oxigenación de la sangre, permitiendo así un mejor descanso.\r\nPara el uso diario, es ideal para usar bajo vestidos o prendas ajustadas, ya que al no tener broches ni cierres, la hace invisible bajo la ropa. Está elaborada con una tela suave que simula la textura de la piel.\r\nEs tipo cachetero, tiene un encaje siliconado que no se marca bajo la ropa y no se arrolla.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.', 535.92, 'si'),
(86, 'TIRANTES', '11083', 'mujer', 'fajate', 'Cargaderas brasier.', 'Cargaderas brasier.', 83.52, 'si'),
(87, 'TABLA ADBOMINAL', '11101', 'mujer', 'fajate', 'Tabla abdominal pequeña 10x23 cm.\r\n', 'Tabla abdominal de uso postquirúrgico, ayuda a evitar pliegues y a que la piel se adhiera más firme al musculo, alivia los dolores, estimula la eliminación de líquidos, acelerando la recuperación y los buenos resultados de cualquier procedimiento quirúrgico.\r\n', 125.28, 'si'),
(88, 'Camiseta deportiva masculina con tecnologia', '508007R', 'hombre', 'leo', '- Estampado localizado.\r\n- Silueta semiajustada.\r\n- Tela transpirable.\r\n- Secado rápido.\r\n- Ligera, liviana y ultracómoda.\r\n- Producida de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 100% poliéster.', 'Esta camiseta deportiva cuenta con tecnología de secado rápido y material transpirable para que te sientas fresco y seco en muy poco tiempo. Es cómoda, fresca y liviana. Combínala con nuestras pantalonetas, licras o joggers deportivos y estarás listo para dar el máximo en tus rutinas.\r\n\r\n', 243.6, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(89, 'Top en algodón ultracómodo con cargaderas graduables', '91082', 'mujer', 'leonisa', 'Este top elaborado en algodón es perfecto para ti si amas la comodidad y la ropa interior desestructurada y ligera. Su elástico en la base es muy suave al tacto y de apariencia plana y su espalda es atlética, es decir que sus cargaderas se mantendrán en su lugar todo el tiempo.', '- Top elaborado en algodón.\r\n- Ideal para busto pequeño y mediano.\r\n- Úsalo para el día a día, para estar en casa o para sentirte muy cómoda.\r\n- Elástico suave en base con el logo de Leonisa.\r\n- Espalda atlética.', 139.2, 'si'),
(91, 'FAJA POSTQUIRÚRGICA CONTROL TOTAL', '11103', 'mujer', 'fajate', 'Faja postquirúrgica de alta compresión con brasier incluido, brinda cubrimiento en espalda y control de brazos. Cuenta con doble refuerzo abdominal. Tiene 3 niveles de broches y abertura prineal.  \r\n', 'Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos. Cuenta con un brasier con mangas, que realza el busto y controla los brazos, tiene 3 medidas de broches y abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética.\r\n', 1287.6, 'si'),
(92, 'FAJA POSTQUIRÚRGICA CONTROL TOTAL', '11103PLUS', 'mujer', 'fajate', 'Faja postquirúrgica de alta compresión con brasier incluido, brinda cubrimiento en espalda y control de brazos. Cuenta con doble refuerzo abdominal. Tiene 3 niveles de broches y abertura prineal.  \r\n', 'Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos. Cuenta con un brasier con mangas, que realza el busto y controla los brazos, tiene 3 medidas de broches y abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética.\r\n', 1329.36, 'si'),
(93, 'TABLA ADBOMINAL ', '11109', 'mujer', 'fajate', 'Tabla abdominal grande 20x30 cm. \r\n', 'Tabla abdominal de uso postquirúrgico, ayuda a evitar pliegues y a que la piel se adhiera más firme al musculo, alivia los dolores, estimula la eliminación de líquidos, acelerando la recuperación y los buenos resultados de cualquier procedimiento quirúrgico.\r\nElaborada con una espuma semi flexible forrada con telas frescas e hipoalergénicas, con componentes VivelTex.  \r\n', 160.08, 'si'),
(94, 'TABLA ABDOMINAL AJUSTE BELCRO', '11121', 'mujer', 'fajate', 'TABLA ,FAJON, POS QUIRÚRGICO', 'TABLA ,FAJON, POS QUIRÚRGICO, CON CUBRIMIENTO EN TODO EL ABDOMEN,AYUDANDO A QUE LA PIEL SE PEGUE  AL MUSCULO NUEVAMENTE,IDEAL PARA CIRUGÍAS  ABDOMINALES, VELCRO AJUSTABLE\r\n', 222.72, 'si'),
(95, 'CHALECO COMPRESIVO CORRECTOR DE POSTURA', '11173', 'mujer', 'fajate', 'Faja de uso diario de alta compresión y total cubrimiento de espalda. 3 medidas de broches. Con varillas internas para mayor firmeza y corrección de postura. \r\n', 'Esta es una de nuestras fajas de uso diario, reductoras de fuerte compresión y espalda alta. sus broches tienen tres posiciones que se ajustan a tu medida. Es busto libre. Para uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.\r\nCuenta con 3 varillas internas para brindar mayor firmeza, telas con componentes VivelTex, que nutren, regeneran e hidratan la pie.\r\n', 633.36, 'si'),
(96, 'FAJA A LA RODILLA CON CUBRIMIENTO DE ESPALDA', '11175', 'mujer', 'fajate', 'Esta es una faja que deja tu busto libre, su diseño con broches permite mayor ajuste, con cubrimiento medio en la espalda beneficiando la región lumbar, y conservar una mejor postura. Ejerce control de tus muslos.\r\n', 'Nivel de control\r\nAlto\r\nUsos recomendados\r\nUso-diarioPostquirúrgica\r\nZona de moldeo\r\nAbdominalPiernasGlúteos\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\npowernetspandex\r\nEstilo\r\nA la rodilla\r\nBeneficios\r\n• Busto libre y espalda con sisa alta. • Abrochadura central de 3 niveles que permiten controlar la compresión. • Doble refuerzo abdominal para mayor compresión y firmeza. • Cubrimiento a la rodilla para definir piernas y glúteos\r\nCuidados de la prenda\r\n• El lavado: preferiblemente A MANO. Evite el uso de secadora. • Utilizar preferiblemente el Jabón Fajate• Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) • Lavar separadamente • Secar a la sombra• No utilizar blanqueadores.', 1113.6, 'si'),
(97, 'PROTECTORES DE HOMBROS', '11193', 'mujer', 'fajate', 'Protector de hombros que se adaptan a las cargaderas, brindando mayor comodidad.', 'Protector de hombros que se adaptan a las cargaderas, brindando mayor comodidad.\r\n100% Poliester.', 83.52, 'si'),
(98, 'FAJA PRIMERA POSTURA', '11198', 'mujer', 'fajate', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 974.4, 'si'),
(99, 'FAJA PRIMERA POSTURA', '11198PLUS', 'mujer', 'fajate', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 1044, 'si'),
(100, 'PANTY   ULTRAREALCE  ', '11227', 'mujer', 'fajate', 'Panty ultrarealce Faja', 'Nivel control: Alto\r\nUso-diario, Ultra realce\r\nZona moldeo: Piernas,Con lebanta cola copmprecion en el axdomen \r\n', 598.56, 'si'),
(101, 'FAJA ULTRA REALCE STRAPLESS', '11230', 'mujer', 'fajate', 'Faja cachetera strapless moldea y levanta los glúteos hasta 3 cm(*), controla fuerte y firmemente la zona abdominal moldeando tu cintura hasta 3cm(*) Importante. ¿Cómo sabes si eres talle corto? 1. Párate frente a un espejo con una posición recta. 2. Obtén la medida de tu talle tomando como punto de inicio la base del busto y como punto final la pelvis. 3. Si la medida que obtienes es igual o inferior a 28 cm esta referencia es para ti. Te recomendamos que al momento de seleccionar tu talla, elijas una adicional a lo que normalmente utilizas en prendas de control.', 'Nivel de control\r\nAlto\r\nUsos recomendados\r\nUso-diarioUltra realce\r\nZona de moldeo \r\nAbdominalGlúteos\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\npowernetspandex\r\nEstilo\r\nCachetera\r\nBeneficios\r\n• Strapless para las blusas escotadas en hombros y espalda. • Cierre semi invisible en la zona perineal para mayor comodidad. • Estructura que moldea y da mayor volumen y forma a tus glúteos.\r\nCuidados de la prenda\r\n• El lavado: preferiblemente A MANO. Evite el uso de secadora. • Utilizar preferiblemente el Jabón Fajate• Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) • Lavar separadamente • Secar a la sombra• No utilizar blanqueadores', 890.88, 'si'),
(102, 'FAJA PRIMERA POSTURA SISA Y BUSTO LIBRE ', '11354', 'mujer', 'fajate', 'Faja postquirúrgica: primera postura, esencial durante las primeras semanas del postoperatorio.', 'Faja postquirúrgica: primera postura, esencial durante las primeras semanas del postoperatorio.', 960.48, 'si'),
(103, 'PANTY FAJA CON REALCE DE GLUTEOS Y CONTROL EN ABDOMEN Y CINTURA ', '11226', 'mujer', 'fajate', 'Panty faja Ultrarealce que moldea y eleva los glúteos, ofreciendo control firme en abdomen, cintura, espalda, glúteos y caderas. Su diseño con refuerzo abdominal y propiedades que benefician la piel garantizan comodidad y una silueta definida. El elástico con silicona interna asegura un ajuste perfecto sin deslizamientos.\r\n\r\nDisimula la celulitis con costuras planas y encaje en las piernas para un ajuste preciso. Incluye cremallera perineal para mayor comodidad. Ideal para usar con vestidos, jeans o pantalones.', '- Forro interno en toda la prenda con componentes Viveltex\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa\r\n- Panty faja que brinda comodidad y versatilidad\r\n- Realce natural de glúteos\r\n- Encaje con silicona en muslos y elástico en bajo busto para mejor sujeción y que no se enrolle\r\n- Doble refuerzo abdominal para controlar y definir el abdomen\r\n- Costuras planas o invisibles que no maltratan la piel\r\n- Cremallera perineal para total comodidad\r\n- Control y moldeo total de torso\r\n- Perfecto moldeo de cintura y caderas con efecto de realce definido\r\n- Agradable aroma ', 730.8, 'si'),
(104, 'Faja panty moldeadora con control abdominal firme y encaje ajustable', '11350', 'mujer', 'fajate', 'Transforma tu figura con la Faja Panty Moldeadora, que moldea cintura, abdomen y caderas. Con refuerzo abdominal para compresión firme y diseño de tiro alto que esculpe el torso.\r\n\r\nSu cremallera lateral, abrochadura interna y cierre perineal ofrecen comodidad y ajuste perfecto. Forrada en lycra con microcápsulas, cuida tu piel mientras te proporciona soporte. ¡Define tu estilo con confianza!', '- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos.\r\n- Moldea la silueta desde la base del busto hasta la mitad de las piernas.\r\n- Doble refuerzo abdominal que controla y da firmeza.\r\n- Disimula la celulitis.\r\n- Encaje elástico con silicona en la base del busto que facilita que la prenda permanezca en su lugar.\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel.\r\n- Cremallera perineal que facilita las idas al baño.\r\n- Cremallera lateral con abrochadura interna que facilita la postura y protege la piel.\r\n- Uso para jeans, vestidos o pantalones.', 946.56, 'si'),
(105, 'Faja postquirúrgica a la rodilla y mangas con control medio fit 360', '11353', 'mujer', 'fajate', 'Faja postquirúrgica ideal para las primeras semanas de recuperación. Ofrece control moderado, ayuda en la eliminación de fluidos y desinflamación, y es perfecta para cirugías de espalda y brazos. Su diseño fit 360 moldea glúteos y se adapta a caderas amplias.\r\n', 'Con cierre perineal y cargaderas ajustables para comodidad durante el uso. Tela que proporciona un ajuste seguro y confortable, recomendado para uso las 24 horas según indicación médica.- Ideal para las primeras semanas de recuperación\r\n- Mediana compresión para desinflamar y mayor comodidad\r\n- Cierre perineal ideal para postoperatorios y uso diario\r\n- Uso diario nocturno durante recuperación\r\n- Mangas para mayor cubrimiento después de intervención de brazos y espalda\r\n- Cola fit 360 para mayor capacidad en la zona de los glúteos\r\n- Tela con apariencia brillante que proporciona un ajuste cómodo', 1141.44, 'si'),
(106, 'FAJA POSTQUIRURGICA  A LA RODILLA CON SOPORTE ABDOMINAL Y CUBRIMIENTO DE ESPALDA ', '11355', 'mujer', 'fajate', 'Faja postquirúrgica con soporte abdominal, ajuste personalizado y tres niveles de broches. Moldea cintura, caderas y piernas, ideal para postparto, postoperatorio o uso diario. Con refuerzo abdominal y detalles de encaje para un ajuste perfecto.\r\n\r\nFabricada con lycra forrada y microcápsulas Viveltex, levanta glúteos y estiliza 360°. Costuras planas para mayor confort y protección de la piel.', ' BENEFICIOS\r\n- Forro interno en toda la prenda con componentes Viveltex\r\n- Tela externa en powernet es la encargada de brindar una alta comprensión\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa\r\n- Tres niveles de broches que permite graduarla\r\n- Mayor capacidad en la zona de los glúteos que los realza y define la cintura\r\n- Doble refuerzo abdominal para controlar y definir el abdomen\r\n- Costuras planas o invisibles que no maltratan la piel\r\n- Falso perineal para total comodidad\r\n- Evita la retención de líquidos y la formación de fibrosis\r\n- Es una faja compresiva, disminuye el dolor y brinda seguridad en tus movimientos\r\n- El cubrimiento total en tu espalda te da una postura estilizada\r\n- Tiene un perfecto moldeo de cintura y caderas con efecto de realce definido\r\n- Agradable aroma', 1211.04, 'si'),
(107, 'Faja postquirúrgica de alta compresión con busto libre mangas y control abdominal', '11360', 'mujer', 'fajate', 'Faja postquirúrgica de alta compresión ideal para cicatrización y recuperación. Fabricada con powernet externo y lycra interna, ofrece beneficios para la piel, control de espalda y ajuste personalizado con abrochadura de 3 niveles y 19 ganchos para mejorar la postura. Perfecta para uso diario y postcirugía, casi invisible bajo la ropa.\r\n', 'Incluye refuerzo abdominal para un control firme, cierre perineal para comodidad y diseño de cola fit 360 para moldear glúteos. Con delicado encaje en el ruedo, es una excelente opción para cirugías de espalda y brazos.- Forro interno en toda la prenda con componentes Viveltex.\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa.\r\n- Cremallera lateral con broches internos brinda un ajuste perfecto y ayuda a la desinflamación uniforme.\r\n- Estiliza los glúteos y resalta las curvas y la cintura con su cola fit 360.\r\n- Doble refuerzo abdominal para controlar y definir tu abdomen.\r\n- Costuras planas o invisibles que no maltratan la piel.\r\n- Elástico superior que ayuda a la correcta sujeción en torso.\r\n- Brasier separado del torso por medio de broches, que permite la asepsia luego de una cirugía estética y facilita la \r\n  lactancia.\r\n- Cierre perineal para total comodidad.', 1322.4, 'si'),
(108, 'Faja postquirúrgica con brasier hasta la rodilla de alta compresión', '11366', 'mujer', 'fajate', 'Faja postquirúrgica de alta compresión ideal para cicatrización y recuperación. Fabricada con powernet externo y lycra interna, ofrece beneficios para la piel, control de espalda y ajuste personalizado con abrochadura de 3 niveles y 19 ganchos para mejorar la postura. Perfecta para uso diario y postcirugía, casi invisible bajo la ropa.\r\n\r\nIncluye refuerzo abdominal para un control firme, cierre perineal para comodidad y diseño de cola fit 360 para moldear glúteos. Con delicado encaje en el ruedo, es una excelente opción para cirugías de espalda y brazos.', '- Forro interno en toda la prenda con componentes Viveltex.\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa.\r\n- Cremallera lateral con broches internos brinda un ajuste perfecto y ayuda a la desinflamación uniforme.\r\n- Estiliza los glúteos y resalta las curvas y la cintura con su cola fit 360.\r\n- Doble refuerzo abdominal para controlar y definir tu abdomen.\r\n- Costuras planas o invisibles que no maltratan la piel.\r\n- Elástico superior que ayuda a la correcta sujeción en torso.\r\n- Brasier separado del torso por medio de broches, que permite la asepsia luego de una cirugía estética y facilita la \r\n  lactancia.\r\n- Cierre perineal para total comodidad.\r\n- Control y moldeo total de torso.', 1440.72, 'si'),
(109, 'Faja postquirúrgica moldeadora a media pierna con busto libre y soporte', '11378', 'mujer', 'fajate', 'Faja postquirúrgica moldeadora de alta compresión, controla abdomen, muslos, torso y caderas. Con cremallera lateral y broches internos para ajuste preciso, alivia dolores lumbares y promueve desinflamación. El doble refuerzo abdominal previene la retención de líquidos y acelera la cicatrización.', 'Diseñada con encaje delicado, powernet exterior para moldeado y lycra interna que cuida la piel. Cola fit 360 realza los glúteos, y el cierre perineal mejora la comodidad. Ideal para recuperación postquirúrgica y uso diario.- Alta comprensión en zona abdominal\r\n- Moldeo de cadera, muslos y torso\r\n- Favorece la recuperación después de procesos postquirúrgicos\r\n- Evita la flacidez\r\n- Cierre lateral con recubrimiento interior permite una postura más cómoda previniendo irritaciones\r\n- Componentes que benefician la piel y la cicatrización\r\n- Mayor capacidad en la zona de los glúteos que los realza, moldea y estiliza gracias a su cola fit 360\r\n- Costuras planas y lisas que la hacen más sutil con tu ropa exterior\r\n- Favorece la buena postura\r\n- Cargaderas removibles', 1238.88, 'si'),
(110, 'Faja postquirúrgica Fit 360 cachetera de alta compresión y realce de glúteos', '11380', 'mujer', 'fajate', 'La faja postquirúrgica de alta compresión controla abdomen, caderas, espalda y glúteos, favoreciendo la recuperación postoperatoria. Con cargaderas graduables y tres niveles de ajuste, ofrece un ajuste personalizado y alivia dolores lumbares. Su encaje siliconado garantiza sujeción firme y cómoda.\r\n\r\nEl color cocoa asegura discreción bajo la ropa, mientras que el diseño Cola Fit 360 realza los glúteos. Además, el cierre perineal facilita el uso diario, brindando confort y practicidad durante todo el día.', '- Compresión alta - previene la retención de líquidos.\r\n- Compresión y cubrimiento en caderas, abdomen, espalda y glúteos, forrada con tela suave y componentes Viveltex.\r\n- Diseñada con costuras planas y lisas que la hacen más sutil con tu ropa exterior.\r\n- Usándola a diario favorece la buena postura y moldea el cuerpo de forma uniforme y natural.\r\n- Acelera y ayuda en la recuperación postquirúrgica.\r\n- Cargaderas removibles con almohadilla.\r\n- Cierre perineal que facilita las idas al baño.', 1092.72, 'si'),
(111, 'Faja de alta compresión con varillas para moldear cintura y abdomen', '11478', 'mujer', 'fajate', 'Faja ultrafit skin con varillas, ideal para moldear y resaltar las curvas. Ofrece alta compresión para definir la cintura y proporciona un contorno curvilíneo al instante, especialmente en el abdomen bajo. Ayuda a corregir la postura, reducir la apariencia de los rollitos y mejora la figura.', 'Con 4 niveles de abrochadura y 17 ganchos en la parte frontal, más 4 niveles en los hombros, garantiza un ajuste perfecto. Las 4 varillas mantienen el molde y previenen que la faja pierda forma. Su falso perineal y tabla lumbar ofrecen comodidad y alivian molestias postquirúrgicas. Asegúrate de medir cintura y caderas para un ajuste adecuado.- Faja postquirúrgica silueta de cuerpo de guitarra que moldea y resalta las curvas, reduciendo visualmente la \r\n cintura y destacando los glúteos.\r\n- Control abdominal adicional.\r\n- Funciona como corrector de postura, mejorando la apariencia.\r\n- Previene los dolores asociados a la mala postura.\r\n- Cuenta con una tabla lumbar en la parte posterior que evita la retención de líquidos favoreciendo el drenaje de \r\n  estos.\r\n- Abrochadura de 4 niveles y 17 ganchos en su parte frontal y en los hombros una abrochadura de 4 niveles por 2 \r\n  ganchos en cada uno para mayor ajuste.\r\n- Falso perineal para brindar comodidad en las idas al baño.', 1197.12, 'si'),
(112, 'Faja corrector de postura de alta compresión con refuerzo abdominal', '11481', 'mujer', 'fajate', 'Faja correctora de postura de alta compresión que moldea abdomen, cintura, espalda y caderas. Con refuerzos en X para mejorar la postura, material powernet que estiliza el cuerpo y libera nutrientes beneficiosos para la piel.\r\n', 'Sistema de ajuste con broches en el frente y hombros, cargaderas graduables y cierre perineal para mayor comodidad. Silicona en el encaje asegura sujeción sin irritaciones. Ideal para uso diario y recuperación.- Faja correctora de postura de alta compresión\r\n- Controla el abdomen alto, medio y bajo\r\n- Moldea la cintura, espalda, cadera y abdomen\r\n- Facilita una mejor postura gracias a los cortes de refuerzo en X en la espalda y el abdomen, elaborados con \r\n  material de compresión\r\n- Sistema de ajuste delantero con abrochadura de 3 niveles y 19 ganchos, y en hombros una abrochadura de 4 niveles y \r\n  dos ganchos para mayor ajuste y facilidad de postura\r\n- Cargadera graduable de 30 centímetros en la parte superior del busto que centra el busto y mantiene la faja en su  \r\n  lugar\r\n- Delicado detalle de encaje con silicona de micropuntos que se adhiere a la piel para su correcta sujeción sin \r\n  causar irritabilidad', 904.8, 'si'),
(113, 'Panty faja moldeadora de alta compresión y realce de glúteos a media pierna', '11482', 'mujer', 'fajate', 'Faja panty moldeadora de control medio que define cintura, espalda y caderas. Con abrochadura ajustable y doble refuerzo abdominal para mayor firmeza. Su cierre perineal facilita las idas al baño.', 'Resalta los glúteos con un efecto redondeado y firme, mientras el elástico con silicona asegura un ajuste perfecto. Forrada en lycra con microcápsulas que cuidan tu piel mientras moldean tu figura.- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos\r\n- Moldea la silueta desde el abdomen medio hasta la mitad de las piernas\r\n- Doble refuerzo abdominal que controla y da firmeza\r\n- Disimula la celulitis\r\n- Elástico con 3 líneas de silicona facilitando que la prenda permanezca en su lugar\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel\r\n- Cremallera perineal que facilita las idas al baño, con gancho que impide que se abra\r\n- Abrochadura con 4 niveles de ajuste y 12 ganchos que facilita la postura\r\n- Uso para jeans, vestidos o pantalones', 696, 'si'),
(114, 'Panty moldeador con control de abdomen y realce para glúteos', '15116', 'mujer', 'fajate', 'Panty básico diseñado para ofrecer un excelente control del abdomen y realzar la forma de tus glúteos. Confeccionado en una tela gruesa que ayuda a ocultar la celulitis, este panty crea una silueta hermosa y estilizada.\r\n', 'El elástico grueso en la parte inferior no solo mejora el ajuste, sino que también proporciona una sujeción adicional, asegurando que la prenda se mantenga en su lugar durante todo el día. Ideal para usar bajo cualquier atuendo, este panty es la elección perfecta para quienes buscan comodidad y estilo en su ropa interior.- Panty control de abdomen.\r\n- Levanta cola. Estiliza la figura.\r\n- Resorte que evita que se enrolle.\r\n- Cubrimiento de imperfecciones.', 619.44, 'si'),
(115, 'TABLA ABDOMINAL POSTQUIRURGICA TIPO PERA PARA DRENAJE Y PREVENSION DE FIBROSIS', '11146', 'mujer', 'fajate', 'Tabla abdominal postoperatoria ideal para acelerar el proceso de recuperacion. Se puede usar debajo de cualquier faja ajustada o faja moldeadora para aplanar el abdomen.', 'Una tabla de compresión es una gran adición a cualquier faja. Esta tabla le ayudará a mantener su faja en la posición correcta y recta. BENEFICIOS:\r\n-Ayuda en el drenaje\r\n-Aumenta los efectos de las Fajas.\r\n-Proporciona una compresión uniforme en la zona abdominal.', 139.2, 'si'),
(116, 'ALMOHADILLA LUMBAR  POSTQUIRURGICA PARA RECUPERACION Y MOLDEADO DE FIGURA ', '11389', 'mujer', 'fajate', 'Almohadilla lumbar en espuma para uso postquirúrgico, Es una complemento ideal para la recuperación luego de un procedimiento estético, evita la retención de líquidos en la zona de la cintura o flancos, y ayuda a moldear la figura definiendo más el derrier.', 'BENEFICIOS:\r\n- Favorece la recuperación postquirúrgica : Brinda soporte y estabilidad en la zona lumbar después de procedimientos estéticos como liposucción o lipoescultura.\r\n- Evita la retención de líquidos : Reduce la acumulación de líquidos en la zona de la cintura y los flancos, favoreciendo un proceso de desinflamación más rápido.\r\n- Moldea la figura : Ayuda a definir mejor la silueta, especialmente en la zona de la espalda baja y cintura.\r\n- Realza el derrier : Su uso contribuye a una mejor distribución de la presión, resaltando y definiendo la forma de los glúteos.\r\n- Brinda comodidad y soporte : Su espuma de alta densidad proporciona una sensación cómoda mientras protege la zona intervenida.\r\n- Facilita una recuperación más segura : Disminuye la presión en los tejidos afectados, ayudando a evitar irregularidades o fibrosis.\r\n- Compatible con fajas postquirúrgicas : Se adapta perfectamente para complementar el uso de fajas y mejorar los resultados.', 118.32, 'si'),
(117, 'Tabla postquirúrgica tipo mariposa', '11516', 'mujer', 'fajate', 'La Tabla Mariposa Postquirúrgica Lumbar es el aliado perfecto para una recuperación cómoda y efectiva después de una cirugía lumbar. Diseñada para ayudar a mantener una postura erguida, esta almohadilla lumbar está especialmente diseñada para disminuir los dolores de espalda y promover una recuperación óptima.', '• Evita el desarrollo de fibrosis \r\n• Facilita una mejor postura erguida y correcta \r\n• Reduce el dolor gracias a la presión \r\n• Sus 4 líneas laterales permiten la correcta ubicación en el abdomen, la parte lisa va en contacto con la piel \r\n• Mantiene el abdomen plano \r\n• Ayuda en el drenaje de líquidos inflamatorios', 215.76, 'si'),
(118, 'Tabla postoperatoria abdominal para drenaje y prevención de fibrosis', '11517', 'mujer', 'fajate', 'Tabla abdominal con diseño de 4 rayas laterales, fabricada en poliuretano flexible y poliéster, ideal para postoperatorios. Facilita el drenaje de líquidos inflamatorios y previene la formación de fibrosis, ayudando en la recuperación.\r\n\r\nPromueve una postura erguida y correcta para mantener el abdomen plano. Su diseño reduce el dolor y la incomodidad, proporcionando una compresión uniforme y efectiva.', '- Evita el desarrollo de fibrosis\r\n- Facilita una mejor postura erguida y correcta\r\n- Reduce el dolor gracias a la presión\r\n- Sus 4 líneas laterales permiten la correcta ubicación en el abdomen, la parte lisa va en contacto con la piel\r\n- Mantiene el abdomen plano\r\n- Ayuda en el drenaje de líquidos inflamatorios', 292.32, 'si'),
(119, 'Faja tipo panty media pierna de alta compresión y realce de glúteo', '11346', 'mujer', 'fajate', 'La faja panty moldea cintura, espalda y caderas en 360°, ofreciendo una silueta definida. Su diseño de tiro alto y ajuste con abrochadura mejora la postura, mientras que el cierre perineal brinda comodidad.\r\n\r\nRealza los glúteos de forma natural y asegura un ajuste perfecto con encaje elástico y silicona. Forrada con lycra y microcápsulas, cuida la piel mientras define caderas y glúteos.', '- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos.\r\n- Moldea la silueta desde la base del busto hasta la mitad de las piernas.\r\n- Doble refuerzo abdominal que controla y da firmeza.\r\n- Disimula la celulitis.\r\n- Encaje elástico con silicona en la base del busto que facilita que la prenda permanezca en su lugar, con varillas \r\n  que impiden que se recoja o de doble.\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel.\r\n- Cremallera perineal que facilita las idas al baño.\r\n- Abrochadura con 2 niveles de ajuste y 17 ganchos que facilita la postura.\r\n- Uso para jeans, vestidos o pantalones.', 835.2, 'si'),
(120, 'BOXER DE HOMBRE CONTROL ABDOMEN', '11079', 'hombre', 'fajate', 'Es un bóxer elaborado con materiales suaves y elásticos con control de abdomen, que brindan un soporte firme y seguro.\r\n', 'Boxer de hombre, con control de abdomen y espalda.\r\nAbajo es como un bóxer normal, la compresión se ejerce de la cadera hacia arriba.\r\nElaborado con telas inteligentes, telas frescas e hipoalergénicas, que no calientan ni causan molestias en la piel. \r\nAl no tener broches ni cierres y estar elaborado con telas suaves, se vuelve imperceptible bajo la ropa exterior. \r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.', 556.8, 'si'),
(121, 'BRASIER MAGIC UP DE REALCE ALTO', '11208', 'mujer', 'leonisa', 'El brasier de realce Magic Up centra y levanta el busto, para que tengas ese escote que te hará lucir radiante. Los encajes en SmartLace® te cubren de sensualidad y te dan excelente modelación. Un brasier para deslumbrar y resaltar tu feminidad.', 'Brasier triangular de cubrimiento medio que realza el escote.\r\nIdeal para busto pequeño y regular.\r\nÚsalo con escotes profundos y en los momentos más sensuales.\r\nAlmohadillas removibles para graduar el nivel de realce: medio o alto.\r\nElaborado con encaje SmartLace® que se ajusta perfectamente a tu cuerpo.\r\nCargaderas multiusos para usar en modo convencional, cruzadas o halter.\r\nComposición: poliamida 86.6%, elastano 13.3%, poliéster 0.1%.', 348, 'si'),
(122, 'BRASIER DE LACTANCIA SIN ARCO CON SEÑALIZADOR', '11338', 'mujer', 'leonisa', 'Brasier exclusivo para la lactancia. La comodidad y la suavidad son los principales beneficios que te ofrece esta prenda.', 'Tiene copas completas que cubren totalmente el busto y tiene broches ubicados en la unión de las copas para facilitar la alimentación del bebé sin tener que quitarte el brasierCopas completas con forro interno para comodidad en la lactancia.\r\nSin arco y copas sin costuras que no se marcan.\r\nBroche central para mayor facilidad a la hora de alimentar al bebé.\r\nSeñalizador para recordarte el último seno con el que alimentaste al bebé.\r\nPerfecto ajuste, modelación, frescura y comodidad durante todo el día.\r\nComposición de la tela: 41% Poliamida, 29% Poliéster, 16% Algodón, 14% Elastano\r\n.    \r\n', 348, 'si'),
(123, 'Paquete X2 Brasier sin arco multibra con broche delantero', '11473X2', 'mujer', 'leonisa', 'Este increíble brasier le ofrece soporte a tu espalda gracias a un refuerzo en X elaborado en PowerSlim facilitando una mejor postura; te permite moverte libremente, sin incomodidad, debido a sus costuras ultrasuaves. Ejercítate sin excusas, ya que una banda ancha bajo el busto, te da todo el soporte que necesitas para hacer ejercicio o cualquier otra actividad.', 'Refuerzo en X elaborado en PowerSlim que facilita una mejor postura.\r\nIdeal como postquirúrgico: controla y da soporte a tu busto, ajustándose perfectamente a tu cuerpo.\r\nLa tecnología PowerSlim de alta resistencia y durabilidad, te da soporte y control, además, cubre tus laterales para disimular los molestos gorditos bajo el brazo.\r\nSiente la comodidad de las copas elaboradas en doble capa de DuraFit: este brasier sin arco te da excelente cubrimiento y controla el volumen del busto, dándole una forma redondeada natural.\r\nBanda ancha bajo el busto, sin arco ni elásticos, que te ayuda a soportar su peso durante todo el día.\r\nDiseño más cómodo: cuenta con cargaderas abullonadas y tres niveles de ajuste.\r\nAjuste perfecto: abrochadura frontal con 6 broches y 2 niveles de ajuste que lo hacen muy fácil de poner e imperceptible bajo la ropa.\r\nComposición de la tela: poliamida 90.00%, elastano 10.00%, Composición Forro: poliamida 91.00%, elastano 9.00%.', 696, 'si'),
(124, 'BRASIER CORRECTOR DE POSTURA CON SOPORTE DE ESPALDA EN X', '11473', 'mujer', 'leonisa', 'Este brasier tiene un refuerzo en X que te brinda un excelente soporte de espalda y te ayuda a mantenerla erguida ¡Te verás estilizada y glamurosa! Las copas tienen gran cubrimiento y un nivel de compresión fuerte que te ayuda a tener el busto siempre firme. ', 'sus cargaderas anchas te brindan mayor soporte, son graduables, suaves y tan cómodas que no sentirás esas molestias en los hombros ni en la espalda producidas por el peso de tu busto. Las mujeres de busto grande generalmente se inclinan hacia adelante o doblan la espalda, con este brasier corrector de postura no se preocuparán más por esto, los hombros y la espalda permanecerán rectos todo el tiempo. Este brasier es utilizado en múltiples ocasiones, hay quienes lo usan a diario, para hacer ejercicio, durante la lactancia o después de una cirugía de busto. Tanta comodidad hará que olvides que lo llevas puesto.\r\nBrasier corrector de postura, sin arco y con abrochadura delantera que facilita su uso.\r\nÚsalo a diario, para hacer ejercicio, después de una cirugía de busto, para dormir, para mastectomía o lactancia.\r\nControla el volumen del busto y elimina los molestos gorditos ubicados en sisa y espalda.\r\nCopas de excelente cubrimiento, elaboradas en doble capa de DuraFit®: una tela lisa, suave, liviana y cómoda\r\nEspalda y sisa en PowerSlim®: un material reductor de alta resistencia y durabilidad.\r\nCargaderas anchas, ergonómicas y ajustables para mayor soporte.\r\nComposición de la tela: 90% Poliamida, 10% Elastano.\r\n', 424.56, 'si'),
(125, 'BRASIER DE COPA COMPLETA CON ARCO Y ENCAJE', '11492', 'mujer', 'leonisa', 'Brasier de copas grandes sin realce ni espuma, que cubren completamente tu busto y se adaptan perfectamente a tu medida. Sus anchas cargaderas y varillas laterales te brindan mayor soporte con total comodidad. El diseño en encaje elástico SmartLace? representa la feminidad y delicadeza que caracterizan a la mujer.\r\n', '- Brasier triangular con arco interno, elaborado en encaje SmartLace? \r\n- Ideal para uso diario y para mujeres de busto grande \r\n- Copas de buen cubrimiento con forro interior que evita transparencias \r\n- Varillas laterales que centran el busto \r\n- Abrochadura con dos ganchos y tres niveles de ajuste \r\n- Composición: poliamida 85.00%, elastano 15.00%, Composición Forro: poliamida 92.00%, elastano 8.00%.\r\n', 348, 'si'),
(126, 'Brasier de Control Suave y Máxima Comodidad', '11503', 'mujer', 'leonisa', 'Este brasier te ofrece el beneficio del control suave del busto, moldeando de forma delicada y sutil tu figura. La combinación de telas dan un efecto transparente que te hará ver y sentir muy femenina.\r\n', 'Detalles de la prenda\r\n- Brasier triangular con arco\r\n- Controla suavemente el volumen del busto\r\n- Copas prehormadas de buen cubrimiento\r\n- Cargaderas graduables y acolchadas para mayor comodidad\r\n- Elásticos ultraplanos para mayor suavidad al contacto la piel\r\n- Espalda encarterada en la base para una apariencia más limpia\r\n', 348, 'si'),
(127, 'Brasier strapless con control fuerte de espalda Perfect Strapless', '11654', 'mujer', 'leonisa', 'Este brasier cuenta con laterales anchos en PowerSlim® que controlan los molestos gorditos de la espalda. Copas prehormadas con arco que ayudan a sostener mejor el busto y dan mayor realce. Elástico antideslizante en espalda, que evita que el brasier se deslice y varillas laterales te dan más soporte. ¡Decide y elige hoy tu propio estilo!', 'Detalles del producto\r\n\r\nBrasier con arco y copas en espuma.\r\nIdeal para busto mediano, grande y muy grande.\r\nCapa interna de PowerSlim en espalda y base del busto, que estiliza y moldea.\r\nElástico antideslizante en espalda que evita que se deslice.\r\nCargaderas para uso convencional, cruzado, halter, o sin ellas como strapless.\r\nVarillas laterales que sostienen la prenda al usarlo como strapless.\r\nEspalda ancha con abrochadura de 3 ganchos y 4 niveles de ajuste.\r\nProducido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\nComposición: 85% poliamida, 14% elastano, 1% elastodieno. Composición forro: 84% poliamida, 16% elastano.', 417.6, 'si'),
(128, 'BRASIER BALCONET DE REALCE MEDIO CON ARCO', '11681', 'mujer', 'leonisa', 'Brasier de copas grandes prehormadas estilo balconet, ideal para uso strapless; que te ofrece un realce natural del busto. Tiene un elástico suave que se ajusta perfectamente a tu cuerpo y un elástico antideslizante que ayuda a sostener la prenda en su lugar. La talla y copa perfectas para ti.', 'Brasier de realce medio estilo balconet.\r\nIdeal para busto grande.\r\nCopas grandes, lisas y sin almohadillas.\r\nTela interna inteligente que te mantiene fresca durante todo el día.\r\nVarillas laterales y elásticos suaves para mayor soporte.\r\nCargaderas removibles para usar de forma: convencional, cruzadas, halter o strapless.\r\nBroche de tres ganchos con cuatro niveles de ajuste, para que te sientas cómoda y segura.\r\nComposición de la tela: 85% Poliamida, 14% Elastano, 1% Caucho.', 417.6, 'si'),
(129, 'BRASIER DE REALCE MEDIO CON ESPALDA TERMOFUSIONADA', '11705', 'mujer', 'leonisa', 'Este brasier triangular con arco te hará sentir muy segura y cómoda; sus copas tienen gran cubrimiento, te dan mayor sostenimiento y aún sin espuma, te ayudan a modelar el busto naturalmente, dándote el realce medio que tanto te gusta. Además por medio de su tela doble termofusionada, estiliza tu espalda para evitar que se salgan los rollitos.', 'Brasier triangular de modelación natural con arco interno.\r\nIdeal para uso diario y para busto regular, grande y muy grande.\r\nCopas con buen cubrimiento.\r\nEspalda con doble tela termofusionada, más limpia y con menos costuras.\r\nSin elásticos en la base que no talla ni se marca en la ropa.\r\nComposición: 82% Poliamida, 18% Elastano.', 417.6, 'si'),
(130, 'BRASIER SIN ARCO CON COPAS EN ENCAJE', '1176', 'mujer', 'leonisa', 'Brasier sin arco, con copas completas que cubren totalmente el busto garantizando una modelación natural, son en encaje floral para darte una apariencia sofisticada con leves transparencias. Las cargaderas son más anchas para darle máximo soporte al busto con mayor comodidad. Espalda en tela lisa que brinda muy buen ajuste, también tiene cortes laterales que dan mayor cubrimiento y ayudan a recoger y centrar el busto.\r\n\r\n', 'Detalles de la prenda\r\n- Brasier triangular sin arco de máximo cubrimiento\r\n- Ideal para las mujeres m´s clásicas y conservadoras\r\n- Copas completas en encaje floral para una apariencia sofisticada\r\n- Cortes laterales que ayudan a recoger y a centrar el busto\r\n- Excelente modelación y sostenimiento del busto\r\n- Espalda en tela lisa con buen ajuste\r\n- Cargaderas anchas graduables, integradas a la espalda, te dan máximo soporte con gran comodidad\r\n- Broches dobles en la espalda con tres niveles de ajuste\r\n', 285.36, 'si'),
(131, 'BRASIER CON ESPALDA DEPORTIVA EN ENCAJE', '11799', 'mujer', 'leonisa', 'Brasier de realce natural, copas lisas y encaje elástico en espalda que te harán lucir supercoqueta. La espalda atlética contrasta con el encaje y te da un look juvenil que resalta tu feminidad.', 'Brasier media copa.\r\nBroche delantero y escote profundo.\r\nCopas suaves y prehormadas que te dan un realce natural.\r\nEspalda deportiva con encaje elástico.', 264.48, 'si'),
(132, 'BRASIER DOBLE MAGIC UP DE DOBLE REALCE CON ARCO', '11827', 'mujer', 'leonisa', 'Es increíble que sin aire, sin almohadillas o geles puedas alcanzar un nivel tan alto de realce, con una modelación perfecta y un look muy natural. ', 'Brasier triangular de realce doble con arco interno.\r\nIdeal para busto pequeño, regular y para aumentar volumen.\r\nSu diferencia radica en las copas, que fueron diseñadas para centrar y aumentar dos tallas dándote un realce extremo que te sorprenderá. Este brasier es ultraliviano, liso y suave al contacto con la piel, por eso te da una apariencia invisible. Las copas están elaboradas con una espuma liviana incorporada que no se deforma, se adapta a la forma del cuerpo y tiene la capacidad de recuperar su forma original.', 417.6, 'si'),
(133, 'BRASIER STRAPLESS ANTIGRAVEDAD DE REALCE EXTREMO', '11841', 'mujer', 'leonisa', '¡Un strapless que no se cae! Este brasier además de ser strapless es push up, te da todo lo que buscas en un brasier. Las copas fueron diseñadas para sostener, centrar, realzar y todo ésto gracias a una estructura interna en forma de manos que sostiene increíblemente el busto evitando que se caiga. Es una prenda lisa, ligera, suave al contacto con la piel y se adapta perfectamente a la forma del cuerpo. Tiene elásticos anchos antideslizantes siliconados en la espalda que se adhieren a la piel.', 'Brasier strapless sin arco y con máximo realce.\r\nCopas con estructura interna en forma de manos que sostiene increíblemente el busto.\r\nCopas prehormadas con espuma ultraliviana que se adaptan a la forma de tu cuerpo.\r\nMenos costuras para evitar marcas.\r\nLos elásticos son cubiertos y te dan una apariencia limpia e invisible.\r\nModelación perfecta que hace lucir el busto natural.\r\nElásticos antideslizantes siliconados en la espalda que mantienen el brasier firme en su sitio.\r\nCargaderas multiusos, las puedes usar de forma convencional, halter, cruzadas, un hombro o strapless.\r\nEspalda ancha con abrochadura de cuatro ganchos y dos posiciones para que lo ajustes a tu contorno.\r\nComposición de la tela: 72% Poliamida, 13% Silicona, 12% Elastano, 3% Poliéster.', 661.2, 'si'),
(134, 'BRASIER STRAPLESS DE DOBLE REALCE ', '11843', 'mujer', 'leonisa', 'Este brasier strapless te da todo lo que buscas en un brasier: las copas fueron diseñadas para centrar tu busto y aumentar hasta dos tallas dándote un realce doble que te va a encantar. Es una prenda lisa, ligera y suave al contacto con la piel. Las copas están elaboradas con una espuma ultraliviana incorporada que no se deforma, se adapta a tu cuerpo y tiene la capacidad de recuperar su forma original. Es un strapless que no se cae, ya que tiene elásticos antideslizantes siliconados en el escote, la espalda y en la base de las copas, que se adhieren a la piel evitando que el brasier se deslice.', 'Brasier strapless con arco de doble realce.\r\nIdeal para busto regular y para dar más volumen.\r\nCopas con espuma ultraliviana incorporada que no se deforman y aumentan hasta dos tallas de tu copa.\r\nMenos costuras para evitar marcas.\r\nModelación perfecta que hace lucir el busto natural.\r\nElásticos antideslizantes siliconados en la espalda y en la base de las copas que mantienen el brasier en su sitio.\r\nCargaderas para usar de forma convencional, cruzadas, halter o strapless.\r\nComposición: 72% Poliamida, 13% Silicona, 12% Elastano, 3% Poliéster.', 515.04, 'si'),
(135, 'BRASIER BALCONET DE CONTROL FUERTE EN DELICADO ENCAJE', '11847', 'mujer', 'leonisa', 'Brasier estilo balconet elaborado en encaje elástico SmartLace® con diseños que resaltan la belleza de tu cuerpo. Con arcos y copas prehormadas que te dan una modelación perfecta del busto. La base es ancha y tiene un refuerzo en la unión de las copas que se ajusta brindando mayor soporte para evitar que las copas se desplacen. Los laterales están forrados en PowerSlim® para controlar y estilizar la figura y la abrochadura es de tres ganchos y cuatro posiciones para que lo ajustes perfectamente a tu medida.', 'Éste brasier te permite usar las cargaderas de forma convencional o cruzadas. ¡Disfruta de una de las siluetas preferidas por todas!\r\nBrasier balconet con arco y copas sin costuras elaborado en SmartLace®: un encaje elástico, delicado y resistente.\r\nIdeal para busto grande que puedes usar diariamente.\r\nControl fuerte en espalda y base, gracias a un forro de PowerSlim®: material reductor de alta resistencia y durabilidad.\r\nCargaderas anchas que te dan mayor soporte y puedes usarlas estilo convencional o cruzadas.\r\nAbrochadura de tres ganchos y cuatro niveles de ajuste.\r\nComposición: 86% Poliamida, 14% Elastano.\r\n', 410.64, 'si'),
(136, 'BRASIER REDUCTOR Y CORRECTOR DE POSTURA CON TOQUES DE ENCAJE', '11848', 'mujer', 'leonisa', 'Este brasier te ayuda a reducir medidas de una forma muy confortable, te brinda máximo soporte y te ayuda a mantener la espalda recta durante todo el día sin mayores esfuerzos.', 'Un diseño con máximo cubrimiento del busto, sin arcos y con un exclusivo refuerzo en X en la espalda para corregir la postura. Elaborado con PowerSlim® un material reductor de alta resistencia y durabilidad. Las copas están elaboradas en nuestro encaje único SmartLace® que resalta tu belleza y te ayuda a reducir el volumen de tu busto.\r\n\r\nBrasier de reducción sin arco elaborado en SmartLace®: un encaje elástico, delicado y resistente.\r\nIdeal para busto, grande, muy grande y para reducir el volumen del busto.\r\nRefuerzo en forma de X que corrige tu postura; elaborado en PowerSlim®: un material reductor de alta resistencia y durabilidad.\r\nCopas completas para mayor cubrimiento con forro interno que evita transparencias.\r\nCargaderas anchas para un mayor soporte, son graduables para que las ajustes a tu medida.\r\nAbrochadura delantera con dos opciones de ajuste que facilita el uso de la prenda.\r\nComposición de la tela: 99% Poliamida, 1% Elastano.\r\n', 396.72, 'si'),
(137, 'BRASIER INVISIBLE DE REALCE ALTO CON ARCO Y COPAS CON MEMORIA', '11868', 'mujer', 'leonisa', 'Brasier con copas triangulares que cubren muy bien el busto, con arco que te da mayor soporte. Las copas son prehormadas y están elaboradas de espuma con memoria, además tiene un diseño especial con mayor espesor en la parte inferior para dar un realce mucho más alto. Cuenta con un soporte de tela al interior de las copas que ayuda a centrar el busto. La espalda es ancha con mayor cubrimiento y está elaborada en microfibra, un material suave con tu piel que te hará sentir extremadamente cómoda.', 'Brasier de realce alto con arco.\r\nCopas triangulares con muy buen cubrimiento del busto.\r\nCopas prehormadas en espuma con memoria, se adapta perfectamente a tu busto.\r\nRefuerzo en la copa con mayor espesor en la parte inferior para realzar el busto.\r\nCargaderas invisibles termofusiondas con excelente soporte.\r\nAbrochadura de cuatro posiciones para que lo adpates a tu contorno.', 528.96, 'si'),
(138, 'BRASIER DE CONTROL CON ARCO - CORRIGE LA POSTURA', '11870', 'mujer', 'leonisa', 'Brasier corrector de postura con alto cubrimiento de sisa. Media copa con buen cubrimiento del busto, te garantiza una modelación perfecta y comodidad total. Tiene forro en PowerSlim?: un material reductor de alta resistencia y durabilidad, que controla suavemente la espalda, la base de las copas y debajo de los brazos estilizando tu figura. Tiene un refuerzo en X en la espalda que te da excelente soporte y te ayuda a mantenerla erguida todo el tiempo.\r\n', 'Detalles de la prenda\r\n- Brasier con arco que corrige la postura, con alto cubrimiento en sisa, base y espalda\r\n- Ideal para busto regular\r\n- Copas sin costuras, suaves y livianas que se adaptan a tu busto cómodamente\r\n- Alto cubrimiento en sisa, espalda y base de las copas. Elaboradas en PowerSlim?: un material de alta resistencia y durabilidad\r\n- Espalda con refuerzo en forma de X que te da máximo soporte y corrige tu postura\r\n- Cargaderas anchas y graduables que te dan mayor sostenimiento\r\n- Abrochadura con dos ganchos y cuatro niveles de ajuste\r\n- Composición: poliamida 88%, elastano 12%', 410.64, 'si'),
(139, 'BRASIER BALCONET DE ENCAJE CON MÁXIMO CUBRIMIENTO DE ESPALDA ,Y REALCE ', '11877', 'mujer', 'leonisa', 'Brasier estilo balconet en encaje elástico, su diseño te da máximo cubrimiento del busto y de la espalda haciendo que luzcas perfecta. Las copas son prehormadas en espuma y cuentan con un realce incorporado en la parte inferior para darle un realce alto al busto. Varillas laterales que ayudan a sostenerlo cuando lo usas como strapless.\r\n', '- Brasier estilo balconet de espalda ancha \r\n- Ideal para busto regular y grande \r\n- Copas prehormadas con realce incorporado \r\n- Sexy encaje que enmarca el escote y la base \r\n- Suaves varillas laterales que dan una excelente modelación y ayudan a sostener la prenda al usar strapless \r\n- Cargaderas anchas para uso convencional, cruzado, halter o strapless \r\n- Espalda ancha con seis broches y dos posiciones de ajuste \r\n- Composición: poliamida 82.00%, elastano 18.00%, Composición Forro: poliéster 53.00%, poliamida 31.00%, elastano 16.00%.\r\n', 549.84, 'si'),
(140, 'BRASIER BALCONET DE REALCE MEDIO CON ENCAJE DELICADO', '11885', 'mujer', 'leonisa', 'Brasier estilo Balconet con cubrimiento medio del busto. Con Arco y Realce Medio Incorporado. Copas con diseño especial en la espuma para dar realce, el interior de las copas es mucho más suave, da una sensación de confort y un tacto más delicado. La base de las copas es más ancha, está hecha de encaje y decorada con puntilla delicada que rodea el contorno dándole ese toque sexy y sutil.', 'Brasier tipo balconet con arco y realce medio.\r\nEspalda ancha con buen cubrimiento, ligera, con transparencias y detalles que le agregan sensualidad a esta prenda.\r\nSuaves varillas laterales que brindan mayor soporte y una mejor modelación del busto.\r\nCómodas cargaderas graduables que puedes usar en modo convencional, cruzadas, halter y strapless.\r\n6 broches en la espalda con 2 niveles de ajuste.', 348, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(143, 'BRASIER STRAPLESS ANTIGRAVEDAD DE REALCE ALTO', '11893', 'mujer', 'leonisa', 'Este brasier además de ser straplBess es push up, te da todo lo que buscas en un brasier. Las copas fueron diseñadas para sostener, centrar, realzar y todo ésto gracias a una estructura interna en forma de manos. Es una prenda lisa que se adapta perfectamente a la forma del cuerpo. Tiene elásticos anchos antideslizantes siliconados en la espalda que se adhieren a la piel evitando que el brasier se deslice.', 'Brasier strapless sin arco de realce alto.\r\nIdeal para busto pequeño, regular y grande.\r\nCopas con estructura interna en forma de manos que sostiene, centra y levanta.\r\nElásticos antideslizantes siliconados en espalda que mantienen el brasier en su lugar.\r\nCargaderas para uso convencional, cruzadas, halter, un hombro o strapless.\r\nEspalda ancha con abrochadura de dos ganchos y cuatro niveles de ajuste.\r\nComposición de la tela: elastano 17.00%, poliamida 70.00%, silicona 13.00, Composición Forro: poliamida 87.00%, elastano 13.00%.', 473.28, 'si'),
(144, 'BRASIER BALCONET NATURAL SEXY CON ACABADOS BRILLANTES', '11896', 'mujer', 'leonisa', 'Este es el strapless ideal para mujeres de busto grande: un bra tipo balconet con arco, elaborado con materiales mates y brillantes. Cuenta con un refuerzo en espalda de tecnología PowerSlim?: un material reductor de alta resistencia y durabilidad para controlar y moldear la figura. Las copas de este bra te brindan el soporte y la sensualidad que buscas; son prehoramadas, con realce medio y escote profundo', '-Brasier con arco tipo balconet de realce medio y escote profundo de gran soporte y cubrimiento\r\n-Es el strapless ideal para las mujeres de busto grande\r\n-Copas prehormadas en espuma suave con varillas laterales que se ajustan perfectamente a ti\r\n-Espalda ancha elaborada en PowerSlim?: un material reductor de alta resistencia y durabilidad que estiliza tu figura\r\n-Tiene un elástico que ejerce presión hacia arriba para generar mayor soporte y mejor sostenimiento\r\n-Elaborado con materiales que combinan un acabado mate en la base y uno brillante en el escote\r\n-Cargaderas multiusos: convencional, cruzadas y halter\r\n-Composición: poliamida 79.00%, elastano 21.00%, Composición Forro: poliamida 86.00%, elastano 14.00%', 417.6, 'si'),
(145, 'BRALETTE TRIANGULAR ESTILO TOP CON ENCAJE', '11897', 'mujer', 'leonisa', 'Bralette sin arco, con muy buen cubrimiento del busto. Tiene copas triangulares extraíbles, elaboradas en espuma muy suave y tul, para darte una sensación de máxima frescura . Este bra estilo top es muy liviano y da un realce natural con excelente modelación. Está diseñado con encajes de última tecnología, que combinan la blonda y los decorados en puntilla en la base, la espalda y el escote.', 'Bralette sin arco, con muy buen cubrimiento del busto. Tiene copas triangulares extraíbles, elaboradas en espuma muy suave y tul, para darte una sensación de máxima frescura . Este bra estilo top es muy liviano y da un realce natural con excelente modelación. Está diseñado con encajes de última tecnología, que combinan la blonda y los decorados en puntilla en la base, la espalda y el escote.', 306.24, 'si'),
(146, 'BRASIER BALCONET CON REALCE ALTO Y ENCAJE', '11898', 'mujer', 'leonisa', 'Brasier balconet con arco y realce alto incorporado. La base de las copas es ancha y te brinda excelente ajuste con gran comodidad, gracias a un elástico ancho que mantiene el bra en su sitio. Elaborado con tela lisa en las copas y con encaje tipo blonda transparente en la espalda. Disfruta el realce alto que te gusta con el encaje más delicado', '-Brasier balconet de cubrimiento medio con arco interno y realce alto\r\n-Elástico ancho en la base que se ajusta muy bien y sostiene con comodidad el busto\r\n-Elásticos en el centro del escote para un efecto de doble cargadera\r\n-Cargaderas graduables y multiusos: convencional, cruzadas, halter\r\n-Broches dobles en la espalda con 3 niveles de ajuste\r\n-Composición: 19% elastano, 81% poliamida', 361.92, 'si'),
(147, 'FAJA INVISIBLE ESTILIZADORA DE BRAZOS CON CORRECTOR DE POSTURA', '15790', 'mujer', 'leonisa', 'Consigue los brazos tonificados que sueñas, con esta faja estilizadora de brazos, que moldea la parte de superior de tus brazos y espalda. Es ideal para usar después de una cirugía de brazos o braquioplastia, ya que ayuda a reducir la inflamación, adormecimiento, hormigueo o cualquier incomodidad causada por la retención de flujos. Su espalda en X te ayuda a mantener una postura correcta a lo largo del día. Es absolutamente cómoda, ya que está elaborada en SkinFuse® un material tan suave, que ni siquiera notarás que lo llevas puesto.', '-Cómoda compresión en la parte superior de los brazos y espalda, que reduce los gorditos más molestos\r\n-Moldea brazos y espalda: suaviza la celulitis y moldea los brazos\r\n-Uso postquirúrgico: reduce inflamación, adormecimiento, hormigueo o cualquier incomodidad causada por la retención de flujos. Conoce más aquí: http://www.leonisa.com/en/arms-shaper-brachioplasty/\r\n-Espalda en X que tira los hombros hacia atrás y corrige tu postura\r\n-Busto libre que se acomoda a cualquier tamaño de busto: centra y levanta\r\n-Elaborado en SkinFuse®, un material suave y liso que comprime cómodamente\r\n-Sus pocas costuras la hacen muy cómoda e imperceptible bajo la ropa\r\n-Abrochadura frontal con cuatro niveles de ajuste\r\n-Debido a la alta capacidad de elongación de su material, esta faja puede parecer pequeña a primera vista, por eso, te recomendamos que te la pruebes\r\n-Composición: poliamida 80.00%, elastano 20.00%.', 327.12, 'si'),
(148, 'BODY FAJA MEDIA PIERNA INVISIBLE CON REALCE', '12807M', 'mujer', 'leonisa', 'Este body te ofrece cubrimiento desde la base del busto hasta la rodilla, controla y moldea suavemente el abdomen alto, medio, bajo, la cintura y los muslos; para darte una figura estilizada. Además cuenta con un tejido especial bajo los glúteos que ayuda a realzarlos. Conoce el efecto invisible de la tecnología SkinFuse: menos cortes y costuras, que no se marca en tu ropa y es fresca, la puedes usar todos los días y lo mejor de todo es que la puedes usar con tu brasier favorito. ¡Moldea tu cuerpo con estilo y nadie sabrá que la llevas puesta!', '-Faja body busto libre con cubrimiento hasta la rodilla\r\n-Control suave en abdomen alto, medio, bajo, cintura y muslos\r\n-Tecnología SkinFuse: menos cortes y costuras; invisible bajo la ropa\r\n-Tensiones inteligentes que ejercen diferentes niveles de control en el cuerpo\r\n-Sin control sobre los glúteos para no aplanarlos y tejido inferior que los realza\r\n-Úsalo con o sin sus cargaderas graduables\r\n-Composición: poliamida 78.00%, elastano 22.00%', 285.36, 'si'),
(149, 'BRASIER COPAS COMPLETAS CON ENCAJE EN BANDAS', '11901', 'mujer', 'leonisa', 'Brasier triangular con arco y cubrimiento total del busto, está elaborado con la nueva tecnología de encaje en bandas, que genera transparencias localizadas y se ajusta perfectamente al busto. Las copas son prehormadas, elaboradas en espuma suave, y más profundas para darte mayor capacidad', '-Brasier triangular con arco y cubrimiento total del busto\r\n-Elástico ultraplano en la base de las copas para dar mayor soporte al busto\r\n-Cargaderas anchas fijas a las copas, muy confortables y graduables\r\n-Apariencia invisible sin elásticos marcados\r\n-Espalda ancha con muy buen cubrimiento\r\n-Broches triples en la espalda con cuatro niveles de ajuste\r\n-Composición: poliamida 75.00%, elastano 25.00%, Composición Forro: poliamida 88.00%, elastano 12.00%.', 431.52, 'si'),
(150, 'BRASIER CON CARGADERAS DOBLES Y ESPALDA EN ENCAJE', '11906L', 'mujer', 'leonisa', 'Este brasier de copas lisas con realce natural y arco, es perfecto para las mujeres naturales que buscan un look diferente. ', 'Las cargaderas son dobles y le dan al bra un toque sexy ideal para lucir con blusas de tirantes o escotadas; la espalda y el escote están elaboradas en encaje sofisticado y femenino que no se desmalla, ni se marca. Además, la abrochadura elástica con gancho, te permite estar totalmente cómoda\r\n-Brasier triangular de realce suave, con copas lisas y arco\r\n-Cargaderas dobles: una que soporta la copa y otra que soporta un encaje en el escote\r\n-Cargaderas multiusos: halter, cruzadas o convencional\r\n-Composición: poliamida 76.00%, elastano 24.00%.\r\n', 306.24, 'si'),
(151, 'BRASIER BALCONET TRIPLE REALCE 3D CON ARCO', '11907', 'mujer', 'leonisa', 'Brasier tipo balconet con arco interno. Disfruta del volumen que genera el triple realce de efecto 3D y aumenta una talla y media en tu copa, gracias a su espuma incorporada. Tiene una banda de silicona en el borde del escote, lo que evita que se deslice, dándote más seguridad. Su escote es muy profundo y tiene el más tecnológico de los encajes a lo largo de la base y la espalda, que permite ver hilos de distintos colores en el mismo tejido y que además, es más suave, resistente y duradero. ', 'Brasier balconet de escote profundo con arco interno.\r\nIdeal para busto pequeño y regular y para usar con escotes profundos.\r\nCopa de triple realce que centra y levanta el busto hasta 1 1/2 talla de copa.\r\nBanda de silicona en el escote que se adhiere al busto para lograr una modelación perfecta y varillas suaves en los laterales para un mejor ajuste.\r\nEspalda ancha con un encaje tecnológico que revela un tejido de distintos colores.\r\nCargaderas graduables y removibles.\r\nAbrochadura doble y cuatro niveles de ajuste.\r\nComposición: 75% poliamida, 14% elastano, 10% rayón, 1% silicona.', 487.2, 'si'),
(152, 'BRASIER BALCONET TIPO BUSTIER CON ESPALDA ANCHA', '11911', 'mujer', 'leonisa', 'Este brasier balconet te permite lucir tu mejor escote, ya que cuenta con una ayuda ergonómica al interior de las copas que realza tu busto. \r\nSus copas son prehormadas y te ayudan a moldear tu busto tal como lo quieres. Al ser tipo bustier, su base ancha elaborada en PowerSlim, se asegura de controlar tu silueta y mantener el bra siempre en su lugar.\r\nÚsalo como strapless o como quieras, siempre te va a quedar bien.\r\n\r\n', 'Brasier balconet tipo bustier con arco interno.\r\nIdeal para busto regular y grande. Úsalo para lo que quieras.\r\n\r\nCopas prehormadas, con una pequeña espuma incorporada que te ayuda a levantar el busto.\r\n\r\nBase y espalda elaboradas en PowerSlim: un material reductor de alta resistencia y durabilidad que estiliza tu figura.\r\n\r\nVarillas laterales suaves y elásticos anchos en espalda, que aseguran que el bra permanezca en su lugar.\r\n\r\nElástico de caucho en el contorno superior de tu bra, que te permite usarlo como strapless.\r\n\r\nCargaderas removibles que puedes usar en modo convencional, cruzadas, halter o strapless.\r\n\r\nAbrochadura con seis ganchos y dos niveles de ajuste.\r\nComposición: poliamida 80%, elastano 19%, caucho 1%.', 577.68, 'si'),
(153, 'Strapless bustier 360', '11911N', 'mujer', 'leonisa', 'Siéntete sexy, segura e imparable con este brasier strapless de realce alto incorporado que centra y levanta el busto. El encaje en contraste que recubre las copas, la base y los laterales es muy sexy, diferente y le da un toque de glamour y elegancia.', '- Brasier strapless con arcos internos. Encaje en contraste para un toque sexy y diferente.\r\n- Ideal para busto mediano y grande.\r\n- Copas prehormadas, con realce alto incorporado que te ayuda a levantar el busto.\r\n- Espalda ancha y laterales del busto elaborados internamente en PowerSlim: nuestro material de compresión que estiliza esta zona de tu cuerpo.\r\n- Varillas laterales suaves y elásticos anchos en espalda, que aseguran que el bra permanezca en su lugar.', 549.84, 'si'),
(154, 'BRASIER TRIANGULAR DE DOBLE REALCE SIN ARCO', '11913', 'mujer', 'leonisa', 'Nunca has sentido un brasier de doble realce que te de tanta comodidad. Brasier triangular que genera un doble realce, incluso sin arco. Esto se debe a una malla tecnológica interna que se encarga de centrar y levantar el busto. La espalda en forma de U está elaborada en el más fino encaje de motivo floral que lo hace muy femenino y su escote profundo lleva una pieza más de encaje.\r\n', 'Detalles de la prenda\r\n- Brasier triangular sin arco y muy cómodo, que genera un doble realce\r\n- Ideal para busto pequeño, regular, grande y para novias\r\n- Espalda en forma de U elaborada en el más fino encaje floral\r\n- Cargaderas tecnológicas de mayor elongación, para uso cruzado o halter\r\n- Composición: poliamida 85%, elastano 15%\r\n- Varillas laterales y malla interna que centran y levantan el busto\r\n- Abrochadura doble en microfibra con cuatro niveles de ajuste', 389.76, 'si'),
(155, 'Suéter deportivo de cuello redondo', '195396', 'mujer', 'leonisa', 'Suéter deportivo de cuello redondo.\r\nPuños y pretina en rib, para que la prenda se ajuste más a tu cuerpo.\r\nTacto suave.\r\nIdeal para complementar tu look deportivo en los días más fríos.\r\nProducido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\nComposición: 64% poliéster, 31% algodón, 5% elastano.', 'Nuestro suéter deportivo es una motivación más para entrenar en los días más fríos. Cuenta con puños y ruedo en rib para que la prenda se ajuste más a tu cuerpo y tengas más libertad de movimiento. Su cuello redondo te hará sentir más abrigada y es muy suave al tacto ¡será tu complemento favorito para tus rutinas deportivas! Combínalo con nuestros leggings o shorts deportivos y estarás lista para entrenar y sin excusas.\r\n\r\n', 271.44, 'si'),
(156, 'Pantaloneta deportiva con acabado antifluidos y bolsillos funcionales', '518014N', 'hombre', 'leo', 'Esta pantaloneta deportiva para hombre cuenta con un acabado antifluidos que repele líquidos y salpicaduras para que entrenes más fresco y seguro. Sus dos bolsillos laterales son ideales para llevar contigo tus objetos personales. El cordón en la cintura es ajustable, para que la prenda permanezca siempre en su lugar. Es perfecta para combinar con nuestras camisetas deportivas de secado rápido y entrenar con total comodidad, libertad y frescura.', 'Pantaloneta deportiva con acabado antifluidos que repele líquidos y salpicaduras.\r\n2 bolsillos laterales funcionales.\r\nCordón ajustable en cintura.\r\nPerfecta para hacer deporte o para los momentos de descanso.\r\nComposición: 95% poliéster, 5% elastodieno', 306.24, 'si'),
(157, 'Short deportivo tipo biker', '195609', 'mujer', 'leonisa', 'Tiro alto.\r\nSecado rápido.\r\nTacto extrasuave.\r\nCorte en glúteos tipo corazón: lucen más realzados y redondeados.\r\nSin costura frontal para que no se marque en la entrepierna.\r\nComposición: 83% poliéster, 17% elastano.\r\n', 'Si eres fan de los bikers ya que tienen buen cubrimiento en piernas y al tiempo te hacen sentir fresca y cómoda ¡este short tipo ciclista está esperando por ti! Es de tiro alto, lo cual es ideal para disimular el abdomen bajo y estilizar visualmente tu cuerpo. En los glúteos tiene un corte tipo corazón que les da un efecto más realzado y redondeado. En la parte frontal no tiene costura frontal vertical para que no se marque en la entrepierna.\r\n\r\n', 174, 'si'),
(158, 'Short ciclista sin costuras control fuerte en abdomen medio y moderado en muslos', '195571', 'mujer', 'leonisa', 'Short deportivo de tiro alto con control fuerte en abdomen medio y control moderado en muslos. Al estar elaborado en SkinFuse, nuestra tecnología sin costuras que se siente como una segunda piel, es ideal para actividades de impacto medio como yoga o pilates, ya que no sentirás las costuras mientras realizas tus posturas más exigentes. Al tener doble capa de tela en cintura, este short afina más tus curvas y la tecnología en el tejido de las piernas y glúteos hará que se vean más firmes. Su material de secado rápido te hará estar fresca y cómoda todo el tiempo. Úsalo para trotar, bailar, montar en bicicleta, ir al gimnasio, hacer yoga o simplemente para cuando quieras sentirte cómoda en el día a día o para usar con tu rop\r\n', 'Short ciclista con doble capa en cintura que afina tus curvas.\r\nControl fuerte en abdomen medio y control moderado en muslos\r\nMaterial de secado rápido: siempre fresca durante tus entrenamientos.\r\nTecnología seamless SkinFuse sin costuras: mayor ajuste al cuerpo, ligereza y libertad de movimiento.\r\nTejido en glúteos y piernas que los hacen lucir más firmes.\r\nÚsalo como deportivo o como ropa exterior.\r\nComposición: 90% poliamida, 10% elastano.\r\n', 229.68, 'si'),
(159, 'PAQUETE X 3 PANTY CLÁSICO DE MÁXIMA COMODIDAD Y FRESCURA', '12771X3', 'mujer', 'leonisa', 'Paquete por 3 panties tipo hipster, elaborados en algodón elástico que te ofrece gran comodidad, frescura y un contacto suave con tu piel. Esta es una silueta muy buscada por su estilo y por su increíble comodidad. Se ajustan perfectamente a tu cuerpo y te dan una modelación perfecta, sus elásticos planos en microfibra en la cintura te ofrecen gran suavidad y no marcan la piel.', '-Paquete x3 panties estilo clásico\r\n-Ajuste perfecto, excelente modelación y máxima comodidad\r\n-Buen cubrimiento de la cola\r\n-Elaborados en algodón elástico supersuave\r\n-Elásticos en microfibra en cintura que no marcan la piel\r\n-Refuerzo inferior 100% en algodón para mayor comodidad\r\n-Composición: ALGODÓN 63.00%, poliamida 26.00%, elastano 11.00%.', 403.68, 'si'),
(160, '3 TANGAS BRASILERAS DESCADERADAS CON ENCAJE SEXY', '12803X3', 'mujer', 'leonisa', 'Encuentra en estas 3 tangas brasileras descaderadas un diseño femenino que te va a encantar, están elaboradas con un elástico delgado que va en la cintura y con delicados encajes SmartLace® en colores contrastantes que te harán ver y sentir muy sexy. Estos panties te ofrecen gran comodidad y mayor suavidad al contacto con la piel y vienen en paquete x 3.\r\n', 'Paquete x3 tangas estilo brasileras descaderadas.\r\nElaboradas en DuraFit® suave para que te sientas absolutamente cómoda.\r\nEncaje SmartLace® ubicado en la cola que te da un toque sexy.\r\nLos elásticos delgados en las piernas y cintura vienen en colores que contrastan.\r\nSilueta sexy que te da perfecta modelación.\r\nRefuerzo inferior 100% en algodón.', 320.16, 'si'),
(161, 'PANTY FAJA INVISIBLE - UNA CINTURA MÁS DELGADA', '12811', 'mujer', 'leonisa', 'Panty de control fuerte que controla el abdomen alto, medio y bajo, la cintura y la espalda, elaborado con PowerSlim®. Tiene elásticos antideslizantes que ayudan a que la prenda se mantenga segura en su sitio. Un nuevo estilo: panty clásico combinado con un tul liviano en los glúteos que le da un efecto de tanga brasilera. ¡Disfruta de los nuevos estilos invisibles!.', 'Panty clásico invisible con efecto brasilera.\r\nControl fuerte de cintura, espalda, abdomen alto, medio y bajo.\r\n2 en 1 panty clásico brasilero.\r\nPoder doble capa: DuraFit® PowerSlim®.\r\nBanda elástica antideslizante que reemplaza los elásticos y evita que se marque en la ropa.\r\nTul ultraliviano en glúteos y laterales de delantero.\r\nMoldea la cintura con excelente ajuste.\r\nRefuerzo inferior 100% en algodón.\r\nComposición de la tela: 79% Poliamida, 20% Elastano, 1% Silicona.', 410.64, 'si'),
(162, 'PANTY FAJA REDUCTOR DE ABDOMEN Y CINTURA', '1282', 'mujer', 'leonisa', 'Panty faja alto en cintura, reduce en abdomen medio y bajo, cintura y laterales, te ofrece buen cubrimiento y excelente ajuste al cuerpo. Tiene un panel en la parte delantera elaborado en PowerSlim® que comprime el abdomen para darte un abdomen más plano y una figura más estilizada.', '-Panty faja clásico\r\n-Reducción de abdomen medio y bajo, cintura y laterales\r\n-Excelente cubrimiento de abdomen, cadera y cola\r\n-Poder doble capa: DuraFit® PowerSlim®\r\n-Elásticos suaves que no se marcan ni tallan\r\n-Perfecta modelación y máxima comodidad\r\n-Refuerzo inferior 100% en algodón para mayor frescura\r\n-Composición: poliamida 76.60%, elastano 17.60%, poliéster 5.80%', 348, 'si'),
(163, 'PANTY CACHETERO DESCADERADO CON TOQUES DE ENCAJE', '12836', 'mujer', 'leonisa', 'Panty estilo cachetero descaderado, con delicado y ligero encaje que reemplaza los elásticos en la cintura y en las piernas, te da una apariencia más romántica y coqueta. Este panty es suave, se adapta a tu cuerpo sin maltratar la piel y es extremadamente cómodo.', 'Panty estilo cachetero descaderado\r\nEncaje elástico que reemplaza los elásticos de las piernas y la cintura y te da gran comodidad\r\nIdeal para usarlo con prendas ajustadas, pues no se te marca en tu ropa exterior\r\nRefuerzo inferior 100% en algodón para tu comodidad\r\nComposición de la tela: 61% Algodón, 26% Poliamida, 13% Elastano', 125.28, 'no'),
(164, 'PANTY FAJA DE CONTROL SUAVE ALTO EN LA CINTURA', '12841', 'mujer', 'leonisa', 'Este panty faja clásico es alto en la cintura, ideal para moldear tu figura con absoluto confort y estilo. Esta prenda ejerce un control suave en el abdomen medio-bajo y la cintura, se ajusta perfectamente dándole a tu cuerpo una forma definida y firme. Está elaborado con tecnología seamless SkinFuse® que evita la presencia de costuras para dar una apariencia invisible debajo de la ropa. Tiene un fajón ancho en la cintura con suaves varillas laterales que evitan que el panty se enrolle en la cintura y ayudan a que se mantenga firme dándote mayor seguridad al usarlo todo el día. ¡Disfruta de lo último en panties de control!', 'Panty faja estilo clásico de control fuerte.\r\nControla el abdomen medio-bajo y define la línea de la cintura.\r\nCosturas y elásticos ultraplanos que dan un efecto invisible debajo de la ropa.\r\nSuaves varillas laterales que ayudan a mantener el panty firme y seguro.\r\nEste panty te da perfecta modelación de la cola realzándola naturalmente.\r\nDiferentes tensiones en el tejido que ejercen diferentes niveles de control de acuerdo a la zona.\r\nLibre de tensión en la cola para evitar aplanarla.\r\nElaborada con tecnología seamless SkinFuse®, con pocas costuras y sin cortes para hacerla invisible bajo la ropa.\r\nRefuerzo inferior 100% en algodón para tu comodidad.\r\nComposición de la tela: 80% Poliamida, 20% Elastano.', 243.6, 'si'),
(165, 'PANTY TIPO CACHETERO CON DELICADO ENCAJE', '12875', 'mujer', 'leonisa', 'Panty cachetero en encaje tipo blonda, ligero y suave que se adapta perfectamente al cuerpo. Su diseño sin elásticos brinda efecto invisible y realza la figura con un toque sensual.', 'Panty Cachetero en Encaje Blonda Invisible\r\n• Composición: 90% poliamida – 10% elastano\r\n• Silueta semidescaderada con ajuste cómodo y adaptable\r\n• Diseño sin elásticos en cintura y piernas para evitar marcas\r\n• Encaje elástico floral, ligero y transparente que aporta frescura\r\n• Costura vertical trasera que realza y moldea los glúteos\r\n• Sensación suave, ligera y cómoda durante todo el día\r\n• Refuerzo inferior 100% en algodón para mayor higiene y confort', 97.44, 'si'),
(166, 'Short corto deportivo ajustado y ligero con cómodo elástico en cintura', '195523', 'mujer', 'leonisa', '- Short ajustado, ligero y cómodo.\r\n- Elástico en cintura suave y ancho para más comodidad.\r\n- De secado rápido para que te mantengas fresca todo el tiempo.\r\n- Elaborado en Microfibra.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 69% poliéster, 18% elastano, 13% poliamida. Composición forro: 81% poliéster, 19% elastano.\r\n', 'Este short tiene la modelación y el largo necesario para permitirte toda la libertad que tus entrenamientos necesitan. Su silueta ajustada, comodidad y ligereza harán que lo sientas como una segunda piel. Lo mejor, es que gracias a que está elaborado en Microfibra, se seca rápidamente y es transpirable ¡para que te mantengas fresca todo el tiempo! Su elástico suave y ancho en cintura te brindarán toda la comodidad que necesitas.\r\n', 160.08, 'si'),
(167, 'Short ciclista con tecnología copper y control de abdomen y muslos', '195512', 'mujer', 'leonisa', 'Este short ciclista está elaborado con tecnología Copper con iones de cobre incorporados, que permiten eliminar las bacterias que causan malos olores y ayudan a mantener la temperatura corporal. Estos iones también promueven la antioxidación combatiendo los radicales libres que causan el envejecimiento de la piel. Es una prenda infaltable en tu clóset ya que puedes usarla como deportivo o prenda exterior. Cuenta con control fuerte en el abdomen medio y bajo, y control moderado en los muslos, y al ser de tiro alto, sentirás todo en su lugar para que te muevas con total libertad. Su material es transpirable y de secado rápido, haciendo que te sientas fresca y seca todo el tiempo. Úsalo también bajo tus vestidos o faldas para sentirte más segura ¡Pruébalo y siente la diferencia de la tecnología aplicada a tus prendas!\r\n', 'Short ciclista de tiro alto.\r\nMás poder en tus rutinas: tecnología Copper con iones de cobre que eliminan las bacterias que causan malos olores.\r\nInnovación en cada paso que das: los iones de cobre ayudan a mantener tu temperatura corporal y a combatir los radicales libres que causan el envejecimiento en la piel.\r\nControl fuerte en abdomen medio y bajo. Control moderado en muslos.\r\nDoble capa en la pretina, que moldea y estiliza tu abdomen y cintura.\r\nSecado rápido, fresca y seca en todo momento.\r\nMultipropósito: úsalo para hacer deporte, como prenda exterior o bajo tus vestidos y faldas.\r\nComposición: 74% poliamida, 26% elastano. Composición forro: 74% poliamida, 26% elastano\r\n', 243.6, 'si'),
(168, 'Panty tipo Tanga Brasilera en Encaje', '12883', 'mujer', 'leonisa', 'Panty estilo brasilera de silueta descaderada, elaborado con dos materiales diferentes de última tecnología que juntos muestran una nueva forma, más fresca y renovada de usar el encaje.', 'La parte delantera de la brasilera está elaborada completamente en encaje floral.\r\nLa parte trasera está elaborada en tul, con transparencias muy evidentes.\r\nPuntilla delicada que rodea la cintura reemplazando el elástico, le agrega ese toque suave y sutil.\r\nUna prenda que se adapta al cuerpo sin que se marque en la ropa.\r\nRefuerzo 100% en algodón para dar mayor comodidad.\r\nComposición: poliamida 85.00%, elastano 15.00%.', 146.16, 'si'),
(169, 'Top deportivo doble faz diseño asimétrico', '19AA10', 'mujer', 'leonisa', '- Top deportivo doble faz.\r\n- Cargaderas anchas para mayor soporte.\r\n- Buen cubrimiento en espalda, sisa y escote.\r\n- Secado rápido: fresca y seca todo el tiempo.\r\n- Base delantera curvada como toque de moda.\r\n- Composición: 77% poliéster, 18% elastano, 5% poliamida. Composición forro: 82% poliamida, 18% elastano.\r\n', 'El diseño curvado en la base de este top será ese detalle que te hará decir ¡lo quiero! Es doble faz para que tengas dos opciones en una sola y sus cargaderas son asimétricas para un toque de estilo diferente y único. Es de muy buen cubrimiento en espalda y laterales de la sisa. Su material de secado rápido hace que incluso después de tus entrenamientos más fuertes, te sientas muy fresca.\r\n', 187.92, 'si'),
(170, 'Jogger deportivo estilo sudadera con bolsillos laterales funcionales', '518012', 'hombre', 'leo', 'Este jogger deportivo tipo sudadera, es ideal para tus rutinas deportivas o para el uso diario, convirtiéndose en un infaltable para esos momentos de comodidad y descanso. Es muy suave al tacto, además, cuenta con bolsillos laterales para que lleves contigo tus objetos personales. Cuenta con cordón ajustable en cintura para que permanezca siempre en su lugar durante tus desplazamientos. El rib (elástico) en la parte inferior de las piernas hace que la prenda tenga mayor ajuste.\r\n', 'Jogger deportivo tipo sudadera.\r\n2 bolsillos laterales ideales para llevar contigo tus objetos personales.\r\nCordón ajustable en cintura.\r\nElástico en la parte inferior de las prendas para mayor ajuste y libertad de movimiento\r\nComposición: 65% poliéster, 29% algodón, 4% elastano, 2% elastodieno\r\n', 271.44, 'si'),
(171, 'BUSTIER STRAPLESS DE MÁXIMO REALCE', '11929', 'mujer', 'leonisa', 'Este bustier además de ser strapless es push up, te da todo lo que buscas en un brasier. Las copas fueron diseñadas para sostener, centrar, realzar y todo ésto gracias a una estructura interna en forma de manos. Es una prenda lisa que se adapta perfectamente a la forma del cuerpo. Tiene elásticos anchos antideslizantes siliconados en la espalda que se adhieren a la piel evitando que el brasier se deslice.\r\n\r\n', 'Bustier strapless de realce alto sin arco interno.\r\nIdeal para busto pequeño, regular y grande.\r\nCopas con estructura interna en forma de manos que sostiene, centra y levanta.\r\nElásticos antideslizantes siliconados en espalda que mantienen el brasier en su lugar.\r\nComposición: poliamida 81%, elastano 14%, silicona 5%.\r\nCargaderas para uso convencional, cruzadas, halter, un hombro o strapless.\r\nEspalda ancha con abrochadura de dos ganchos y cuatro niveles de ajuste.\r\n', 487.2, 'si'),
(172, 'Paquete x 2 Panties Cacheteros en Encaje y Tul', '12884X2', 'mujer', 'leonisa', 'Cacheteros semidescaderados en paquete x 2 elaborados con materiales de ultima tecnología: delicado tul con puntos tejidos en la parte delantera y encaje de ajuste perfecto, en la parte trasera. ¡Te sentirás muy sexy y cómoda, querrás tenerlos en todos los colores! Son ideales para el día a día. Combínalos con nuestros bralettes o brasieres en encaje y luce espectacular. Refuerzo 100% en algodón para dar mayor comodidad.', 'Paquete x2 panties cacheteros elaborados en encaje y tul.\r\nSilueta semidescaderada\r\nEncaje delicado que rodea la cintura reemplazando el elástico.\r\nNo se marcan en tu piel, ni tu ropa, perfectos para usar con topa ajustada.\r\nRefuerzo 100% en algodón para dar mayor comodidad.\r\nComposición: 85% poliamida, 15% elastano', 306.24, 'si'),
(173, 'Jogger deportivo de silueta amplia con bolsillos', '195532', 'mujer', 'leonisa', 'Toda la comodidad que necesitas en tus entrenamientos la tendrás con este jogger deportivo de silueta amplia. Ideal para deportes de impacto medio como caminar, bailar, hacer yoga o pilates, y también para uso diario o para momentos de descanso. Su cintura es ajustable ya que además del elástico, cuenta con un cordón que permite que lo adaptes y ajustes a tu contorno.\r\n', 'Jogger deportivo suave al tacto con tu piel.\r\nElástico en cintura para darle más ajuste a la prenda.\r\nCordón plano en cintura para adaptarlo a tu contorno y para que el jogger se mantenga en su lugar durantes tus movimientos.\r\nBolsillos delanteros de gran capacidad.\r\nCosturas decorativas planas en el bolsillo que le dan un toque sutil de moda.\r\nComposición: 74% poliéster, 21% elastano, 3% algodón, 2% elastodieno.\r\n', 250.56, 'si'),
(174, 'Camiseta deportiva con tela texturizada y transpirable', '508039', 'hombre', 'leo', ' Camiseta deportiva de máxima tecnología.\r\n- Silueta semiajustada.\r\n- Tela texturizada que permite el paso del aire ¡siempre fresco!\r\n- Secado rápido.\r\n- Ultraliviana y suave al tacto.\r\n- Tejido elástico que te da libertad de movimiento.\r\n- Reflectivo en espalda: ideal para caminar o trotar de noche.\r\n- Composición: 92% poliéster, 8% elastano.\r\n', 'Camiseta deportiva masculina de máxima tecnología, perfecta para estar fresco todo el tiempo, gracias a su tela texturizada que permite el paso del aire. También es ultraliviana y suave al tacto para que te sientas cómodo todo el tiempo. El estampado reflectivo en la espalda es perfecto para cuando salgas a caminar o trotar durante la noche y su tejido elástico te da libertad de movimiento. Úsala para salir a trotar, ir al gimnasio, levantar pesas o practicar tus deportes favoritos.', 250.56, 'si'),
(175, 'BRALETTE TRIANGULAR TIPO BUSTIER', '11950L', 'mujer', 'leonisa', 'Este bralette triangular es un homenaje a la feminidad, ya que está totalmente cubierto del más lindo de los encajes.', 'Sus copas están elaboradas con una suave y delgada espuma que permite el paso del aire, logrando que te sientas cómoda y fresca todo el tiempo. Además, su espalda está totalmente libre de abrochaduras, ya que cuenta con un elástico que la atraviesa de manera horizontal para lograr el ajuste que necesitas\r\n-Bralette triangular tipo bustier\r\n-Copas en suave y delgada espuma que permite el paso del aire\r\n-Cubierto totalmente por un encaje delicado y resistente\r\n-Espalda sin abrochadura, la cual es reemplazada por un elástico horizontal que asegura el ajuste\r\n-Composición: poliamida 83%, elastano 17%\r\n-Cargaderas fijas y graduables', 306.24, 'si'),
(176, 'PANTY ALTO CON ENCAJE EN BANDAS', '12890', 'mujer', 'leonisa', 'Panty hipster de tiro alto con control suave de abdomen y encaje en bandas. Se ajusta al cuerpo sin marcar, realzando tus curvas con un efecto elegante y sensual. Ideal para estilizar la figura con comodidad.', 'Panty Hipster de Encaje con Control Suave de Abdomen\r\n• Composición: 65% poliamida – 35% elastano / refuerzo 100% algodón\r\n• Silueta alta a la cintura con control suave de abdomen\r\n• Tecnología de encaje en bandas con transparencias localizadas\r\n• Ajuste firme y cómodo que se adapta al cuerpo sin oprimir\r\n• Diseño sin elásticos en cintura y piernas para efecto invisible\r\n• Costura vertical trasera que ayuda a modelar y realzar los glúteos\r\n• Refuerzo inferior en algodón que aporta frescura e higiene\r\n• Sensación suave, ligera y de soporte durante todo el día', 118.32, 'si'),
(177, 'PANTY CLÁSICO EN ENCAJE TECHNO-LACE', '12897', 'mujer', 'leonisa', 'Panty clásico de tiro alto en encaje Techno-Lace que ofrece máximo cubrimiento y comodidad total. Su diseño sin costuras ni elásticos brinda efecto invisible, mientras realza la figura de forma natural.', 'Panty Clásico Alto en Encaje Techno-Lace\r\n• Composición: 65% poliamida – 35% elastano\r\n• Ajuste de tiro alto que moldea el abdomen y estiliza la silueta\r\n• Diseño sin elásticos ni costuras laterales para evitar marcas\r\n• Encaje Techno-Lace resistente que no se desmalla y mantiene su forma\r\n• Parte trasera en tul ligero que realza el volumen natural\r\n• Sensación suave, cómoda y fresca durante todo el día\r\n• Refuerzo en algodón que aporta mayor higiene y confort', 139.2, 'si'),
(178, 'SEXY PANTY CACHETERO EN TELA ULTRALIVIANA', '12898', 'mujer', 'leonisa', 'Panty hipster invisible de silueta descaderada, ultraliviano y suave. Su diseño sin elásticos ni marcas se adapta perfectamente al cuerpo, realzando la figura con total comodidad.', 'Panty Hipster Invisible Ultraliviano con Puntilla\r\n• Composición: 77% poliamida – 23% elastano\r\n• Silueta descaderada con laterales anchos para mayor cubrimiento\r\n• Diseño sin elásticos en cintura y piernas que evita marcas\r\n• Costuras superplanas e imperceptibles para efecto invisible\r\n• Tela ultraliviana, suave y fresca con fibras de alta tecnología\r\n• Detalle en puntilla que aporta un acabado delicado y femenino\r\n• Costura vertical trasera que realza y moldea los glúteos\r\n• Refuerzo inferior 100% en algodón para mayor higiene y confort', 111.36, 'si'),
(179, 'SEXY BRASILERA EN TELA ULTRALIVIANA', '12899', 'mujer', 'leonisa', 'Esta brasilera descaderada está elaborada en tela ultraliviana con fibras de última tecnología que aseguran suavidad, frescura y ligereza. No tiene elásticos en cintura ni piernas para mayor comodidad y ajuste. Las costuras son superplanas e imperceptibles, con excelente ajuste al cuerpo.', 'Panty estilo brasilera invisible.\r\nSilueta semidescaderada.\r\nLaterales anchos.\r\nDetalle en puntilla en piernas y cintura para dar un toque delicado.\r\nRefuerzo inferior 100% en algodón.\r\nComposición: poliamida 78%, elastano 22%.', 83.52, 'no'),
(180, 'LEGGINGS CON CONTROL DE ABDOMEN', '12900', 'mujer', 'leonisa', 'Estos leggings de control están elaborados con nuestra tecnología Skinfuse®, que cuenta con tensiones inteligentes y muy pocas costuras; es decir que ejercen presión y moldean aquellas áreas del cuerpo que quieres mejorar y suavizan sin cambiar la forma de aquellas partes que quieres resaltar. Cuenta con un tiro alto con el fin de moldear tu abdomen y acentuar tu cintura. Esta prenda que conocíamos por su gran confort, ahora también moldea tu cuerpo.', 'Leggins elaborados con nuestra tecnología Skinfuse®.\r\nEl tejido de la cola suaviza la piel pero no tiene comprensión, para que no se aplane.\r\nTiro alto perfecto para controlar el abdomen medio, bajo y cintura.\r\nSin costuras marcadas para brindarte mayor comodidad.\r\nComposición: Elastano 20%, Poliamida 80%.', 320.16, 'si'),
(181, 'PANTY FAJA CLÁSICO CON BANDAS DE TUL', '12903', 'mujer', 'leonisa', '¡Prepárate para sentirte más sexy que nunca! Con este seductor panty clásico alto a la cintura, que además de controlar tu abdomen hace que tu cuerpo se vea moldeado. Es efecto invisible, por eso no se marca con la ropa exterior ya que no tiene elásticos en las piernas. ¡Realza tus glúteos y obtén una silueta increíble! Ya que cuenta con un increíble encaje con diseño de bandas en los laterales y glúteos, que le dan ese toque femenino y muy sexy. Gracias a su comodidad y sensualidad, vas a querer uno para cada día.', 'Panty clásico con control fuerte en abdomen y cadera\r\n¡Es invisible bajo tu ropa! Ya que no tiene elásticos en la pierna\r\nLe da más volumen a tus glúteos, gracias a una costura trasera recogida\r\nCosturas planas que la hacen más suave y cómoda\r\nRefuerzo en algodón, para que te sientas fresca todo el día\r\nComposición: 73% poliamida, 24% elastano', 236.64, 'si'),
(182, 'Bralette sin Arcos Triangular en Encaje ', '11952', 'mujer', 'leonisa', 'Este es un bralette sin estructuras ni realce, elaborado totalmente en encaje, lo que le da a la prenda un cierto nivel de transparencias que te aporta muchísima sensualidad. Y en la base, cuenta con un elástico a rayas que le dá un toque deportivo y muy juvenil.', 'Bralette triangular sin arco ni estructuras\r\nElaborado totalmente en encaje para un look muy sexy\r\nElástico lúrex en la base, para un toque de brillo\r\nElásticos cruzados en el pecho para un escote perfecto\r\nAbrochadura doble con cuatro niveles de ajuste\r\nComposición: poliamida 80.00%, elastano 19.00%, poliéster 1.00%.', 208.8, 'si'),
(183, 'Panty faja busto libre de control de abdomen invisible en piernas', '12906', 'mujer', 'leonisa', 'Este panty faja de tiro alto controla el abdomen alto, medio, bajo y la cintura. Cuenta con doble capa de tela en el abdomen: PowerSlim, nuestro material de compresión   una tela lisa suave al tacto que te dan mayor compresión. Su elástico antideslizante en la base del busto se adhiere a tu piel ayudando a que la faja permanezca en su lugar y cuenta con ojales para abrochar las cargaderas del brasier. Su práctica abrochadura en la parte inferior permite ajustarlo a tu cuerpo y facilita su uso diario para ir al baño. El encaje en bandas sólidas y transparentes de la parte delantera, los laterales y los glúteos le dan un toque femenino y sexy. Su costura central en la parte trasera brinda una modelación redondeada a tus glúteos, y al no tener elásticos en las piernas es de efecto invisible ¡No te preocupes por las marcas en tu piel!', 'Panty faja de control con doble capa en abdomen PowerSlim   tela lisa.\r\nControl moderado en abdomen alto.\r\nControl fuerte en abdomen medio y bajo.\r\nElástico antideslizante en la base del busto que facilita que la prenda permanezca en su lugar.\r\nBandas con transparencias en abdomen, glúteos y piernas para un toque muy sexy.\r\nElástico recogido en los glúteos para una modelación más redondeada.\r\n¡Despídete de las marcas en tu piel! No tiene elásticos en las piernas.\r\nUso fácil y práctico: abrochadura inferior con refuerzo de algodón y 3 niveles de ajuste.\r\nComposición: 70% poliamida, 28% elastano, 2% silicona, composición forro: 79% ', 410.64, 'si'),
(184, 'Camiseta deportiva masculina semiajustada de secado rápido', '508007', 'hombre', 'leo', 'Camiseta deportiva masculina con tecnología aplicada a la prenda: material transpirable de secado rápido. Con esta camiseta te sentirás cómodo y fresco durante tus entrenamientos. Su silueta es semiajustada y su material es muy liviano. Combínala con nuestras pantalonetas, licras o joggers deportivos: todo lo que necesitas para dar el máximo en tus rutinas.\r\n', 'Camiseta deportiva masculina.\r\nLiviana y ligera.\r\nTela transpirable.\r\nSecado rápido.\r\nComposición: 100% poliéster', 243.6, 'si'),
(185, 'PANTY EN ALGODÓN ULTRASUAVE', '12908', 'mujer', 'leonisa', 'Panty hipster de algodón Pima ultra suave que brinda frescura y máxima comodidad. Su diseño sin elásticos y efecto invisible se adapta al cuerpo con ajuste perfecto y mayor cobertura.', '\r\nPanty Hipster en Algodón Pima Premium\r\n• Composición: 95% algodón Pima – 5% elastano\r\n• Tiro medio con mayor cobertura para mayor seguridad y confort\r\n• Diseño sin elásticos que evita marcas bajo la ropa\r\n• Algodón Pima de alta calidad, extra suave, transpirable y resistente\r\n• Tecnología antientorche que mantiene la prenda en su lugar sin enrollarse\r\n• Corte trasero moderno que aporta un look juvenil\r\n• Sensación fresca, ligera y cómoda para uso diario', 125.28, 'si'),
(186, 'PANTY HIPSTER CON ENCAJE ', '12911', 'mujer', 'leonisa', 'Panty cachetero de diseño mixto que combina tela antientorche y encaje multicolor. Brinda ajuste cómodo, efecto levantacola natural y un look moderno con toque sofisticado.', 'Panty Cachetero con Encaje Multicolor y Efecto Levantacola\r\n• Composición: 67% poliamida – 19% elastano – 14% rayón\r\n• Diseño de tiro medio con ajuste cómodo y adaptable al cuerpo\r\n• Tela frontal antientorche que evita que la prenda se enrolle o se desplace\r\n• Parte trasera en encaje tecnológico con efecto visual multicolor\r\n• Costura recogida posterior que realza y levanta los glúteos de forma natural\r\n• Elástico delgado y suave en cintura que no oprime ni marca\r\n• Sensación ligera, fresca y cómoda para uso diario\r\n• Refuerzo inferior en algodón para mayor higiene y frescura', 167.04, 'si'),
(187, 'CAMISETA DE COMPRESION MODERADA', '35013', 'hombre', 'leo', 'Esta camiseta para hombre cuenta con compresión moderada en abdomen y espalda, y es ideal para hacer deporte o para uso diario ya que está elaborada en algodón elástico, garantizándote un excelente ajuste a tu cuerpo. Cuenta con doble capa de algodón en el abdomen y en la zona lumbar para mayor compresión y para facilitar una mejor postura. Úsala cada que vayas a hacer deporte de peso o cardiovascular. También es ideal para usarla bajo tu ropa en el día a día.\r\n', '- Camiseta deportiva o de uso diario, de compresión moderada.\r\n- Doble capa de algodón elástico en abdomen y zona lumbar, para mayor compresión.\r\n- Cuello redondo y manga sisa para mayor comodidad y libertad de movimiento.\r\n- Ayuda a mantener la espalda recta durante el día.\r\n- Puedes usarla bajo todas tus camisas.\r\n', 334.08, 'si'),
(188, 'BRALETTE TRIANGULAR EN ENCAJE CON APLIQUE BORDADO', '11957', 'mujer', 'leonisa', 'Este bralette triangular es perfecto para aquellas mujeres cómodas y naturales que no quieren perder su sensualidad; ya que no tiene estructuras rígidas, almohadillas ni arcos internos. ', ' Está elaborado totalmente en encaje y la parte de las copas cuenta con doble tela para evitar transparencias y con un aplique bordado que te va a encantar. Si las rosas están de moda y los bralettes se hicieron para mostrar, esta es la mezcla perfecta.\r\nDetalles de la prenda\r\n- Bralette triangular sin arco ni almohadillas\r\n- Copas en doble tela para evitar transparencias, con aplique bordado\r\n- Elaborado en encaje y con un elástico en la base para mayor soporte del busto\r\n- Cargaderas fijas adelante que puedes graduar tanto como lo necesites\r\n- Espalda en U para un look muy delicado\r\n- Abrochadura doble con tres niveles de ajuste\r\n- Composición: poliamida 84.00%, elastano 16.00%, Composición Forro: poliamida 91.00%, elastano 9.00%.\r\n\r\n', 215.76, 'no'),
(189, 'PANTY BIOMODELADOR DE CONTROL FUERTE CON LEVANTACOLA', '12912', 'mujer', 'leonisa', 'Faja pantalón elaborada en PowerSlim, lo que genera un control fuerte en el abdomen alto, medio, bajo, cintura y espalda. Además, dos bandas de PowerSlim ubicadas debajo de los glúteos, se encargan de centrar y levantar la cola de una forma muy natural. Disfruta de la facilidad que este panty biomodelador te ofrece al momento de la postura, gracias a un cierre acompañado de dos ganchos y un broche en la parte superior, que hacen que ponerte y quitarte la prenda sea mucho más fácil.', '-Panty biomodelador con doble capa de PowerSlim, genera un control fuerte en abdomen, cintura y espalda\r\n-Dos bandas de PowerSlim que rodean los glúteos y una costura recogida, crean un efecto levantacola\r\n-Elástico antideslizante en el contorno y cuatro ojales para poner tus cargaderas\r\n-Cierre frontal que no talla, con dos ganchos y un broche que facilitan la postura\r\n-Control moderado en los muslos y abertura perineal\r\n-Composición: poliamida 84.00%, elastano 15.00%, caucho 1.00%, Composición Forro: poliamida 78.00%, elastano 14.00%, ALGODÓN 8.00%.', 508.08, 'no'),
(190, 'Enterizo deportivo de cargaderas cruzadas en espalda', '195624', 'mujer', 'leonisa', ' Incluye top interno fijo con elástico en la base para brindarte mayor soporte.\r\n- Sus cortes en la cintura y en las piernas le dan un efecto más curvado a tu cuerpo.\r\n- Control moderado de abdomen y muslos: un cuerpo más definido en segundos.\r\n- Cargaderas graduables en espalda con elástico expuesto.\r\n- Corte en los glúteos en forma de corazón para efecto realce.\r\n- Tecnología de secado rápido: fresca y seca incluso después de tus entrenamientos más fuertes.\r\n- Sin corte frontal para que no se marque en la entrepierna.\r\n- Úsalo con una camisa o una chaqueta abierta y estarás lista para salir ¡transforma tu look deportivo en exterior con solo algunos\r\ncomplementos y accesorios!\r\n- Composición: 63% poliamida, 37% elastano. Composición forro: 82% poliamida, 18% elastano.\r\n', 'Si eres amante de los enterizos deportivos, este en específico tiene unos detalles que te encantarán. Por ejemplo, sus cortes en cintura y piernas te hacen ver con más curvas. Sus cargaderas cruzadas en espalda son graduables y le dan un look muy trendy al tener el elástico expuesto. En los glúteos tiene un corte tipo corazón para darles un efecto más redondeado. Además, en la entrepierna, no tiene costura frontal, para evitar que se marque la zona V.\r\n\r\n\r\n', 640.32, 'si'),
(191, 'PANTY HIPSTER CON TUL Y ENCAJE', '12919', 'mujer', 'leonisa', 'Panty hipster en tul ligero que combina transparencia sutil y suavidad. Su diseño con encaje en cintura y doble capa trasera brinda comodidad, ajuste perfecto y un toque coqueto.', 'Panty Hipster en Tul con Encaje Decorativo\r\n• Composición: 90% poliamida – 10% elastano\r\n• Tiro semidescaderado con ajuste cómodo y adaptable\r\n• Tul ligero y suave que aporta frescura y sensación liviana\r\n• Franja de encaje en la cintura que añade un toque femenino y elegante\r\n• Doble capa trasera que evita transparencias y brinda mayor seguridad\r\n• Diseño que se adapta al cuerpo con libertad de movimiento\r\n• Refuerzo en algodón para mayor higiene y confort diario', 139.2, 'si'),
(192, 'BRALETTE DE REALCE MEDIO EN ENCAJE', '11961A', 'mujer', 'leonisa', 'Este bralette es la mezcla perfecta entre un brasier con estructura y un top suave y ligero, ya que sus copas cuentan con un pequeño relleno en la parte inferior, que te dan un realce medio; pero el resto de la prenda, está elaborada totalmente en encaje Eyelash®, lo que la hace totalmente femenina y cómoda.\r\n', 'Bralette triangular en encaje Eyelash®.\r\nCopas con relleno inferior, para un realce medio.\r\nCargaderas fijas y graduables estilo halter.\r\nEspalda con diseño en encaje para un look único.\r\nComposición: poliamida 83.00%, elastano 17.00%, Composición Forro: poliamida 100.00%.\r\n', 320.16, 'si'),
(193, 'BRASIER TIPO BUSTIER DE REALCE SUAVE', '11965', 'mujer', 'leonisa', 'Enamórate de la delicadeza de este bustier, elaborado totalmente en el más femenino de los encajes. Sus copas son muy suaves y livianas, sin realce incorporado y generan un seductor realce suave. y Gracias a unas varillas flexibles en la espalda, el brasier permanece siempre en su lugar.\r\n', 'Detalles de la prenda\r\n- Brasier tipo bustier elaborado en encaje\r\n- Copas prehormadas con arco, que generan un realce suave\r\n- Varillas flexibles y fragmento de tul elástico en espalda, que lo hace muy cómodo\r\n- Cargaderas para uso convencional, cruzado, halter, un hombro y strapless\r\n- Espalda ancha con abrochadura de seis ganchos y cuatro posiciones de ajuste\r\n- Composición: poliéster 67%, poliamida 18%, elastano 15%', 438.48, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(194, 'Top deportivo con espalda atlética en material de secado rápido', '195356', 'mujer', 'leonisa', 'Top deportivo de soporte medio sin copas removibles, con detalle de tul en cargaderas y espalda. Su material es de secado rápido, por lo que te sentirás fresca y seca en todo momento durante tus entrenamientos. El elástico ancho en la base le brinda soporte al busto. Cuenta con doble capa de tela en las copas para evitar transparencias. Su espalda es de silueta atlética para que te sientas muy libre en tus movimientos. El detalle de media luna en el centro de la espalda deja ver tu piel: además de facilitar la transpiración es perfecto para lucir su diseño con camisetas de silueta amplia, espalda escotada o incluso como prenda única superior. Es ideal para ir al gimnasio, bailar, caminar, trotar o para usar en el día a día.\r\n', 'Top deportivo de soporte medio con doble capa de tela en las copas.\r\nSin copas removibles.\r\nMaterial de secado rápido: fresca y seca todo el tiempo.\r\nDetalle en tul en cargaderas y espalda para facilitar transpiración.\r\nLibertad de movimiento gracias a su espalda atlética.\r\nIdeal para ir al gimnasio, bailar, caminar, trotar o para usar en el día a día.\r\nÚsalo con camisetas de silueta amplia o espalda descubierta.\r\nComposición: 60% poliéster, 25% poliamida, 15% elastano, composición forro: 92% poliamida, 8% elastano.\r\n', 167.04, 'si'),
(195, 'PANTY CACHETERO SEMIDESCADERADO CON ENCAJE', '12920', 'mujer', 'leonisa', 'Panty cachetero de excelente cubrimiento que combina comodidad y sensualidad. Sus franjas laterales de encaje realzan la figura mientras moldean suavemente con un ajuste perfecto.\r\n', 'Panty Cachetero con Encaje Lateral y Modelación\r\n• Composición: 90% poliamida – 10% elastano\r\n• Silueta semidescaderada con buen cubrimiento en cintura y glúteos\r\n• Fajón en cintura con doble capa que brinda mejor ajuste y soporte\r\n• Franjas laterales de encaje que aportan un toque sensual y moderno\r\n• Costura trasera que mejora la modelación y realza la figura\r\n• Tela suave y elástica que se adapta cómodamente al cuerpo\r\n• Sensación de confort y seguridad para uso diario', 146.16, 'si'),
(196, 'Camiseta deportiva de secado rápido ', '195336', 'mujer', 'leonisa', 'Te sentirás muy fresca durante y después de tu entrenamiento con esta camiseta deportiva de secado rápido. Es manga sisa, de espalda atlética y de silueta semiajustada, lo cual te permitirá moverte con total libertad. Ideal para combinar con nuestros leggings, shorts y capris deportivos.\r\n', 'Camiseta deportiva atlética.\r\nSecado rápido.\r\nEspalda atlética.\r\nSilueta semiajustada.\r\nComposición: 100% poliéster\r\n', 167.04, 'si'),
(197, 'SUPPORT BRA DE REALCE MEDIO ', '11966', 'mujer', 'leonisa', 'Este brasier es la mezcla perfecta entre realce y control, ya que sus copas prehormadas con realce medio, le dan a tu busto una linda forma redondeada y al tener PowerSlim en toda la base y la espalda, genera un control que te ayuda a reducir los molestos gorditos de esa parte del cuerpo.\r\n', 'Brasier triangular de realce medio con arco interno.\r\nCopas prehormadas y elástico ancho bajo el busto para mayor soporte.\r\nBase y espalda ancha de PowerSlim, que controla y reduce los gorditos.\r\nSuaves varillas laterales que ayudan a centrar el busto.\r\nCargaderas graduables para uso convencional o cruzado.\r\nAbrochadura con tres ganchos y cuatro niveles de ajuste.\r\nComposición de la tela: poliamida 84.00%, elastano 16.00%, Composición Forro: poliamida 86.00%, elastano 14.00%.\r\n', 382.8, 'si'),
(198, 'Camiseta deportiva de secado rápido y silueta semiajustada', '195324', 'mujer', 'leonisa', 'Camiseta deportiva de secado rápido y silueta semiajustada. Poliéster.\r\n', 'Camiseta deportiva de secado rápido.\r\nSilueta semiajustada.\r\nPoliéster.\r\nComposición: 100% poliéster\r\n\r\n\r\n', 194.88, 'si'),
(199, 'BRASIER TRIANGULAR DE ENCAJE Y TRANSPARENCIAS', '11967', 'mujer', 'leonisa', 'Este brasier es la sensualidad hecha prenda, ya que está elaborado completamente en encaje floral y transparencias, lo cual genera transparencias muy seductoras. Cuenta con un arco que genera mayor soporte y mejor modelación del busto, para generar un escote increíble. Además, tiene varillas laterales para mayor ajuste al cuerpo y las moras del encaje se prolongan desde el escote hasta los hombros, dándole un toque romántico y sexy a las cargaderas.\r\n', 'Detalles de la prenda:\r\n\r\n- Brasier triangular elaborado en encaje floral con transparencias\r\n- Ideal para busto pequeño, regular y grande\r\n- Copas en encaje, con arco interno que moldea tu busto increíblemente\r\n- Suaves varillas laterales, hacen que la prenda permanezca en su lugar\r\n- Cargaderas graduables para uso convencional o cruzado\r\n- Espalda ancha elaborada en un tul con transparencia; con abrochadura de 6 ganchos y 4 niveles de ajuste\r\n- Composición: poliamida 95%, elastano 5%', 334.08, 'si'),
(200, 'Top deportivo doble faz de un solo hombro', '19AA01', 'mujer', 'leonisa', 'Ya tienes un top asimétrico de un solo hombro para tus entrenamientos? Nuestro top deportivo será una de tus nuevas siluetas favoritas. Es una prenda muy liviana y ligera sin copas removibles. Es doble faz ¡solo tienes que darle la vuelta y tendrás una nueva prenda! Su material de secado rápido hará que te sientas muy fresca todo el tiempo. Su diseño hace que tus manos estén libres para moverte, alzar pesas, bailar, hacer yoga ¡lo que quieras! Incluso es un top que puedes usar también con tu ropa exterior.\r\n', 'Top deportivo de un solo hombro.\r\nSin copas removibles.\r\nDoble faz: dos prendas en una.\r\nSecado rápido: fresca y seca todo el tiempo.\r\nLiviano, ligero y de tacto suave.\r\nAdemás de usarlo en tus entrenamientos, úsalo también como top con tu ropa exterior.\r\nComposición: 86% poliamida, 14% elastano. Composición Forro: 82% poliamida, 18% elastano\r\n', 139.2, 'si'),
(201, 'Panty hipster semidescaderado en encaje de bandas con refuerzo en algodon', '12921', 'mujer', 'leonisa', 'Panty hipster de encaje con transparencias que combina sensualidad y comodidad. Su diseño sin elásticos se adapta suavemente al cuerpo, brindando un ajuste ligero y elegante.', 'Panty Hipster en Encaje con Transparencias\r\n• Composición: 90% poliamida – 10% elastano\r\n• Silueta semidescaderada con ajuste cómodo y adaptable\r\n• Encaje de líneas con bloques sólidos y transparencias que aportan un diseño sensual\r\n• Sin elásticos en cintura y glúteos para evitar marcas y mayor confort\r\n• Tela ligera, suave y elástica que permite frescura y libertad de movimiento\r\n• Diseño que realza la figura con un acabado moderno y elegante\r\n• Refuerzo inferior en algodón para mayor higiene y frescura', 139.2, 'si'),
(202, 'Brasilera invisible con toques de encaje en cintura', '12968', 'mujer', 'leonisa', 'Brasilera invisible elaborada en tela lisa para mayor confort con encaje en laterales para dar un toque de sensualidad y feminidad. Sin elásticos para que sientas extremo confort, mayor suavidad al tacto con la piel y además no se marque en la ropa.', 'Detalles del producto:\r\n\r\n- Panty estilo brasilera con toques de encaje en laterales.\r\n- Elaborado en tela lisa para mayor confort.\r\n- Tiro medio.\r\n- Sin costuras para una apariencia invisible. No se marca en tu piel ni en tu ropa.\r\n- Refuerzo inferior 100% en algodón para mayor comodidad y frescura.', 647.28, 'si'),
(203, 'BÓXER CORTO CON CONTROL DE ABDOMEN Y CINTURA', '12925', 'mujer', 'leonisa', '¡Este bóxer es el complemento perfecto de tus looks! Úsalo con la ropa que quieras: pantalones ajustados, vestidos o faldas, ya que al contar con un talle alto y estar elaborado con dos capas de tela, genera un control moderado en tu abdomen y cintura, moldeando tus curvas para que no tengas que preocuparte por nada. Además, tiene unos cortes ergonómicos en la parte trasera, que moldean los glúteos sin aplanarlos. ¡Pruébatelo y enamórate de tu nueva silueta!', 'Panty hipster elaborado en tela antientorche en la parte delantera\r\nEncaje en la parte trasera, con un tejido que permite ver varios colores\r\nCostura recogida en la parte de atrás, que genera un natural efecto levantacola\r\nRefuerzo inferior en algodón para mayor frescura\r\nElástico suave y delgado en la cintura\r\nComposición: 19% elastano, 67% poliamida, 14% rayón', 341.04, 'si'),
(204, 'Top deportivo sin costuras doble faz', '195369', 'mujer', 'leonisa', 'Top deportivo doble faz con tecnología sin costuras SkinFuse, para que sientas más confort y comodidad cuando realices tus entrenamientos. Es liviano, ligero y muy suave al tacto. Su diseño recoge y centra el busto para que sientas todo en su lugar mientras realizas tus actividades deportivas ¡Además tu busto lucirá muy natural! Se ajusta perfectamente a tu cuerpo y brinda un excelente soporte.\r\n', ' Top deportivo con tecnología seamless SkinFuse: total comodidad y no se marca en la ropa exterior.\r\n- Excelente ajuste y soporte alto de busto.\r\n- Tecnología de secado rápido: fresca y seca todo el tiempo.\r\n- Doble faz, dos tops en uno solo, ¡más variedad!\r\n- Ideal para ir al gimnasio, bailar, caminar, trotar o para usar en el día a día.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 70% poliamida, 30% elastano.\r\n', 194.88, 'si'),
(205, 'PANTY HIPSTER DESCADERADO CON ENCAJE', '12927', 'mujer', 'leonisa', 'Panty hipster de tiro bajo con laterales anchos que brindan mayor cobertura y ajuste cómodo. Su detalle en encaje aporta un toque delicado mientras estiliza suavemente la silueta.', 'Panty Hipster con Laterales Anchos y Encaje\r\n• Composición: 86% poliamida – 14% elastano\r\n• Silueta descaderada que se adapta cómodamente al cuerpo\r\n• Laterales anchos que ayudan a estilizar y brindar mayor cobertura\r\n• Franja de encaje frontal que aporta un toque femenino y coqueto\r\n• Tela suave y elástica que favorece un ajuste natural\r\n• Sensación cómoda y ligera ideal para uso diario\r\n• Refuerzo en algodón para mayor higiene y frescura', 125.28, 'si'),
(206, 'COVER BRA. DE REALCE SUAVE Y CUBRIMIENTO ALTO', '11970L', 'mujer', 'leonisa', 'Este brasier es ideal para aquellas mujeres que buscan estilizar su figura, debido a que es de alto cubrimiento, no solo en copas, sino, sobre todo, en sisa y espalda; ya que cuenta con una capa interna de PowerSlim® en la base y la sisa y con doble capa de tela en la espalda.\r\n', 'Detalles de la prenda\r\n- Brasier triangular con alto cubrimiento en sisa y espalda\r\n- Copas de alto cubrimiento, con arco interno, para un realce suave\r\n- PowerSlim® en la base y la sisa, para controlar los gorditos\r\n- Espalda ancha con doble capa de tela, que elimina los rollitos más molestos\r\n- Suaves varillas laterales que centran el busto\r\n- Cargaderas graduables con broches delanteros, para uso cruzado\r\n- Abrochadura de tres gachos y cuatro niveles de ajuste', 556.8, 'si'),
(207, 'COVER BRA: BRASIER DE REALCE SUAVE Y CUBRIMIENTO ALTO', '11970D', 'mujer', 'leonisa', 'Este brasier es ideal para aquellas mujeres que buscan estilizar su figura, debido a que es de alto cubrimiento, no solo en copas, sino, sobre todo, en sisa y espalda; ya que cuenta con una capa interna de PowerSlim', 'Detalles de la prenda\r\n- Brasier triangular con alto cubrimiento en sisa y espalda\r\n- Copas de alto cubrimiento, con arco interno, para un realce suave\r\n- PowerSlim® en la base y la sisa, para controlar los gorditos\r\n- Espalda ancha con doble capa de tela, que elimina los rollitos más molestos\r\n- Suaves varillas laterales que centran el busto\r\n- Cargaderas graduables con broches delanteros, para uso cruzado\r\n- Abrochadura de tres gachos y cuatro niveles de ajuste', 584.64, 'si'),
(208, 'Fierce Almost-Plunge Sheer Lace Wireless Bralette', '11971', 'mujer', 'leonisa', 'Enamórate de la delicadeza de este lindo bralette, totalmente cómodo y suave. No tiene, arco,y sus copas están elaboradas en encaje, para que puedas disfrutar de una modelación totalmente natural. Cuenta con una banda elástica bajo el busto, que te da mayor soporte. No tiene abrochadura y por eso, se ajusta perfectamente a tu contorno.', 'Bralette triangular en tul y encaje.\r\nElástico que rodea toda la base, para mayor ajuste y soporte.\r\nDoble tela en las copas para un tacto muy suave.\r\nCargaderas anchas y fijas.\r\nComposición de la tela: poliamida 80.00%, elastano 20.00%, Composición Forro: poliamida 93.00%, elastano 7.00%.', 334.08, 'si'),
(209, 'BRASIER BRASTOP CON BUEN CUBRIMIENTO DE SISA ', '11974', 'mujer', 'leonisa', 'Este es un brasier ideal para mujeres de todas las edades con busto regular y grande que buscan sentirse cómodas y seguras. ', 'Es la combinación de dos siluetas, brindando el soporte y la modelación de un brasier con el cubrimiento de un top. Además ayuda a disimular un poco el volumen del busto para aquellas que prefieren que este no se vea tan grande.Sus copas están elaboradas en espuma ultrasuave y muy ligera que se adapta perfectamente al busto dejando que luzcas espectacular. El refuerzo en PowerSlim que tiene tanto en la sisa como en la espalda ayuda a disimular esos molestos rollitos que se forman en esa zona, ¡haciendo que la figura que se vea mucho más estilizada! Al tener cargaderas anchas ayuda a sostener el busto, además cuenta con una abrochadura de 3 posiciones y 4 niveles de ajuste, además tiene muy buena capacidad de elongación, lo que permite que se adapte a contornos mucho más anchos. Ven por el tuyo y descubre el bra que tanto te hacía falta.\r\nLa combinación perfecta entre el soporte de un brasier y el cubrimiento de un top.\r\nAyuda a disimular el volumen para quienes prefieren que no se vea tan grande.\r\nCopas elaboradas en espuma ultrasuave y ligera.\r\nRefuerzo en sisa y espalda que ayuda a disimular los rollitos estilizando la figura.\r\nAbrochadura con 3 posiciones y 4 niveles de ajuste.\r\nBrasier triangular con alto cubrimiento de sisa y espalda.\r\nArco interno brinda mejor modelación.\r\nSuaves varillas laterales que garantizan ajuste.\r\nComposición: poliamida 86.00%, elastano 14.00%, \r\nComposición Forro: poliamida 88.00%, elastano 12.00%.', 556.8, 'si'),
(210, 'PANTY HIPSTER CON LATERAL ALTO DE ENCAJE', '12928', 'mujer', 'leonisa', '\r\nPanty hipster de encaje con laterales anchos que brindan mayor cubrimiento y comodidad. Su diseño sin elásticos ofrece efecto invisible y un acabado delicado con transparencias sutiles.', 'Panty Hipster en Encaje con Laterales Anchos\r\n• Composición: 86% poliamida – 14% elastano\r\n• Silueta semidescaderada con ajuste cómodo y adaptable\r\n• Diseño sin elásticos en cintura y piernas para evitar marcas\r\n• Laterales anchos en encaje que brindan mayor cubrimiento y soporte\r\n• Encaje suave con transparencias que aporta un toque femenino\r\n• Tela ligera y elástica que se adapta al cuerpo con libertad de movimiento\r\n• Sensación de comodidad y frescura para uso diario\r\n• Refuerzo en algodón para mayor higiene y confort', 111.36, 'si'),
(211, 'BRASIER DOBLE LOOK DE REALCE ALTO PARA UN ESCOTE INCREIBLE', '11976L', 'mujer', 'leonisa', '¡Con este bra, tu escote será irresistible! Enamórate del realce alto que puedes conseguir, gracias a las copas en espuma, el arco y los refuerzos laterales que tiene este bra; además, es una prenda 2 en 1, ya que cuenta con unos elásticos en el centro del escote que puedes usar de dos maneras: enganchándolos cada uno en su copa para que queden sobre tu busto, o abrochándolos en la copa contraria, para crear un escote cruzado que se va a convertir en el centro de todas las miradas.', '¡No esperes más, ven y descubre un escote irresistible!\r\nDetalles de la prenda\r\n- ¡Escote irresistible! Realce alto, gracias a sus copas de espuma con arco y refuerzo lateral\r\n- Doble look: gracias a elásticos decorativos que crean escotes únicos\r\n- Engancha cada elástico en su copa para que queden sobre tu busto, o abróchalos en la copa contraria, para crear un escote cruzado\r\n- ¡Úsalo como quieras! Cargaderas que puedes usar en modo convencional o cruzadas\r\n- Ajuste perfecto: abrochadura en espalda de dos ganchos y cuatro niveles de ajuste\r\n- Composición: poliamida 82%, elastano 18%', 417.6, 'si'),
(212, 'Top sin costuras doble faz con soporte alto de busto', '195337P', 'mujer', 'leonisa', 'Este top doble faz es seamless o sin costuras, lo que te da una sensación de comodidad e invisibilidad, pues no cuenta con costuras que tallen o se marquen en tu ropa exterior. Además, es muy versátil ya que cuentas con 2 opciones de color, en 1 sola prenda. Se ajusta perfectamente a tu cuerpo y cuenta con un tejido prehormado alrededor del busto que le dará más soporte. Su tejido en malla es transpirable y de secado rápido y permite el paso del aire, haciendo que te sientas fresca y seca en todo momento. Úsalo para trotar, bailar, montar en bicicleta, caminar, ir al gimnasio, hacer yoga, o simplemente cuando quieras sentirte cómoda en el día a día, ideal para todo momento.\r\n', 'Top doble faz: 2 opciones con 2 colores en 1 sola prenda.\r\nTecnología seamless sin costuras.\r\nAlto soporte de busto con tejido prehormado alrededor para más soporte.\r\nSecado rápido, fresca y seca en todo momento.\r\nÚsalo como deportivo, para el día a día o para dormir.\r\nComposición: 62% poliamida, 34% poliéster/poliamida, 4% elastano\r\n', 257.52, 'si'),
(213, 'PANTY CACHETERO ESTILO DESCADERADO EN ENCAJE', '12936', 'mujer', 'leonisa', 'Panty cachetero en encaje de alta tecnología que combina suavidad y ajuste perfecto. Su diseño sin elásticos brinda efecto invisible, mientras estiliza la figura con un toque moderno y delicado.', 'Panty Cachetero en Encaje Tecnológico con Detalle Bordado\r\n• Composición: 90% poliamida – 10% elastano\r\n• Silueta descaderada con ajuste cómodo y adaptable al cuerpo\r\n• Encaje en cintura y piernas que reemplaza los elásticos para evitar marcas\r\n• Tela de encaje suave, ligera y elástica que aporta frescura\r\n• Aplique bordado lateral que añade un toque moderno y sofisticado\r\n• Diseño que estiliza la figura con acabado delicado\r\n• Sensación de comodidad y ligereza para uso diario\r\n• Refuerzo inferior en algodón para mayor higiene y frescura', 118.32, 'si'),
(214, 'BRASIER TRIANGULAR DE REALCE SUAVE CON ESCOTE PROFUNDO', '11977', 'mujer', 'leonisa', '¡Muestra tus curvas al natural! Este brasier triangular es todo lo que necesitas, ya que tiene un realce suave que no aumenta el tamaño de tu busto y te permite lucir tan natural como te gusta. Lo mejor de todo es que tiene un escote profundo y muy seductor, para que puedas usarlo con prendas muy escotadas y aún así lucir perfecta. Bajo el busto, tiene unas franjas en transparencias que le dan un toque absolutamente irresistible y un elástico ancho en la base, te ayuda a soportar tu busto cómodamente. ¡Enamórate de una silueta 100% natural!\r\n', '¡Sexy y natural! Con este brasier triangular de escote profundo.\r\n¡Realce suave! Ideal para mujeres de busto pequeño y regular.\r\nSiéntete muy seductora: franjas en transparencias bajo el busto.\r\nSoporte perfecto: elástico ancho en la base.\r\nSiempre cómoda: cargaderas suaves y elásticas para uso convencional o cruzado.\r\nAjuste perfecto: espalda con tres broches y cuatro niveles de ajuste.\r\nComposición de la tela: poliamida 83.40%, elastano 16.10%, poliéster .50%, Composición Forro: poliamida 84.30%, elastano 15.70%.\r\n', 334.08, 'si'),
(215, 'Panty clásico efecto invisible de control fuerte en abdomen', '12949', 'mujer', 'leonisa', 'Experimenta la comodidad extrema con este panty clásico invisible de tiro alto y de control fuerte en abdomen medio y bajo. Está elaborado en DuraFit, un material de tacto frío que comprime con total confort y suavidad.\r\n', '- Panty clásico invisible elaborado en DuraFit, una tela de tacto frío, resistente y liviana, ultrasuave al tacto.\r\n- Control fuerte en abdomen medio y bajo.\r\n- Vas a amar este producto porque tus glúteos se verán más redondeados y porque estiliza tu abdomen y es muy suave al\r\ntacto.\r\n- Tienes que tenerlo porque siempre es una opción para el día a día, y porque es el complemento perfecto de los\r\npantalones de tiro alto o pantalones ajustados.\r\n- Es muy cómodo porque no se siente cuando lo llevas puesto.\r\n- Alta tecnología, sin elásticos ni costuras en piernas: efecto invisible. No se marca en la ropa ni talla la piel.\r\n- Refuerzo 100% en algodón.\r\n', 208.8, 'si'),
(216, 'Panty clásico tiro alto de control fuerte de abdomen', '92045', 'mujer', 'leonisa', 'Panty de tiro alto con control fuerte y fajón ultraplano que estiliza la cintura. Su efecto invisible y diseño sin marcas lo hacen ideal para el día a día. Realza los glúteos con un ajuste cómodo y favorecedor.', 'Panty Tiro Alto con Control Fuerte y Modelación de Glúteos\r\n• Composición: (no especificada) / refuerzo 100% algodón\r\n• Tiro alto con cobertura completa y ajuste firme en la cintura\r\n• Fajón ultraplano termofusionado que brinda control fuerte en abdomen medio y bajo\r\n• Diseño sin costuras ni elásticos visibles para efecto invisible total\r\n• Efecto invisible en piernas y glúteos que no se marca en la ropa\r\n• Elástico recogido en glúteos que aporta una modelación más redondeada\r\n• Refuerzo interno en algodón que brinda frescura, suavidad e higiene\r\n• Sensación cómoda, ligera y de soporte para uso diario\r\n• Producción responsable bajo prácticas laborales justas', 271.44, 'si'),
(217, 'BRASILERA TIPO CACHETERO CON ELÁSTICOS DECORATIVOS', '12937E', 'mujer', 'ellipse', 'Panty culotte con tulle, con fajón en encaje y elásticos decorativos en cintura.', 'Panty culotte con tulle doble en delantero y posterior con fajón en encaje y elásticos decorativos en cintura en color verde, rosado y crudo.', 250.56, 'si'),
(218, 'Panty cachetero en encaje y tul increíblemente sexy', '92057', 'mujer', 'leonisa', '\r\nPanty brasilera de tiro bajo con encaje floral y tul, suave y seductor. Se adapta cómodamente al cuerpo con laterales anchos que estilizan la figura. Ideal para quienes buscan sensualidad sin renunciar al confort.', 'Panty Brasilera de Encaje y Tul Tiro Bajo\r\n• Composición: 85% poliamida – 15% elastano / refuerzo 100% algodón\r\n• Ajuste cómodo con laterales anchos que brindan mayor equilibrio visual\r\n• Encaje floral en glúteos que realza la silueta con un efecto sensual\r\n• Combinación de tul y encaje que aporta ligereza y transpirabilidad\r\n• Detalle de ojal que añade un toque atractivo y femenino\r\n• Refuerzo inferior en algodón que garantiza frescura e higiene\r\n• Sensación suave y ligera para uso prolongado\r\n• Producción responsable bajo prácticas laborales justas', 222.72, 'si'),
(219, 'Bra Doble Realce Perfecto', '11985', 'mujer', 'leonisa', 'Este brasier de doble realce te encantará, ya que está pensado para mujeres de busto pequeño y mediano que buscan darle un efecto más redondeado y con mayor volumen al escote. Sus copas tienen arcos y dos pads de espuma incorporados, uno en la parte lateral e inferior de la copa que centran, levantan y realzan. ', 'Además su escote profundo solo cubre la mitad de tu busto ¡perfecto si te gustan las camisas o blusas escotadas! Tanto la base como la espalda están elaboradas en encaje lo que le dará un toque muy sexy, además, la base cuenta con excelente elongación, lo que permite que se adapte a los contornos más anchos. Sus cargaderas graduables son fijas en el frente y removibles en espalda para que las uses de forma convencional o cruzadas, y la espalda cuenta con una abrochadura de 2 posiciones y 4 niveles de ajuste.\r\n- Brasier de doble realce de escote profundo.\r\n- Ideal para mujeres con busto pequeño y mediano.\r\n- Copas con arco y dos pads de espuma incorporados que centran, levantan y realzan el busto.\r\n- Elástico ancho en su interior que hace que su espalda sea de una excelente elongación.\r\n- Una prenda perfecta para darte seguridad y ese toque sexy que estabas buscando.\r\n- Cargaderas graduables y multiusos (uso cruzado o convencional).\r\n- Abrochadura con 2 posiciones y 4 niveles de ajuste.\r\n- Composición: 87% poliamida, 13% elastano. Composición forro: 100% poliamida.\r\n', 431.52, 'si'),
(220, 'Brasier tipo bustier support strapless', '11986', 'mujer', 'leonisa', 'Este es el brasier ideal para lucir tu mejor escote con toda la seguridad de un buen soporte.\r\nSus copas prehormadas cuentan con una tela en el lateral que ayudan a centrar tu busto de la manera que lo deseas.', 'Copas prehormadas.\r\nCopas con gran cubrimiento, capacidad y profundidad.\r\nBase ancha elaborada en PowerSlim que estiliza la silueta y mantiene el bra siempre en su lugar.\r\nCargaderas removible que te permiten usarlo como quieras, strapless, convencional o cruzado.\r\nParte externa de la espalda elaborada en encaje.\r\n', 598.56, 'si'),
(221, 'Bralette con costuras internas que simulan arcos', '91090', 'mujer', 'leonisa', ' Copas doble tela: encaje externo tela lisa interna que funciona como bolsillo para copas (no incluido).\r\n- Costuras internas que simulan arcos.\r\n- Elástico en suave en base para más soporte.\r\n- Cargaderas no removibles. Graduables para que las ajustes a tu medida.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n', 'Bralette elaborado en encaje cómodo y suave con tu piel. Es muy liviano ya que no cuenta con arcos ni varillas. Las copas tienen una capa interna en tela lisa, la cual también es un bolsillo para que puedas ponerle copas en espuma (no incluidas). En la parte interna de la base cuenta con un elástico suave y unas costuras que simulan arcos, los cuales le dan más soporte al busto. Sus cargaderas no son removibles, pero puedes graduarlas para ajustarlas a tu medida, y además en la base tiene un detalle de cargaderas dobles que es ¡wow!\r\n', 424.56, 'si'),
(222, 'Panty faja de tiro alto con control en abdomen y cintura', '12940', 'mujer', 'leonisa', 'Por qué te encantará\r\n\r\nPanty faja de control fuerte en abdomen alto, medio y bajo.\r\n¡Una figura estilizada en segundos! Moldea tu silueta desde la base del busto hasta la mitad de las piernas.\r\nEnamórate de tus curvas: cortes efecto reloj de arena.\r\nDisimula la celulitis. ¡Úsalo como quieras! Bajo tus jeans, vestidos o pantalones.\r\nElástico antideslizante en la base del busto que facilita que la prenda permanezca en su lugar.\r\nImperceptible bajo la ropa: ya que no tiene costuras en las piernas y por eso, no se marca.\r\nOjales en la base del busto para que abroches las cargaderas de tu brasier.', 'Este increíble panty faja de tiro alto, moldea tu figura desde la base del busto hasta la mitad de las piernas. Elaborado en una tela lisa suave al tacto una capa interna de PowerSlim que ejerce control fuerte en abdomen, cintura y además sus cortes efecto reloj de arena definen aún más tus curvas. En la base del busto cuenta con un elástico antideslizante interno para que la prenda se mantenga en su lugar y con ojales para que abroches las cargaderas de tu brasier. Es perfecto para disimular la celulitis y es de apariencia invisible en las piernas al no tener costuras. También moldeará tus glúteos de forma natural para que luzcan redondeados gracias al elástico recogido en el centro. Es ideal para complementar tu look bajo tus vestidos, jeans o pantalones, ¡qué esperas para ver cambios en tu figura en pocos segundos!', 431.52, 'si'),
(223, 'TOP CON ESPALDA DEPORTIVA EN ENCAJE', '15784', 'mujer', 'leonisa', 'Este top tiene un diseño femenino y confortable, la espalda es deportiva lo que te da mayor libertad de movimiento y está elaborado en encaje SmartLace? que contrasta perfectamente con el color del top y además resalta ese lado delicado que tanto te gusta. Tiene una abertura en la espalda que permite el paso del aire cuando lo usas para hacer ejercicio. Las copas están elaboradas con doble tela de DuraFit?, un material suave, fresco y resistente que te da máximo soporte y un ajuste perfecto al cuerpo.', '-Top sin arco con diseño deportivo y espalda en encaje SmartLace?\r\n-Doble tela de DuraFit? en las copas, un material fresco y cómodo que te da excelente ajuste\r\n-Espalda atlética, deja los hombros más libres para que te muevas con mayor seguridad\r\n-Abertura en la espalda que permite el paso del aire y te mantiene fresca cuando haces ejercicio\r\n-Elástico ancho en la base del busto elaborado con fibras de alta tecnología que dan mayor sostenimiento\r\n-Cargaderas anchas y suaves con toques de encaje\r\n-Composición: poliamida 87.00%, elastano 13.00%, Composición Forro: poliamida 78.00%, elastano 22.00%.', 201.84, 'si'),
(224, 'Bralette de cuello alto tipo crop top sin estructura', '15807', 'mujer', 'leonisa', 'bralette romántico, femenino y muy sexy. Sin arcos, abrochaduras, ni estructuras para máxima comodidad y darte toda la libertad que buscas, es muy cómodo y versátil .\r\n', '- Bralette sin estructuras o abrochaduras. Cómodo, ligero y versátil.\r\n- Elaborado en encaje y tul te harán lucir sexy, a la moda y encantadora todo el tiempo.\r\n- Elástico en base para mayor soporte\r\n- Silueta con cuello alto y manga sisa, un diseño único.\r\n- Modelación natural.\r\n- Ideal para mujeres de busto pequeño, regular y grande.\r\n- Puede usarse también como prenda exterior con un kimono o chaqueta.\r\n- Las copas cuentan con transparencias que permiten ver el pezón.\r\n- Composición: 86% poliamida, 14% elastano, composición forro: 93% poliamida, 7% elastano.', 348, 'si'),
(225, 'Panty faja de control efecto levanta cola', '18526', 'mujer', 'leonisa', ' Panty faja de control fuerte en el abdomen medio y bajo. Control moderado en el abdomen alto.\r\n- Elaborada con nuestro material de compresión DuraFit, un material suave y de tacto frío, que te brinda comodidad\r\nmientras estiliza tu figura.\r\n- Moldea tu cuerpo desde la base del busto hasta la parte alta de las piernas. Imperceptible bajo la ropa: ya que no\r\ntiene costuras en las piernas y por eso, no se marca.\r\n- Elástico antideslizante en la base del busto que facilita que la prenda permanezca en su lugar.', 'Panty faja de control con doble capa de tela en abdomen para verte más estilizada ¡si quieres moldear con comodidad tu cuerpo encontraste lo que necesitas! Está elaborado en DuraFit, uno de nuestros materiales de compresión: es muy suave, de tacto frío y estiliza tus curvas con total comodidad. En la base del busto cuenta con un elástico antideslizante interno para que la prenda se mantenga en su lugar, y también con dos 2 ojales en el frente y 2 ojales en espalda, para que abroches las cargaderas (incluidas) a la distancia que tú elijas. Es perfecto para disimular la celulitis y es de apariencia invisible en las piernas al no tener costuras. También realzará tus glúteos ya que los cortes en la parte inferior los levantan y el elástico recogido en el centro, hace que tengan una modelación más redondeada. Es ideal para complementar tu look bajo tus vestidos cortos o largos, con jeans o con pantalones de silueta amplia y tela delgada.\r\n', 445.44, 'si'),
(226, 'SEXY BODY HIPSTER EN TUL Y ENCAJE', '18495', 'mujer', 'leonisa', 'Este body es el más grande elemento de seducción, ya que está elaborado totalmente en una mezcla de tul y encaje. Sus copas triangulares están elaboradas con una suave y delgada espuma que, acompañada de su arco interno, generan un realce muy natural. Solo pruébatelo, te vas a enamorar de él.', '-Body en tul y encaje con copas triangulares y panty hipster\r\n-Copas de espuma suave y delgada con arco interno, logran un realce natural\r\n-Espalda y centro del abdomen, elaborados en tul\r\n-Copas, cargaderas, laterales y trasero del panty, elaborados en encaje\r\n-Franja de encaje que rodea la parte alta de la espalda\r\n-Cargaderas fijas y graduables con encaje en la parte trasera\r\n-Abrochadura inferior de tres ganchos y tres ajustes\r\n-Refuerzo de algodón que evita que los ganchos entren en contacto con tu piel', 522, 'si'),
(227, 'FAJA BODY ESTILO BRASILERA', '12730M', 'mujer', 'leonisa', 'Esta faja controla tu abdomen y está diseñada para las mujeres que buscan moldear su cuerpo sin tener que renunciar a la comodidad y a la moda. Está elaborada con tecnología SkinFuse: con menos cortes y costuras, con materiales ultrasuaves, livianos y frescos que hacen que te sientas muy cómoda. Además, no se marca debajo de la ropa y la puedes usar con tu brasier favorito.\r\n', 'Faja body busto libre estilo brasilero.\r\nControl suave en abdomen alto, medio y bajo.\r\nMaterial ultrasuave con tecnología SkinFuse®: menos cortes y costuras.\r\nÚsala después del embarazo, para darle firmeza a la piel y recuperar tu figura.\r\nCargaderas graduables y removibles.\r\nAbrochadura inferior para mayor comodidad.\r\nComposición: poliamida 79.00%, elastano 21.00%.\r\n', 208.8, 'si'),
(228, 'Brasier strapless con realce incorporado', '61308', 'mujer', 'leonisa', 'Por qué te encantará\r\n\r\n- Brasier strapless con arco de realce medio.\r\n- Ideal para mujeres de busto pequeño o mediano.\r\n- Copas con espuma incorporada que realzan tu busto y le dan una forma más redondeada.\r\n- Copas lisas que no se marcan a través de la ropa.\r\n- Elásticos antideslizantes en la espalda que mantienen el brasier en su lugar.', 'Con este brasier push up strapless con arco puedes sentirte cómoda y segura ya que no se cae: sus elásticos antideslizantes en la espalda se adhieren a tu piel haciendo que no se deslice. Las copas cuentan con realce incorporado para darle mayor realce a tu escote, y es ideal para un busto pequeño o mediano. Cuenta con varillas laterales que te dan mayor soporte. Su espalda es de poco cubrimiento, perfecto para ti si prefieres brasieres más ligeros y livianos. Ideal para usar con blusas o vestidos cuello bandeja, de tiritas o de un solo hombro. Combínalo con nuestros panties ultracómodos en algodón o nuestros panties invisibles.', 375.84, 'si'),
(229, 'BODY REDUCTOR LEVANTA COLA EN LÁTEX', '18433', 'mujer', 'leonisa', 'Faja body reductor de abdomen, cintura, espalda y muslos. Moldea tu cuerpo y le da una forma estilizada resaltando tus atributos y controlando las áreas que más te preocupan. Este body te ofrece el nivel de control que tanto buscabas y te hará sentir segura y cómoda durante todo el día.\r\n', '-Body busto libre de reducción, que te permite el uso de tu brasier preferido\r\n-Ideal para reducir medidas\r\n-Poder triple capa: tela elástica lisa DuraFit? látex algodón\r\n-Reduce y controla abdomen, contorno de cintura y muslos; control de espalda y corrector de postura\r\n-Cierre delantero con tres broches internos que no entran en contacto con tu piel\r\n-Cargaderas graduables y removibles que puedes reemplazar por las de tu bra\r\n-Cortes y costuras especiales que levantan la cola naturalmente y abertura inferior para mayor comodidad\r\n-Composición: látex 48.00%, poliamida 39.00%, elastano 13.00%, Composición Forro: ALGODÓN 90.00%, elastano 10.00%.\r\n', 835.2, 'si'),
(230, 'MI PRIMER BRASIER - TOP BÁSICO EN ALGODÓN', '61311', 'ninos', 'leonisa', 'Brasier principiante, para las más pequeñas que quieren tener su primera experiencia con el brasier. Diseño con copas triangulares elaboradas en algodón elástico y con suave espuma interna para evitar las transparencias y las marcas a través de la ropa, también tiene costuras que simulan los arcos. La espalda es delgada y tiene broche sencillo con tres opciones de ajuste. Este es una bra delicado que brinda toda la comodidad y suavidad.', '\"Brasier básico principiante\r\nElaborado en algodón elástico que da mayor comodidad y suavidad\r\nCopas triangulares con suave espuma interna\r\nElásticos planos con excelente ajuste\r\nCosturas que simulan los arcos\r\nCargaderas delgadas graduables para uso convencional o cruzado\r\nEspalda delgada con broche sencillo y tres opciones de ajuste\r\nPrenda ideal para uso diario\"', 194.88, 'si'),
(231, 'TOP PRINCIPIANTE CON ESPALDA DEPORTIVA', '65290', 'ninos', 'leonisa', 'Top con espalda cruzada estilo deportivo. Diseño con copas triangulares elaboradas en algodón elástico y con doble tela para evitar las transparencias. Los elásticos son delgados y planos, son suaves con la piel y no se marcan. Este top brinda toda la comodidad y suavidad.', '\"Top básico con copas con diseño triangular\r\nElaborado en algodón elástico para dar mayor comodidad y suavidad\r\nCopas triangulares con doble tela para evitar transparencias\r\nElásticos planos con excelente ajuste\r\nCargaderas delgadas\r\nEspalda deportiva con buen cubrimiento\r\nPrenda ideal para uso diario\"', 111.36, 'si'),
(232, 'TOP BÁSICO EN ALGODÓN', '65292', 'ninos', 'leonisa', 'Top con muy buen cubrimiento, elaborado en algodón elástico que da mayor comodidad y es más suave con la piel. Los elásticos son delgados, planos y no se marcan. Las cargaderas son delgadas y se pueden usar de forma convencional o cruzadas.', '\"Top básico con buen cubrimiento\r\nElaborado en algodón elástico para mayor comodidad y suavidad\r\nElásticos planos con excelente ajuste\r\nCargaderas delgadas graduables, uso convencional o cruzado\r\nEspalda más ancha\r\nPrenda ideal para uso diario\"', 111.36, 'si'),
(233, 'BODY HIPSTER EN DURAFIT ULTRALIVIANO', '18484', 'mujer', 'leonisa', 'Este body hipster te ayuda a enmarcar el busto y la cola. Está hecho con nuestra mejor tecnología DuraFit®, que es 20% más liviana que el PowerSlim® y funciona igual de bien. Con esto nos aseguramos de darte el control que necesita tu cuerpo, pero la libertad y la suavidad que necesita tu piel. Es perfecto para usar con vestidos, faldas cortas o shorts. ¡Pruébatelo!\r\n', 'Este body hipster te ayuda a enmarcar el busto y la cola. Está hecho con nuestra mejor tecnología DuraFit®, que es 20% más liviana que el PowerSlim® y funciona igual de bien. Con esto nos aseguramos de darte el control que necesita tu cuerpo, pero la libertad y la suavidad que necesita tu piel. Es perfecto para usar con vestidos, faldas cortas o shorts. ¡Pruébatelo!\r\n', 417.6, 'si'),
(234, 'PAQUETE X 2 TOP BÁSICO EN ALGODÓN', '65292X2', 'ninos', 'leonisa', 'Paquete por 2 Top con muy buen cubrimiento, elaborado en algodón elástico que da mayor comodidad y es más suave con la piel. Los elásticos son delgados, planos y no se marcan. Las cargaderas son delgadas y se pueden usar de forma convencional o cruzadas.', '\"Pack 2 Top básico con buen cubrimiento\r\nElaborado en algodón elástico para mayor comodidad y suavidad\r\nElásticos planos con excelente ajuste\r\nCargaderas delgadas graduables, uso convencional o cruzado\r\nEspalda más ancha\r\nPrenda ideal para uso diario\"', 167.04, 'si'),
(235, 'BODY BUSTO LIBRE ANTIDESLIZANTE DE CONTROL FUERTE', '18491', 'mujer', 'leonisa', 'Este body busto libre, te permite usar el bra que prefieras. Está elaborado en PowerSlim®: un material de alta resistencia y durabilidad y en DuraFit®: un material muy suave al tacto. Su abrochadura cuenta con una capa de algodón que evita que los ganchos entren en contacto con tu piel y tiene tres niveles de ajuste, lo que te permite ver claramente cómo moldeas tus curvas mientras lo usas. Para abrochar tu body, es necesario hacerlo de manera escalonada, es decir: empezando de abajo hacia arriba, abrocha el primer gancho en la posición más ajustada, el segundo en el medio y desde ese punto en adelante, abrocha en el gancho de mayor amplitud.\r\n', '-Body busto libre con bóxer corto elaborado en PowerSlim® y DuraFit®\r\n-Costuras que moldean los glúteos y elásticos antideslizantes en la pierna\r\n-Alto cubrimiento en sisa que minimiza los molestos gorditos\r\n-Elaborado en PowerSlim®: material de alta resistencia y durabilidad y en DuraFit®: material muy suave al contacto con la piel\r\n-Espalda alta con tres cortes ergonómicos para mejorar la modelación\r\n-Cargaderas termofusionadas: más suaves, graduables y removibles\r\n-Abrochadura frontal con tres niveles de ajuste y con una capa de algodón que evita que los ganchos entren en contacto con tu piel\r\n-Abertura inferior para mayor comodidad\r\n-Composición: poliamida 81.00%, elastano 17.00%, silicona 2.00%, Composición Forro: poliamida 81.00%, elastano 19.00%.\r\n', 730.8, 'si'),
(236, 'TOP EN ALGODÓN CON ESPALDA DEPORTIVA', '65297', 'ninos', 'leonisa', 'Top con muy buen cubrimiento, elaborado en algodón elástico que da mayor comodidad y es más suave con la piel. Tiene doble tela en la parte delantera y un elástico ancho en la base para brindar mejor soporte y ajuste. La espalda es atlética para dar un look deportivo y brindar mayor comodidad.', '\"Top básico con buen cubrimiento\r\nElaborado en algodón elástico para mayor comodidad y suavidad\r\nCargaderas anchas y espalda deportiva\r\nElástico en la base\r\nPrenda ideal para uso diario\"', 125.28, 'no'),
(237, 'Panty hispster de tiro bajo', '12944', 'mujer', 'leonisa', 'Panty de alta cobertura en DuraFit® con encaje en cintura que combina suavidad y frescura. Su diseño sin costuras brinda efecto invisible y ajuste perfecto para máxima comodidad.', 'Panty de Cobertura Total en DuraFit® con Encaje\r\n• Composición: 62% poliamida – 38% elastano\r\n• Alto cubrimiento en glúteos que brinda mayor seguridad y confort\r\n• Diseño sin costuras ni elásticos que evita marcas en la piel\r\n• Tela DuraFit® fresca, ligera y de gran suavidad al tacto\r\n• Tecnología inteligente que evita que la prenda se enrolle\r\n• Encaje en cintura que aporta un toque delicado y femenino\r\n• Sensación de comodidad extrema y ajuste perfecto al cuerpo\r\n• Refuerzo en algodón para mayor frescura e higiene', 111.36, 'si'),
(238, 'BRASIER CON ARCO Y COPAS CON GRAN CUBRIMIENTO', '71222', 'mujer', 'leonisa', 'Brasier con arco, con copas triangulares que dan total cubrimiento al busto manteniendo siempre la modelación perfecta. La base de las copas es más ancha y se ajusta muy bien al contorno dando mayor soporte y firmeza al busto. La espalda es más ancha y ajustada, controla con comodidad esa zona de tu cuerpo. Las cargaderas son anchas, cómodas y están fijas en la parte delantera; además cuentan con accesorios metálicos que le agregan un toque diferente a la prenda, dando mayor suavidad y frescura.', 'Brasier triangular con arco.\r\nCopas con total cubrimiento ideales para mujeres con busto más grande.\r\nAjuste perfecto, excelente soporte y modelación perfecta.\r\nElástico ancho en la base de las copas y espalda que da máximo soporte.\r\nEspalda ancha con gran cubrimiento y excelente ajuste, controla con comodidad esta zona del cuerpo.\r\nCargaderas anchas fijas, las puedes ajustar a tu medida y dan máximo sostenimiento del busto.\r\nAccesorios metálicos en las cargaderas.\r\nBroches triples con tres opciones de ajuste al contorno.\r\nComposición de la tela: 77.40% Poliamida, 14.90% Elastano, 7.70% Algodón.', 348, 'si'),
(239, 'BRASIER SIN ARCO DE MAYOR CUBRIMIENTO Y SOPORTE', '71223', 'mujer', 'leonisa', 'Es un brasier que ofrece un look femenino y un busto moldeado. Tiene copas triangulares completas que cubren el busto, lo controlan y te dan una modelación impecable. Este brasier tiene cortes y costuras especiales que reemplazan las varillas ofreciéndote excelente soporte y la comodidad que tanto te gusta. Las copas están forradas al interior con doble tela y en la parte exterior vienen con encajes delicados, la espalda está elaborada en tela lisa brindándote un contacto más suave con tu piel. ', 'Brasier triangular de copas completas.\r\nCortes y costuras especiales que reemplazan los arcos.\r\nCopas forradas al interior para ofrecerte control suave del busto y una modelación perfecta.\r\nEncaje delicado en las copas.\r\nTela elástica lisa en la espalda suave con tu piel.\r\nLa combinación perfecta de delicado y femenino encaje.\r\nCargaderas anchas y suaves que te dan mayor comodidad y sostenimiento.\r\nComposición de la tela: 90.2% Poliamida, 9.8% Elastano.', 334.08, 'si'),
(240, 'Paquete x 2 panties cacheteros descaderados con encaje', '12946X2', 'mujer', 'leonisa', 'Paquete x 2 cacheteros con encaje en la parte trasera. Esta silueta es la preferida de muchas, y con la combinaci', 'Paquete x 2 cacheteros con encaje en la parte trasera. Esta silueta es la preferida de muchas, y con la combinación', 257.52, 'si'),
(241, 'BRASIER SIN ARCO DE CONTROL SUAVE CON COPAS COMPLETAS EN ENCAJE', '71239', 'mujer', 'leonisa', 'Brasier sin arco, con copas completas que cubren totalmente el busto garantizando una excelente modelación, en encaje floral para darte una apariencia sofisticada, al interior están cubiertas con tul para evitar transparencias. Las cargaderas son más anchas para darle máximo soporte al busto con mayor comodidad. Espalda en PowerSlim® que brinda muy buen ajuste y control suave de esta zona del cuerpo, también tiene cortes laterales que dan mayor cubrimiento, ayudan a recoger y a centrar el busto.', 'Brasier sin arco de máximo cubrimiento.\r\nCopas completas en encaje floral para una apariencia sofisticada.\r\nCortes laterales que ayudan a recoger y a centrar el busto.\r\nExcelente modelación y sostenimiento del busto.\r\nEspalda en PowerSlim®, tendrás un ajuste perfecto y control suave en esta zona.\r\nCargaderas anchas ajustables, integradas a la espalda, te dan máximo soporte con gran comodidad.\r\nBroches dobles en la espalda con 3 opciones de ajuste.', 292.32, 'si'),
(242, 'BODY BUSTO LIBRE REDUCTOR DE MEDIDAS', '18492', 'mujer', 'leonisa', 'Este body, además de ser suave al tacto, ligero e innovador, es mucho más de lo que esperabas; ya que cuenta con paneles internos de PowerSlim: un material reductor de alta resistencia y durabilidad, que controla abdomen alto, medio, bajo, cintura y espalda. Úsalo con tu brasier favorito y no te preocupes por los incómodos gorditos, ya que el alto cubrimiento en sisa y espalda, se encargan de moldear tu figura de la mejor manera. Además, cuenta con almohadillas removibles en los glúteos, que te ayudan a aumentar su volumen.\r\n', 'Body busto libre con cierre lateral\r\n-Control fuerte en abdomen, cintura y espalda\r\n-Paneles de PowerSlim: material de alta resistencia y durabilidad y una capa externa de DuraFit, material suave y delicado\r\n-Costura que moldea los glúteos y almohadillas removibles que aumentan su tamaño\r\n-Cierre lateral con broches internos y capa de algodón que evita que entre en contacto con la piel\r\n-Sin elásticos en pierna para que no se marque y abertura inferior para mayor comodidad\r\n-Cargaderas termofusionadas, más suaves y removibles\r\n-Composición: poliamida 66.00%, elastano 34.00%, Composición Forro: poliamida 83.00%, elastano 17.00%.', 591.6, 'si'),
(243, 'Panty Faja Brasilera de Control Moderado', '12952', 'mujer', 'leonisa', 'Brasilera de control fuerte en DuraFit®, de tiro alto y laterales anchos que estilizan la figura. Invisible bajo la ropa, suave y cómoda al tacto. Ideal para moldear con firmeza sin sacrificar confort.', 'Panty Brasilera de Control Fuerte DuraFit® Tiro Alto\r\n• Composición: (no especificada) DuraFit® / refuerzo 100% algodón\r\n• Control fuerte en abdomen medio, bajo y laterales de la cintura\r\n• Tecnología DuraFit® que moldea la figura con suavidad y confort\r\n• Doble capa en abdomen para mayor compresión sin incomodidad\r\n• Diseño sin elásticos en piernas ni glúteos para efecto invisible\r\n• No se marca ni corta la silueta bajo la ropa\r\n• Refuerzo inferior en algodón que aporta frescura e higiene\r\n• Sensación firme, suave y de soporte ideal para uso diario\r\n• Mayor cubrimiento gracias a su diseño de tiro alto y laterales anchos', 174, 'si'),
(244, 'BODY BUSTO LIBRE DE CONTROL MODERADO', '18493', 'mujer', 'leonisa', 'Este body está diseñado para generar un control moderado en zonas específicas de tu cuerpo como: el abdomen y la cintura. Tiene unas costuras especiales que ayudan a darle una forma estilizada a tu figura especialmente en la parte de los glúteos, ya que no los aplana. Además, está elaborado en DuraFit®: un material que ejerce el mismo control que el PowerSlim® y se adapta a tu cuerpo como una segunda piel.\r\n', '-Body busto libre de espalda alta, elaborado en DuraFit®\r\n-Control moderado en abdomen y cintura\r\n-Cortes ergonómicos bajo los glúteos que los moldean sin aplanarlos\r\n-Cargaderas tecnológicas, graduables y removibles\r\n-Abertura inferior para mayor comodidad\r\n-Composición: poliamida 70.00%, elastano 28.00%, silicona 2.00%, Composición Forro: poliamida 57.00%, elastano 43.00%.', 522, 'si'),
(245, 'Sexy hipster en tela ultraliviana', '12960', 'mujer', 'leonisa', ' Panty hipster invisible de tela ultraliviana que brinda frescura y ajuste perfecto. Sus laterales anchos ofrecen mayor cubrimiento, mientras el encaje en cintura aporta un toque delicado y sensual.', 'Panty Hipster Invisible Ultraliviano con Encaje\r\n• Composición: 90% poliamida – 10% elastano\r\n• Tiro medio con laterales anchos para mayor cubrimiento y soporte\r\n• Diseño invisible que no se marca bajo la ropa\r\n• Tela ultraliviana con fibras tecnológicas, suave y fresca al tacto\r\n• Encaje delicado en cintura que aporta un estilo femenino y elegante\r\n• Ajuste cómodo que se adapta al cuerpo con libertad de movimiento\r\n• Sensación ligera y fresca ideal para uso diario\r\n• Refuerzo inferior 100% en algodón para mayor higiene y confort', 160.08, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(246, 'BRASIER CON TOQUES DE ENCAJE Y TUL', '71253', 'mujer', 'leonisa', 'Brasier con arco y copas triangulares que cubren completamente el busto dándote una modelación perfecta y haciéndote sentir absolutamente cómoda. Las copas están elaboradas en tul y forradas en encaje elástico SmartLace? para evitar las transparencias, pero manteniendo el toque sofisticado del encaje. En la base de las copas y la espalda tiene un elástico ancho y suave que te da mayor sostenimiento y ajuste.', '\"Brasier con copas triangulares que cubren completamente el busto\r\nCon arco para dar excelente soporte\r\nCopas sin espuma, elaboradas con tul y forradas con el encaje elástico\r\nExcelente modelación del busto y mayor soporte\r\nEspalda en tela lisa brillante, te da buen ajuste y es suave con la piel\r\nElástico ancho y suave en la base de las copas y la espalda que da mayor sostenimiento\r\nCargaderas anchas graduables integradas a la copa\r\nSoporte máximo con absoluta comodidad\"', 313.2, 'si'),
(247, 'Brasier de realce suave con cargaderas multiusos', '71261', 'mujer', 'leonisa', 'Brasier con arco y copas vacía materiales suaves y frescos con excelente ajuste.', 'Brasier triangular con arco.\r\nCopas delgadas \r\nBroches dobles con tres opciones de ajuste al contorno.\r\nComposición de la tela: 81% Poliamida, 19% Elastano.', 334.08, 'si'),
(248, 'Panty cachetero con toques de transparencia', '12961', 'mujer', 'leonisa', 'Panty cachetero de tiro medio que brinda mayor cubrimiento y comodidad. Sus delicadas transparencias realzan la figura con un toque sutil y sensual.', 'Panty Cachetero de Transparencias Delicadas\r\n• Composición: 90% poliamida – 10% elastano\r\n• Mayor cubrimiento que aporta seguridad y comodidad en el uso diario\r\n• Ajuste suave que se adapta al cuerpo sin oprimir\r\n• Tela ligera con transparencias que permite frescura y transpirabilidad\r\n• Diseño que realza la silueta con un acabado delicado y femenino\r\n• Sensación cómoda y fresca durante todo el día\r\n• Material elástico que facilita libertad de movimiento', 97.44, 'si'),
(249, 'Panty en encaje y tul', '12964', 'mujer', 'leonisa', 'Panty cachetero en encaje y tul que combina ligereza y sensualidad. Su diseño invisible se adapta al cuerpo con suavidad, brindando comodidad y un acabado delicado.', 'Panty Cachetero en Encaje y Tul Invisible\r\n• Composición: 90% poliamida – 10% elastano\r\n• Silueta semidescaderada con ajuste cómodo y adaptable\r\n• Encaje sutil y delicado que aporta un toque femenino\r\n• Corte frontal en tul que brinda ligereza y frescura\r\n• Diseño que no se marca bajo la ropa para efecto invisible\r\n• Tela suave y ligera que se adapta al cuerpo con naturalidad\r\n• Sensación de comodidad y frescura durante todo el día\r\n• Refuerzo inferior 100% en algodón para mayor higiene y confort', 125.28, 'si'),
(250, 'Short de control suave de abdomen efecto invisible tiro alto', '12966', 'mujer', 'leonisa', '¡Este panty tipo short es el complemento perfecto para tus looks! Úsalo con pantalones ajustados, vestidos o faldas, ya que por estar elaborado en tecnología sin cortes y con pocas costuras, es ideal para el uso diario sin que se marque en tu ropa exterior. Es alto en cintura y su diseño localizado en puntos con efecto brillo ejerce un control suave en el abdomen, y le agrega estilo a la prenda. Su elástico recogido en el centro de los glúteos les da una modelación más redondeada, ¡creando una figura increíble!', 'Short de compresión.\r\nSilueta: short largo.\r\nControla tu abdomen, estiliza tus muslos y moldea tus glúteos.\r\nInvisible bajo la ropa: menos cortes y costuras.\r\nDiseño localizado en puntos con efecto de brillo en el centro del abdomen que genera compresión suave.\r\nElástico recogido en el centro de los glúteos para una modelación más redondeada.\r\nComposición: 81% poliamida, 19% elastano.', 160.08, 'si'),
(251, 'BODY REDUCTOR CON COPAS - MÁXIMO AJUSTE EN TODO TU CUERPO', '18687', 'mujer', 'leonisa', 'Siéntete segura con este body reductor que se ajusta perfectamente a tu medida. Elaborado en PowerSlim?, te ofrece todos los beneficios que buscas, control, reducción y definición de tu figura con gran comodidad. Tiene copas triangulares prehormadas que te dan buen soporte, controla el abdomen alto medio y bajo, la cintura, la espalda y los muslos, no deja nada descubierto, es la faja ideal para que cubras y moldees todo tu cuerpo. Tiene cierre delantero con tres broches internos que facilitan la postura y una abertura inferior que te da mayor comodidad para las visitas al baño.', '-Body faja con cubrimiento hasta la rodilla\r\n-Reduce la cintura, caderas, muslos, abdomen alto, medio y bajo\r\n-Copas triangulares prehormadas en tela doble para un mejor ajuste\r\n-Elaborado en PowerSlim? y cubierto con DuraFit? para darte mayor comodidad\r\n-Tiene cortes y costuras especiales que levantan y modelan la cola\r\n-Cargaderas anchas que te ofrecen soporte y abrochadura en los hombros para graduar a tu gusto\r\n-Cuenta con un cierre delantero y tres broches internos que hacen mucho más fácil su postura\r\n-Esta faja es ideal para usarla en tratamientos postquirúrgicos y postparto\r\n-Su práctica abertura inferior te facilita las visitas al baño y te hace sentir mucho más cómoda\r\n-Composición: poliamida 83.00%, elastano 17.00%, Composición Forro: poliamida 75.00%, elastano 21.00%, ALGODÓN 4.00%.', 765.6, 'si'),
(252, 'FAJA CHALECO TÉRMICO DE REDUCCIÓN EN LÁTEX', '15482', 'mujer', 'leonisa', 'Faja chaleco reductor se ajusta perfectamente a tu cuerpo dándote excelente modelación. Tiene un diseño especial con materiales como el látex que te ayudan a eliminar toxinas, reduciendo medidas en cintura y abdomen. Moldea tu cuerpo con máximo ajuste y control todos los días.', '-Faja chaleco que reduce medidas\r\n-Moldea, reduce y controla el contorno de la cintura, abdomen alto, medio y bajo\r\n-Busto libre que permite el uso de tu brasier favorito\r\n-Poder triple capa, tela elástica lisa DuraFit?, látex y algodón\r\n-Forro interno en algodón que brinda comodidad y frescura\r\n-Materiales de alta resistencia y durabilidad\r\n-Diseño alto en espalda para mayor cobertura y control\r\n-Con tres broches internos y cierre en delantero para ponerlo rápida y cómodamente\r\n-Varillas internas que estilizan y ayudan a moldear tu figura\r\n-Composición: látex 64.00%, poliamida 26.00%, elastano 10.00%, Composición Forro: ALGODÓN 91.00%, elastano 9.00%', 535.92, 'si'),
(253, 'FAJA CINTURILLA DE CONTROL EXTRAFUERTE EN LÁTEX', '15791', 'mujer', 'leonisa', 'Esta cinturilla de control extrafuerte, elaborada en látex, tiene como ventaja que su material es mucho más liviano de lo normal. Esto hace que la cinturilla sea más ligera, más cómoda sin perder sus cualidades de control. Te ayuda a moldear el abdomen, la cintura y la espalda, para un efecto de modelación completa en toda la zona media de tu cuerpo. Úsala y descubre los excelentes resultados de una verdadera cinturilla de control extrafuerte', '-Cinturilla de control extrafuerte, elaborada en látex liviano y más cómodo\r\n-Dos varillas en abdomen y dos en la espalda, que mejoran tu postura\r\n-Capa interna de algodón, para un contacto más suave y delicado\r\n-Abrochadura frontal con tres niveles de ajuste, que te permite ver tu progreso\r\n-Broche en la parte superior, que asegura que la cinturilla se quede en su lugar\r\n-Composición: látex 93%, poliamida 6%, elastano 1%\r\n', 473.28, 'si'),
(254, 'FAJA CINTURILLA REDUCTORA - DEFINE TU CINTURA', '18624', 'mujer', 'leonisa', 'Sabemos que el abdomen y la cintura son las zonas que más preocupan a las mujeres, y también sabemos que quieres tener un figura con la línea de cintura más definida, por esto te traemos la mejor solución, las cinturillas realmente son una excelente opción. Con esta cinturilla podrás reducir medidas en tu abdomen alto, medio y bajo, en la cintura y la espalda y lo mejor de todo es que puedes usar tu sujetador preferido. Está elaborada con el poder doble capa: PowerSlim? que te ofrece reducción y una tela elástica lisa de alta tecnología llamada DuraFit? que te brinda frescura y suavidad al contacto con la piel. Tiene broches delanteros en tres posiciones para que la ajustes perfectamente a tu cuerpo y para que puedas ponértela fácilmente, además sus suaves varillas internas te ayudan a que la prenda permanezca firme en su sitio, se ajuste y no se enrolle ¡Aquí tienes la solución que estabas buscando!', '-Reduce medidas, moldea la cintura y el abdomen\r\n-Elaborada en PowerSlim? un material de alta resistencia y durabilidad\r\n-Suaves varillas en espalda y laterales que mantienen la prenda firme, sin enrollarse\r\n-Broches delanteros con tres niveles de ajuste\r\n-No se marca ni maltrata la piel\r\n-La cinturilla va hasta el final de la espalda con un corte recto para no partir los glúteos\r\n-Composición: poliamida 82.00%, elastano 18.00%', 452.4, 'si'),
(255, 'Sexy panty cachetero en tela ultraliviana con encaje comodidad total', '12967', 'mujer', 'leonisa', '\r\nPanty cachetero de tiro medio con ajuste suave y efecto invisible. Su diseño sin costuras y detalle posterior realza la figura con total comodidad.\r\n', 'Panty Cachetero Invisible con Efecto Moldeador\r\n• Composición: 90% poliamida – 10% elastano\r\n• Tiro medio con ajuste cómodo y adaptable al cuerpo\r\n• Diseño sin costuras en piernas que evita marcas bajo la ropa\r\n• Tela suave, ligera y elástica que brinda frescura\r\n• Costura recogida posterior que realza y da forma a los glúteos\r\n• Sensación de comodidad y libertad de movimiento durante todo el día\r\n• Acabado invisible ideal para prendas ajustadas', 90.48, 'si'),
(256, 'BANDA DE COMPRESIÓN EN PECHO Y BUSTO', '54004', 'mujer', 'leonisa', 'Esta banda por medio de la compresión y el soporte que ejerce en el pecho y el busto logra que te sientas mucho más cómoda durante una recuperación. Cuenta con cierre de Velcro para ajustarla con comodidad y así obtener el nivel de compresión preciso que necesitas. Es perfecta para usar después de una mamoplastia de aumento.', '-Banda de compresión para el pecho\r\n-Da excelente soporte y compresión con comodidad\r\n-Cierre de velcro\r\n-Gradúalo para obtener el ajuste perfecto\r\n-Úsalo después de una mamoplastia de aumento\r\n-Composición: poliamida 75.00%, elastano 25.00%, Composición Forro: poliamida 100.00%.', 222.72, 'si'),
(257, 'CAMISETA INVISIBLE CON COPAS EXTRAIBLES', '15804', 'mujer', 'leonisa', 'Consigue la silueta que siempre soñaste! Esta camiseta invisible es perfecta para moldear tu torso completo, ya que está elaborada en doble capa de DuraFit® y genera un control moderado en tu abdomen, cintura y espalda. ¡Estiliza tu silueta sin perder la comodidad! Además, tiene un increíble cubrimiento en la sisa que te ayuda a disimular los molestos gorditos debajo del brazo. Y como si todo eso no fuera suficiente, puedes usarla sin brasier ya cuenta con copas suaves de espuma que puedes extraer con facilidad y que redondean tu busto para crear un escote irresistible.', 'Increíble camiseta invisible con control moderado en abdomen, cintura y espalda.\r\nCrea un escote irresistible, gracias a sus copas de espuma removibles.\r\n¡Olvídate de los gorditos! Gracias a su alto cubrimiento en sisa.\r\nSiéntete tan cómoda como siempre, gracias a que está elaborada en DuraFit®: un material suave, ligero y cómodo.¡Adiós, costuras! Es termofusionada, así que tiene muy pocas costuras.\r\n¡Perfecta todo el día! No se enrolla ni se sube en la cintura.\r\nÚsala como ropa interior o como parte de tu atuendo exterior.\r\nComposición: 77% Poliamida, 23% Elastano.', 396.72, 'si'),
(258, 'CHALECO BUSTO LIBRE CON LÁTEX REDUCTOR', '15794', 'mujer', 'leonisa', 'Este chaleco es una prenda perfecta para usar como prenda interior todo el tiempo, ya que al ser busto libre y no tener mangas, es imperceptible bajo tu ropa. Está elaborado con dos capas de tela: una capa exterior en látex ultraliviano para máxima compresión y reducción y una capa interior en algodón para que estés cómoda siempre que lo lleves puesto.\r\n', 'Chaleco busto libre en látex, con suaves varillas en abdomen y espalda.\r\nMoldea y reduce medidas en abdomen, cintura y espalda. Úsalo para hacer ejercicio y comprueba sus resultados.\r\nCapa interna en algodón para mayor comodidad y capa externa en látex para máxima compresión.\r\nAbrochadura frontal con tres niveles de ajuste y gancho en la parte superior que evita que la prenda se abra.\r\nEspalda alta que cubre y controla totalmente corrigiendo la postura.\r\nCargaderas ajustables para uso convencional o cruzadas.\r\nComposición: caucho 96%, poliamida 3%, elastano 1%.', 570.72, 'si'),
(260, ' SHORT DE COMPRESIÒN MODERADA - ASPECTO INVISIBLE', '12970', 'mujer', 'leonisa', '¡Este short invisible de compresión es el complemento perfecto de tus looks! Cuenta con un fajón ancho en la pretina que está elaborado con tecnología antideslizante para que la prenda se adhiera a tu piel. Está elaborado en microfibra fresca, ligera y liviana que genera una compresión moderada en el abdomen y la cintura, moldeando tu figura y ayudando a disimular la celulitis. Cuenta con un elástico recogido en el centro de los glúteos para que se vean más redondeados, y al tener menos elásticos y costuras, se ajusta perfectamente a tu cuerpo como una segunda piel, haciéndolo ideal para usar bajo vestidos o pantalones ajustados sin que se note ni se marque y para evitar el roce entre las piernas ¡Pruébalo y enamórate de tu nueva silueta!', 'Detalles del producto\r\nShort de compresión que se adhiere al cuerpo gracias a su tecnología antideslizante en la pretina.\r\nSilueta: short medio.\r\n¡Tus curvas bajo control! Compresión moderada en abdomen medio y bajo.\r\nElaborado en microfibra. Es fresco y suave al tacto.\r\nAspecto invisible: no se marca en tu ropa.\r\nÚsalo con pantalones ajustados, vestidos o faldas para lucir más estilizada y evitar el roce entre las piernas.\r\nEvita el roce entre las piernas cuando lo uses con vestidos o faldas.\r\nLargo de la pierna en cm: Talla S (15.5 cm). Talla M (16.5 cm). Talla L (17.5 cm). Talla XL (18.5).\r\nProducido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\nComposición: 50.3% elastano, 49.7% poliamida.', 243.6, 'si'),
(261, 'Brasileras paquete x3 en algodón elástico con detalle en encaje', '12971X3', 'mujer', 'leonisa', '- Paquete de 3 panties estilo brasilera de tiro medio.\r\n- Elaborados en algodón elástico suave para máxima comodidad y excelente modelación.\r\n- Encaje decorativo en cintura para un toque más femenino.\r\n- Refuerzo inferior 100% en algodón para mayor comodidad.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 51% poliéster, 26.7% poliamida, 13% algodón, 9.3% elastano.', 'Paquete x3 de panty estilo brasilera de tiro medio con encaje decorativo en cintura, son súper cómodas y de excelente modelación. Están elaboradas en algodón elástico que se ajusta perfectamente a tu cuerpo y te brinda máxima frescura. Elásticos planos en piernas para evitar que se marquen en la ropa y maltraten la piel, te darán una apariencia invisible, perfectas para usar con prendas ajustadas. Refuerzo inferior 100% en algodón para mayor comodidad.', 348, 'si'),
(262, 'BRASIER DE REALCE MEDIO CON COPAS LISAS', '71274', 'mujer', 'leonisa', 'Brasier con arco y con realce incorporado en la parte inferior de las copas para darle a tu busto un look natural, se adapta perfectamente dándote un realce medio con excelente modelación. Está elaborado con tela lisa con buen ajuste al cuerpo, sus copas lisas no se marcan a través de la ropa. Es un brasier multiusos, puedes usarlo con las cargaderas convencionales, cruzadas o halter.\r\n\r\n', 'Brasier triangular con arco.\r\nCopas prehormadas con espuma incorporada que da el realce medio al busto.\r\nForro al interior de la copa en algodón para darte más frescura.\r\nElaborado en tela lisa con buen ajuste al cuerpo, suave con tu piel y no se marca en la ropa.\r\nCargaderas multiusos para usar de forma convencional, cruzadas o halter.\r\nBroches dobles con tres opciones de ajuste al contorno.\r\nComposición de la tela: 78% Poliamida, 22% Elastano.', 278.4, 'si'),
(263, 'BODY BUSTO LIBRE EN DURAFIT® ULTRALIVIANO', '18483', 'mujer', 'leonisa', 'Este body busto libre le da control moderado a tu espalda, abdomen, piernas y cintura, y te ayuda a realzar el busto y los glúteos. Está elaborado con nuestra mejor tecnología DuraFit®, material que moldea y comprime con total confort, para asegurar el control que necesita tu cuerpo con la libertad y la suavidad que necesita tu piel.', 'Body busto libre con control moderado en abdomen y espalda\r\n-DuraFit® ultraliviano y capa doble en espalda, que disimula los gorditos bajo los brazos\r\n-Cargaderas anchas y cómodas sin costuras\r\n-Realza el busto gracias al refuerzo en los laterales y levanta los glúteos\r\n-Tecnología antientorche en los muslos para que no se enrolle ni se marque\r\n-Abertura ergonómica y funcional en medio de las piernas\r\n-Composición: poliamida 61.00%, elastano 39.00%, Composición Forro: ALGODÓN 75.00%, poliamida 14.00%, elastano 11.00%.', 598.56, 'si'),
(264, 'Faja tipo body con bralette incorporado con control de abdomen', '18517', 'mujer', 'leonisa', ' Faja body Bralette incorporado en tul.\r\n- Control moderado en abdomen alto. Control fuerte en abdomen medio y abdomen bajo, justo en esas zonas que más quieres\r\ndisimular.\r\n- Doble capa en abdomen tela lisa PowerSlim.\r\n- Cortes frontales: cintura reloj de arena.\r\n- Buen soporte de busto: elástico en base y refuerzo en laterales de la sisa. Las copas cuentan con transparencias que\r\npermiten ver el pezón.\r\n', 'Con este body faja bralette en tul y diferentes niveles de control en abdomen y cintura, estilizarás más tu figura y tendrás todo en 1 sola prenda. Está elaborado con doble capa de tela lisa PowerSlim nuestro material de compresión, y cuenta con cortes frontales que dan un efecto de cintura reloj de arena. Sus copas son de muy buen cubrimiento, incluso perfectas para disimular los rollitos de la sisa. El refuerzo en los laterales del busto lo centrará más y el elástico en la base te dará mayor soporte. El tul en los laterales de las piernas y los glúteos le da un toque femenino y sexy a la faja, y además, es de efecto invisible ya que el panty no cuenta con elásticos. Un beneficio más: te encantará saber que la costura en el centro de los glúteos les dará una modelación más redondeada.\r\n', 682.08, 'si'),
(265, 'PAQUETE X 2 CAMISILLAS DE ALGODÓN', '35005x2', 'hombre', 'leo', 'Perfecto para todo momento, debido a que es ideal como prenda interior, para que las uses bajo todas tus camisas. Están elaboradas completamente en algodón, para que te sientas fresco todo el tiempo.', 'Camisilla de cuello redondo\r\nSilueta semiajustada y muy cómoda\r\nComposición: ALGODÓN 100.00%.\"', 334.08, 'si'),
(266, 'BRASIER SIN ARCO DE MÁXIMO SOPORTE Y REALCE NATURAL', '71280', 'mujer', 'leonisa', 'Brasier con copas triangulares que cubren completamente el busto dándote una excelente modelación. Tiene un diseño especial con costuras alrededor de las copas que simulan los arcos para darte un realce suave y natural. Este brasier te da máximo soporte y ajuste perfecto al cuerpo, además lo hace con total comodidad. Elaborado en DuraFit?, una tela suave, lisa y resistente', '-Brasier triangular sin arco de realce natural\r\n-Copas con cubrimiento total del busto\r\n-Costuras alrededor de las copas que simulan los arcos y te dan un realce natural\r\n-Espalda ancha para mayor sujeción de la prenda, es suave al contacto con la piel\r\n-Cargaderas anchas ajustables que te dan gran soporte con comodidad\r\n-Excelente ajuste al cuerpo y perfecta modelación del busto\r\n-Composición de la tela: 81% Poliamida, 17% Elastano, 2% Algodón\r\n', 320.16, 'si'),
(267, 'SEDUCTOR BRASIER DE REALCE ALTO EN ENCAJE', '71292', 'mujer', 'leonisa', 'Disfruta de un sensual realce con este brasier que tiene un novedoso diseño que te brinda un realce alto del busto. Sus copas triangulares tienen al interior una espuma especial incorporada con un poco más de espesor en la parte inferior que levanta el busto naturalmente, y una almohadilla removible adicional con la que puedes graduar el realce al nivel que más te guste.', 'Está elaborado en encaje elástico que se adapta perfectamente a tu cuerpo dándote una excelente modelación. Tiene suaves varillas laterales que te ofrecen mayor soporte y comodidad.\r\nBrasier con arco de realce alto media copa.\r\nCopas triangulares prehormadas con realce incorporado, novedosa espuma al interior que da un realce alto.\r\nBolsillo interno con almohadillas removibles para graduar el nivel de realce.\r\nElaborado en encaje elástico que se adapta muy bien al cuerpo y da una apariencia seductora.\r\nElásticos planos que te ofrecen excelente ajuste con comodidad.\r\nSuaves varillas laterales que ayudan a sostener mejor la prenda y dan una modelación perfecta.\r\nCargaderas removibles multiusos, las puedes usar de forma convencional, cruzada y halter.\r\nDelicados accesorios metálicos en las cargaderas y en la base de las copas.\r\nComposición de la tela: 57% Poliamida, 26% Poliéster, 17% Elastano.', 403.68, 'si'),
(268, 'Hipster invisible ultra cómodo sin costuras', '12976', 'mujer', 'leonisa', 'Este panty invisible de tiro bajo te permitirá sentirte muy cómoda ya que no tiene costuras en piernas ni cintura, evitando que se marque en la ropa y en tu piel. Su material te encantará ya que es suave al tacto y muy ligero. Sus dos costuras en contraste en la parte frontal le dan un look muy fresco y divertido. Su refuerzo inferior en algodón 100% te brinda total comodidad. Es perfecto para usar en el día a día, para tus looks más relajados, o para los momentos de descanso y para dormir.', 'Panty de tiro bajo estilo hipster invisible con costuras en contraste.\r\nTela fresca, resistente y liviana. Ultra suave al tacto.\r\nAlta tecnología, sin elásticos ni costuras.\r\nNo se marca en la ropa ni talla la piel.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición: 77% poliamida, 23% elastano', 125.28, 'si'),
(269, 'Paquete x 2 hipsters invisibles ultracómodos de tiro bajo', '12976X2', 'mujer', 'leonisa', '¡Como sabemos que te gusta tanto, ahora puedes llevarlo en paquete x 2! Estos panties invisibles de tiro bajo te permitirán sentirte muy cómoda ya que no tienen costuras en piernas ni cintura, evitando que se marquen en la ropa o en tu piel. Su material te encantará ya que es suave al tacto y muy ligero. Sus dos costuras en contraste en la parte frontal le dan un look muy fresco y divertido y su refuerzo inferior en algodón 100% te brinda total comodidad. Lo bueno de tener 2 panties de tu estilo favorito, es que siempre tendrás uno disponible para elegir en tu armario. Son perfectos para usar en el día a día, para tus looks más relajados, o para los momentos de descanso y dormir.', 'Paquete x 2 panty de tiro bajo estilo hipster invisible con costuras en contraste.\r\nTela fresca, resistente y liviana. Ultrasuave al tacto.\r\nAlta tecnología, sin elásticos ni costuras.\r\nNo se marca en la ropa ni talla la piel.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición: 77% poliamida, 23% elastano', 201.84, 'si'),
(270, 'BRASIER BALCONET CON ARCO DE REALCE MEDIO', '71320', 'mujer', 'leonisa', 'Brasier estilo balconet con arco, elaborado en tela lisa. Las copas son prehormadas en espuma suave y delgada, tienen mayor profundidad y le dan al busto una buena modelación. La espalda en tela lisa se ajusta muy bien y es totalmente cómoda. Puedes usar las cargaderas en modo convencional, cruzadas o halter.', '\"Brasier con arco de realce medio estilo balconet\r\nCopas prehormadas en espuma suave y delgada con buena capacidad\r\nLa espalda y la base del busto son en tela lisa, con excelente ajuste al cuerpo\r\nElásticos planos en la base de las copas y espalda que ayudan a sostener mejor\r\nCargaderas graduables y removibles que puedes usar en modo convencional, cruzadas o halter\r\nAbrochadura doble con tres niveles de ajuste\r\nComposición: poliamida 79%, elastano 21%\"', 320.16, 'si'),
(271, 'BRASIER TRIANGULAR DE REALCE MEDIO Y ESPALDA ANCHA', '71321', 'mujer', 'leonisa', 'Este brasier te va a encantar, porque es el esencial para tu día a día. Cuenta con copas prehormadas de buen cubrimiento, arco interno y varillas en los laterales, lo que ayuda a crear el escote perfecto. Además, su espalda es más ancha para estilizar tu figura.', '\"Brasier triangular con arco y copas prehormadas\r\nIdeal para busto regular y grande\r\nVarillas laterales que mantienen el bra en su lugar\r\nElástico ancho en la base para mayor soporte\r\nComposición: poliamida 82%, elastano 18%\r\nCargaderas graduables y fijas atrás, para uso convencional o cruzadas\r\nAbrochadura triple con cuatro niveles de ajuste\"', 327.12, 'si'),
(272, 'Panty faja tipo short levanta cola', '12983', 'mujer', 'leonisa', '¡Un short que guardará el secreto de una figura más estilizada y unos glúteos más redondeados sin cirugías! Este panty faja además de moldear tu figura es levanta cola. Su capa externa en nuestro material de compresión PowerSlim genera un control fuerte en el abdomen medio, bajo y la cadera. Además, los laterales de la espalda y tus piernas también lucirán más estilizados. Su capa interna en tela lisa es muy suave al tacto con la piel y cuenta con una franja de encaje en las piernas que le aporta estilo a la prenda. El elástico recogido en el centro de los glúteos les dará una modelación más redondeada, ¡úsalo con pantalones, vestidos o faldas y luce increíble!', 'Panty faja tipo short en PowerSlim con control fuerte en el abdomen medio, bajo y cadera.\r\nSilueta: short corto.\r\nEfecto levanta cola gracias a las costuras que realzan los glúteos.\r\nDisimula los rollitos de los laterales de la espalda.\r\nCapa interna en tela lisa para mayor suavidad al tacto.\r\nBanda de PowerSlim bajo los glúteos que le da una apariencia más lisa a esta zona de cuerpo.\r\nElástico recogido en el centro de los glúteos para una modelación redondeada.\r\nComposición: 88% poliamida, 12% elastano.', 480.24, 'si'),
(273, 'BRASIER TRIANGULAR DE REALCE MEDIO PARA BUSTO GRANDE', '71322', 'mujer', 'leonisa', 'Este brasier de realce está creado especialmente para bustos grandes, con copas de gran capacidad que te permiten adaptarlo perfectamente a tu medida. Elaborado con tela elástica de última tecnología DuraFit?.', '\"Brasier triangular de realce medio\r\nIdeal para busto grande\r\nCopas con excelente capacidad y refuerzo interno\r\nElaborado en DuraFit?: una tela lisa, suave y de alta duración\r\nCargaderas graduables y acolchadas para uso halter, cruzado o convencional\r\nComposición: poliamida 86%, elastano 14%\"', 354.96, 'si'),
(274, 'BUSTIER DE REALCE MEDIO ESTILO BALCONET EN ENCAJE', '71325', 'mujer', 'leonisa', 'Este brasier es un símbolo de sensualidad, ya que está elaborado totalmente en el más delicado de los encajes, dándote un aspecto muy sexy y femenino. Sus copas son de espuma suave y gracias a su arco, cuentan con un realce muy natural que se encarga de darte el escote perfecto. Su silueta alargada, le da a tu cuerpo un aire de elegancia clásica.', '-Bustier estilo balconet elaborado en encaje\r\n-Copas en espuma con arco interno para un realce medio\r\n-Varillas suaves bajo el busto y en los laterales para un ajuste y escote perfectos\r\n-Cargaderas graduables y removibles para uso convencional, cruzado o halter\r\n-Abrochadura de seis ganchos con dos niveles de ajuste\r\n-Composición: poliamida 88.00%, elastano 12.00%, Composición Forro: poliéster 73.00%, elastano 14.00%, poliamida 13.00%.', 361.92, 'si'),
(275, 'BRASIER DE REALCE SUAVE EN ENCAJE', '71326', 'mujer', 'leonisa', 'Enamórate de la delicadeza de este bra, cubierto totalmente por el más femenino de los encajes. Su arco interno se encarga de darte todo el soporte que necesitas y de crear un realce suave que te va a encantar.\r\n', 'Brasier de realce suave con arco interno.\r\nCubierto totalmente en encaje floral.\r\nCargaderas graduables para uso convencional, cruzado o halter.\r\nAbrochadura con dos ganchos y tres niveles de ajuste.\r\nComposición de la tela: poliamida 86.00%, elastano 14.00%, \r\nComposición Forro: poliamida 100.00%.\r\n', 306.24, 'si'),
(276, 'BRASIER TRIANGULAR DE BUEN CUBRIMIENTO Y REALCE SUAVE', '71327', 'mujer', 'leonisa', 'Este brasier se convertirá en el compañero ideal de todos tus días, gracias a su infinita comodidad. Sus copas tienen muy buen cubrimiento, te dan un delicado realce suave y tienen un arco que moldea tu busto. Sus cargaderas, están elaboradas en un material ergonómico que las hace muy suaves y cómodas. ¡Te va a encantar!', '\"Brasier triangular con arco y realce suave\r\nIdeal para busto regular y grande\r\nCargaderas anchas, ergonómicas, fijas y graduables para mayor comodidad\r\nAbrochadura de tres ganchos y cuatro niveles de ajuste\r\nComposición: poliamida 72%, elastano 19%, poliéster 9%\"', 431.52, 'si'),
(277, 'Brasier balconet de encaje con realce incorporado', '71330', 'mujer', 'leonisa', 'El escote recto de este brasier, le da a tu busto la sensualidad que estabas buscando, haciendo que tu escote se vea con más volumen. Cuenta con arcos internos para darle más soporte a tu busto. Las copas son prehormadas en espuma y tienen un realce incorporado en la parte inferior para levantar el busto de forma natural. El elástico ancho en la base te da mejor soporte cuando lo usas como strapless. Su abrochadura de 3 broches y 4 ajustes, permite que lo ajustes a tu cuerpo.', '- Brasier de escote recto y espalda ancha.\r\n- Ideal para busto mediano y grande.\r\n- Copas prehormadas con realce incorporado.\r\n- Encaje elástico que le da ese toque femenino y sexy.\r\n- Elástico ancho en la base que ayuda a sostener la prenda si lo usas sin cargaderas.\r\n- Cargaderas removibles para uso convencional, cruzado, halter o strapless.\r\n- Espalda ancha con 3 broches y 4 niveles de ajuste.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 82% poliamida, 18% elastano. Composición forro: 90% poliamida, 10% elastano.', 257.52, 'si'),
(279, 'Brasier triangular con cubrimiento de sisa y espalda', '71339', 'mujer', 'leonisa', 'Este brasier triangular se convertirá en el aliado perfecto para todos los días gracias a su buen cubrimiento y comodidad. Sus copas en espuma suave se adaptan a la forma de tu busto dándole una apariencia más redondeada en la parte superior del escote. Tiene arcos que dan un mejor soporte, manteniendo el bra en su lugar. Es el brasier ideal para aquellas mujeres que buscan cubrir los laterales de la sisa y espalda, gracias a que es más ancho en esta zona, ayudando a disimular los rollitos de esta zona. Sus cargaderas son graduables y cuenta con una abrochadura de tres ganchos y cuatro niveles que te permiten un mejor ajuste.', 'Brasier triangular con arco.\r\nIdeal para busto regular.\r\nElástico ancho en la base para mayor soporte.\r\nCargaderas graduables y fijas.\r\nAbrochadura de tres ganchos y cuatro niveles de ajuste.\r\nComposición: 82% poliamida, 18% elastano, composición forro: 85% poliamida, 15% elastano.', 229.68, 'si'),
(280, 'PANTALOCILLOS CLÁSICOS EN ALGODÓN', '33180', 'hombre', 'leo', '¡Ahora tu pantaloncillo clásico! Está elaborado en algodón para que sientas máximo confort, frescura y un contacto suave con la piel. Es un diseño clásico, alto en las piernas, con cubrimiento medio de la cadera y además te ofrecen excelente modelación y soporte. Tiene en la cintura un elástico ancho expuesto, con buen ajuste al cuerpo.', 'Pantaloncillo clásico\r\nElaborado en algodón polyester\r\nCubrimiento medio de la cadera y alto en las piernas\r\nElástico ancho expuesto en la cintura con excelente ajuste al cuerpo\r\nElásticos suaves en las piernas\r\nMáxima frescura y confort', 104.4, 'si'),
(281, 'Bralette triangular de encaje en el frente y tela lisa en espalda', '71340', 'mujer', 'leonisa', 'Este bralette triangular es la combinación ideal entre comodidad, delicadeza y sensualidad. Está elaborado en encaje en la parte frontal y en la espalda combina el encaje con una tela lisa y suave al tacto en la base. No tiene arco y sus copas están elaboradas en encaje y tul, para que puedas disfrutar de una modelación natural. Es ideal para mujeres de busto regular y grande que buscan una prenda ligera y sexy.', ' Cuenta con una banda elástica en la base y con cargaderas anchas y fijas lo cual le dará mayor soporte a tu busto.\r\n- Bralette triangular en encaje en el frente y tela lisa en espalda.\r\n- Ideal para mujeres de busto regular y grande.\r\n- Elástico que rodea toda la base, para mayor ajuste y soporte.\r\n- Doble tela en las copas para un tacto muy suave y evitar transparencias.\r\n- Cargaderas anchas y fijas.\r\n- Abrochadura de 3 ganchos y 4 niveles de ajuste.', 194.88, 'si'),
(282, 'Brasier tipo top con abrochadura en espalda', '71341', 'mujer', 'leonisa', 'La comodidad de un top con el ajuste y soporte de un brasier los encuentras en este brastop. Sus copas son suaves, livianas y lisas. Es muy suave al contacto con tu piel. Sus copas completas tiene buen cubrimiento en el escote y en los laterales de la sisa, además, cuentan con bolsillos internos para darte la opción de usarlo con copas removibles (no incluidas).', 'El escote en V cuenta con un detalle de tres ojales en el centro que le da un toque sexy, moderno y único. El elástico en la base del busto, y los cortes y costuras que reemplazan los arcos, le dan soporte y sostenimiento. Además, sus varillas laterales ayudan a centrar el busto y a que la prenda se ajuste a tu contorno. Sus cargaderas son fijas en el frente y son graduables en espalda para que las ajustes a tu medida.\r\nBrasier tipo top sin arcos internos con varillas laterales.\r\nCopas de buen cubrimiento en escote y sisa, elaboradas en tela lisa muy suaves al contacto con la piel.\r\nDetalle de ojales en el centro del escote para un look moderno y único.\r\nBolsillo interno para usarlo con copas removibles (no incluidas).\r\nEspalda cómoda y lisa.\r\nElástico bajo el busto, y cortes y costuras que le brindan soporte.\r\nAbrochadura de 3 ganchos y 4 niveles de ajuste.\r\nComposición: 79% poliamida, 21% elastano', 320.16, 'si'),
(283, 'Brasier copa lisa con arcos y realce incorporado', '71344', 'mujer', 'leonisa', 'Brasier con cubrimiento medio del busto. Cuenta con arcos y con realce incorporado en la parte inferior de las copas para darle una forma más redondeada a la parte superior de tu escote y más volumen a tu busto.', 'Detalles del producto:\r\n\r\n- Brasier media copa con arco.\r\n- Ideal para busto mediano.\r\n- Copas prehormadas con espuma incorporada para realce medio del busto.\r\n- Elaborado en tela lisa con buen ajuste al cuerpo, suave con tu piel y no se marca en la ropa.\r\n- Cargaderas multiusos para usar de forma convencional, cruzadas o halter.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.', 278.4, 'si'),
(284, 'Brasier doble realce escote profundo elaborado en encaje', '71345', 'mujer', 'leonisa', 'Este brasier de doble realce será tú favorito si lo que buscas es darle más volumen a tu escote y sentirte muy sexy. Sus copas están elaboradas en espuma con dos pads incorporados, uno en el lateral y otro en la parte inferior de la copa que centran, levantan y realzan el busto, ¡la combinación perfecta entre seguridad, soporte y sensualidad! Cuenta con cargaderas fijas y graduables para que lo ajustes a tu medida.', 'La espalda es de excelente elongación gracias al elástico ancho de la base, permitiendo que se ajuste a diferentes contornos y su abrochadura es de 3 posiciones y 4 niveles de ajuste.\r\n- Brasier triangular doble realce.\r\n- Copas con arco y dos pads de espuma que centran, levantan y realzan el busto.\r\n- Ideal para mujeres con busto pequeño y mediano\r\n- Escote profundo para resaltar tu sensualidad.\r\n- Cargaderas fijas y ajustables.\r\n- Abrochadura de 3 ganchos y 4 niveles de ajuste.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 86% poliamida, 14% elastano. Composición forro: 100% poliéster.\r\n', 348, 'si'),
(285, 'Brasier tipo top ultraliviano con copas internas fijas', '71346', 'mujer', 'leonisa', 'Al tener la estructura de un brasier y la comodidad de un top, este bra se convertirá en tu nuevo favorito para el día a día. Su estructura interna es totalmente diferente y tecnológica, sus copas son prehormadas y no cuentan con arcos ni realce. Tiene muy buen soporte gracias al elástico suave en la base del busto y sus varillas laterales ayudan a centrar el busto y a que la prenda tenga más ajuste', 'Detalles del producto:\r\n\r\n- Brasier ultracómodo elaborado en tela lisa.\r\n- Ideal para mujeres de busto pequeño y mediano.\r\n- Estructura interna que integra las dos copas, sin costuras, sin realce, ni arcos.\r\n- Escote recto con buen cubrimiento del busto que te da seguridad y comodidad.\r\n- Suaves varillas laterales que ayudan a centrar el busto.\r\n- Elástico ancho en la base del busto para mayor soporte.\r\n- Espalda ancha de buen cubrimiento.', 292.32, 'si'),
(286, 'Brasier triangular con copas en encaje y espalda en tela lisa', '71357', 'mujer', 'leonisa', '- Diseño clásico, atemporal ¡nunca pasa de moda!\r\n- Copas en encaje   forro interno en tela suave.\r\n- Estructura interna en las copas, en forma de hamaca, para más soporte de busto.\r\n- Arcos internos.\r\n- Buen cubrimiento en sisa.\r\n- Cargaderas graduables, no removibles.\r\n- Abrochadura de 3 broches y 4 niveles de ajuste.', 'Si lo que más buscas en un brasier es cubrimiento, comodidad y un diseño atemporal y clásico, encontraste lo que estabas buscando. Además de los arcos, tiene un detalle diferenciador en las copas, lo que le da un soporte extra a tu busto: una tela en forma de hamaca. Su espalda es elástica, en tela lisa y suave al tacto. Sus cargaderas no son removibles, pero son graduables para que las ajustes a tu cuerpo, y su espalda en forma de U, hace que tenga más ajuste a tu cuerpo y sus cargaderas se mantengan firmes. La abrochadura es de 3 broches y 4 niveles de ajuste.', 361.92, 'si'),
(287, 'Brasier de buen cubrimiento y soporte con arco', '71358', 'mujer', 'leonisa', 'Si eres fan del buen soporte en un brasier y también del encaje, tienes que tener este bra. Sus copas prehormadas en espuma fija son de muy buena capacidad, haciéndolo ideal para busto mediano y grande. Cuenta con arcos y con un elástico interno en la base del busto que le dan muy soporte a tu busto. La espalda es uno de sus partes más diferenciadoras ya que es ancha y de aspecto invisible ¡lucirá increíble con tus camisetas y blusas! Sus cargaderas graduables son removibles en espalda y su abrochadura es de 3 ganchos y 4 niveles de ajuste.', '- Copas prehormadas fijas en espuma: ideal para busto mediano y grande.\r\n- Buen cubrimiento en escote y en los laterales de la sisa.\r\n- Elástico interno ancho en la base del busto para que se ajuste más a tu cuerpo y tengas un mayor soporte.\r\n- La tela adicional sobre la sisa permite que su cubrimiento sea mayor y que disimule los rollitos de esta zona brindando más comodidad.\r\n- Varillas laterales que permiten que el bra se ajuste y adapte mejor a tu cuerpo.', 494.16, 'si'),
(288, 'Brasier en encaje ideal para busto pesado Sexy Support', '91001', 'mujer', 'leonisa', 'Brasier tipo bustier de copas triangulares.\r\nIdeal para busto regular y grande.\r\nCopas suaves de espuma, arco y varillas laterales.\r\n', 'Este brasier te da el soporte y el cubrimiento que necesitas. Es ideal para mujeres de busto mediano y grande. Está cubierto totalmente en el más delicado de los encajes, cuenta con suaves copas en espuma, arcos que soportan tu busto y varillas laterales que te garantizan la mejor modelación. Es tipo bustier, es decir, que tiene más cubrimiento en la base del busto ayudando a disimular los rollitos del abdomen alto. Su espalda ancha disimula el volumen de esta zona dándole una apariencia más plana. Pruébatelo y enamórate de inmediato. ¿Habías pensado antes que una misma prenda podría moldear tu cuerpo y a la vez hacerte lucir muy sexy?', 605.52, 'si'),
(289, 'Bralette en tul y encaje con cargaderas dobles', '91002', 'mujer', 'leonisa', 'País de origen: COLOMBIA\r\nFabricante y/o importador: CI GIRDLE & LINGERIE S.A.S\r\nNIT: 811044814-1\r\nInstrucciones de cuidado: Lavar a mano temperatura máxima 40°C. Lavar con colores similares. No usar blanqueador. No retorcer ni exprimir. Secado en tendedero en la sombra. No planchar. No limpieza en seco.', 'Bralette ligero sin arcos, pensado para mujeres de busto pequeño y regular que buscan comodidad y un toque sexy. Sus copas son triangulares y están elaboradas en dos materiales, tul y encaje, para una apariencia muy femenina. Al no tener realces incorporados su modelación se hace muy natural. Además te dará el soporte que necesitas gracias al elástico en la base y sus dobles cargaderas, una ancha y otra estilo pitillo, para un look muy juvenil. Una opción perfecta para usar todos los días. Puedes combinarlo con nuestros panties de encaje o algodón para que te sientas muy cómoda comenzando desde tu interior.', 605.52, 'si'),
(290, 'Brastop ultra confort multiusos y de mastectomía', '91004N', 'mujer', 'leonisa', 'Brasier tipo top en tela lisa y suave, con toques de encaje en el escote, perfecto para mostrar con camisas abiertas. Cuenta con un bolsillo interno para copas o prótesis de mastectomía (no incluídas). Su alto cubrimiento del busto, sisa y espalda te brindará la comodidad y seguridad que necesitas después de una cirugía de mastectomía o también en el uso diario. ', 'Su espalda ancha estiliza esta zona y disimula los rollitos. Está elaborado con tecnología Bodyfresh, una tela con efecto antibacterial que minimiza la formación de bacterias, manteniéndote fresca todo el tiempo. Sus cargaderas anchas y ergonómicas te dan mayor comodidad y soporte, evitando que se maltrate tu piel.\r\nBrastop para mastectomía o uso diario sin arcos ni varillas.\r\nBolsillos internos para copas o prótesis de mastectomía (no incluidas).\r\nCopas lisas, sin cortes ni costuras.\r\nElaborado en DuraFit, un material que te brinda mayor suavidad y comodidad.\r\nTecnología BodyFresh, que evita la proliferación de bacterias.\r\nEspalda ancha para mayor cubrimiento y excelente ajuste.\r\nCargaderas anchas y ergonómicas muy suaves con la piel.\r\nComposición: poliamida 85.00%, elastano 15.00%, Composición Forro: poliamida 82.00%, elastano 18.00%.', 299.28, 'si'),
(291, 'Brasier de buen cubrimiento ideal para busto pesado Natural Support', '91008', 'mujer', 'leonisa', 'Porque te encantará\r\n\r\n- Brasier copa completa de alto cubrimiento de busto y excelente modelación.\r\n- Con varillas internas, diseñado para brindar excelente soporte.\r\n- Mayor cubrimiento en sisa y espalda.\r\n- Varillas laterales para más soporte.\r\n- Tirantes anchos graduables. Broche de 3 ganchos con 4 niveles de ajuste para adaptar el bra a tu - \r\n  contorno.\r\n', 'Brasier de cubrimiento alto de busto, espalda y sisa. Las copas están diseñadas para centrar y brindar muy buen soporte, lo que lo hace ideal para busto grande y pesado. Cuenta con varillas laterales que dan mayor ajuste y hacen que el brasier se mantenga en su lugar. Su espalda ancha ayuda a disimular los rollitos y la broche de 3 broches y 4 niveles permite que lo adaptes a tu contorno.', 382.8, 'si'),
(292, 'Bralette en encaje sexy y natural', '91009', 'mujer', 'leonisa', '¡Sexy y natural! Este bralette triangular sin arco, de copas muy suaves y livianas con cubrimiento medio que hacen que el busto se vea muy natural, sin darle volumen adicional. Elástico en la base de la copa que reemplaza los arcos y soporta el busto. Pensado para las amantes de brasieres de copas lisas y toques de encaje, sus moras en el escote y la base le dan una apariencia muy romántica. Sus cargaderas son graduables y removibles, para que puedas usarlo de forma convencional o cruzado. Es ideal para mujeres de busto pequeño y regular y perfecto para usarlo con prendas abiertas y escotadas o bajo una transparencia. ¡Enamórate de una silueta 100% natural!', '- ¡Sexy y natural! Bralette triangular sin arco.\r\n- Ideal para mujeres de busto pequeño y regular.\r\n- Detalles en encaje en base y espalda, sutiles y femeninos.\r\n- Copas suaves y livianas de cubrimiento medio.\r\n- Siempre cómoda: cargaderas suaves y elásticas para uso convencional o cruzado.\r\n- Ajuste perfecto: espalda con 3 broches y 4 niveles de ajuste.\r\n- Composición: 82% poliamida, 18% elastano', 368.88, 'si'),
(293, 'Brasier triangular de realce alto y buen cubrimiento Memory Bustier', '91010', 'mujer', 'leonisa', 'Bustier de realce alto con espuma suave de alta tecnología para lograr la perfección del escote con un busto más redondeado. Tipo bustier quiere decir que tiene más cubrimiento en la base del busto ayudando a disimular los rollitos del abdomen alto.', 'Detalles del producto:\r\n\r\n- Brasier tipo bustier de realce alto con arcos.\r\n- Memory foam en las copas: espuma que se adapta a la forma de tu busto.\r\n- Da una apariencia redondeada del busto.\r\n- Elástico ancho en base para mayor soporte y seguridad.\r\n- Espalda ancha de buen cubrimiento, disimula los rollitos.\r\n- Cargaderas graduables, removibles en espalda, con excelente soporte.\r\n- Abrochadura de 3 posiciones y 4 niveles de ajuste.', 598.56, 'si'),
(294, 'Bralette con copas en espuma cubierto en encaje', '91012', 'mujer', 'leonisa', 'Bralette sin arco cubierto totalmente en encaje.\r\nIdeal para mujeres de busto pequeño y regular.\r\nCopas en suave y delgada espuma sin realce, que dan una modelación natural del busto.\r\nEspalda sin abrochadura con elástico en la base que genera más ajuste, perfecta para mostrar con tu ropa exterior.\r\nCargaderas graduables y removibles.\r\nComposición: 85.00% Poliamida, 15.00% Elastano', 'Este bralette cómodo sin arco tiene copas en espuma prehormadas, muy suaves y livianas que hacen que tu busto se vea muy natural, sin darle volumen adicional. Fue diseñado para las amantes de los bralettes y los encajes ya que está cubierto totalmente por un delicado encaje en motivo floral, y sus moras en el escote y la base le dan una apariencia muy romántica. Sus cargaderas son graduables y removibles, para que puedas usarlo de forma convencional o cruzado. Es ideal para mujeres de busto pequeño y regular, perfecto para usarlo con prendas abiertas y escotadas en la espalda o bajo una transparencia.', 278.4, 'si'),
(295, 'Brasier multitallas con ajuste flexible en espalda', '91013', 'mujer', 'leonisa', 'EL brasier con la espalda cómoda y versátil que siempre te soñaste: 2 abrochaduras que están unidas por 2 elásticos que elongan para ajustarse perfectamente a los diferentes contornos.\r\nBrasier triangular de modelación natural con arco interno.\r\nCopas suaves con buen cubrimiento y soporte.\r\nIdeal para uso diario, para busto regular, grande y muy grande.\r\nEspalda con material termofusionado de ajuste perfecto y con menos costuras.\r\nCargaderas graduables y removibles para uso convencional, cruzadas o halter.', 'El nuevo brasier multitallas se adapta a tu espalda, gracias a sus 2 abrochaduras que están unidas por 2 elásticos que elongan para ajustarse perfectamente a los diferentes contornos. Al no tener cortes o costuras, estos elásticos no se marcan ni se sienten; además, no se deforman ni se estiran.\r\n\r\nPuedes ajustarlo a tus medidas de acuerdo a los cambios en tu cuerpo generados por: embarazo, cambios hormonales, cambios de peso durante el año, etc. Sus copas ultrasuaves y cómodas se adaptan a tu busto sin dejar espacio entre la piel y las copas. Cuenta con arco interno. Su material es transpirable para una mayor sensación de frescura.\r\n\r\n¿Estás cansada de sentir que la espalda te queda ajustada, que te quedan marcas o que nunca logras adaptarlo realmente a tu contorno?\r\n¿Sueñas con volver a usar brasieres con copa pero te habías rendido porque la espalda no era lo suficientemente cómoda?\r\nSu magia está en que se adapta a tus medidas, incluso cuando estas cambian:\r\nla flexibilidad nunca antes vista en un brasier .\r\n\r\n\r\nEl toque innovador de este brasier está en sus 2 abrochaduras que están unidas por 2 elásticos que elongan para ajustarse perfectamente a los diferentes contornos.\r\n\r\n\r\nAl no tener cortes o costuras, estos elásticos no se marcan ni se sienten; además, no se deforman ni se estiran.', 361.92, 'si'),
(296, 'Bralette multiusos sexy siempre en encaje ideal para prótesis de mastectomía', '91014', 'mujer', 'leonisa', 'Este bralette está creado especialmente para aquellas mujeres que les gusta sentirse cómodas y sexies con prendas de buen cubrimiento y materiales ligeros. Cuenta con un bolsillo perfecto para usar prótesis (no incluídas) después de una cirugía de mastectomía y darle el volumen necesario al busto. Está elaborado en encaje, lo cual le da un toque muy femenino. El detalle en tul del centro del escote lo hace perfecto para combinarlo con la ropa exterior. Su buen ajuste de base y abrochadura graduable lo hacen una prenda muy cómoda.', '- Bralette multiusos ideal para uso diario o para mastectomía.\r\n- Bolsillo en las copas para almohadillas o prótesis de mastectomía (prótesis no incluídas).\r\n- Espalda ancha para mayor cubrimiento y excelente ajuste.\r\n- Cargaderas fijas y anchas.\r\n- Abrochadura de 3 broches y 4 niveles de ajuste.\r\n- Composición: 84% poliamida, 16% elastano, composición forro: 84% poliamida, 16% elastano.', 382.8, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(297, 'BÓXER LARGO LEO EN ALGODÓN CON AJUSTE PERFECTO', '33247', 'hombre', 'leo', 'Bóxer Leo medio ajustado al cuerpo, elaborado en algodón para garantizar comodidad y excelente modelación. Costuras planas, diseño anatómico y elástico suave expuesto en colores que contrastan y te dan una apariencia moderna.', 'Bóxer medio ajustado al cuerpo\r\nElaborado en algodón/spandex para garantizar comodidad y modelación\r\nSuave elástico expuesto que se ajusta sin dejar marcas\r\nCosturas planas que no tallan\r\nDiseño anatómico que se adapta a tu figura\r\nComposición de la tela: 80% Algodón, 11% Poliamida, 8% Elastano, 1% Poliéster', 167.04, 'si'),
(298, 'Bralette en encaje con transparencias y arco', '91017', 'mujer', 'leonisa', 'Este bralette ligero y liviano elaborado en encaje es el complemento perfecto para sentirte cómoda y espectacular. Está diseñado para mujeres de busto pequeño y mediano que buscan comodidad, libertad y frescura. Elaborado completamente en encaje con transparencias muy femeninas. Su silueta triangular se ajusta al busto generando una modelación muy natural y los arcos le brindan mayor soporte.', 'El escote profundo y los accesorios dorados en el centro de las copas y las cargaderas, le dan un toque sexy y único. Su espalda en encaje es de poco cubrimiento y sus cargaderas delgadas son graduables para que las ajustes a tu medida.\r\n- Bralette triangular elaborado totalmente en encaje con transparencias.\r\n- Ideal para busto pequeño y mediano.\r\n- Copas en encaje, con arco interno que soporta tu busto.\r\n- Espalda de poco cubrimiento elaborada en encaje.\r\n- Cargaderas graduables para que lo ajustes a tu medida.\r\n- Las copas cuentan con transparencias que permiten ver el pezón.\r\n- Abrochadura de 2 ganchos y 4 niveles de ajuste.\r\n- Composición: 83.8% poliamida, 16.2% elastano', 271.44, 'si'),
(299, 'BÓXER LEO SUELTO EN ALGODÓN DE MÁXIMA FRESCURA', '33271', 'hombre', 'leo', 'Bóxer suelto con abertura frontal que te brinda mayor comodidad, está elaborado en algodón para darte máxima frescura y confort durante todo el tiempo que lo uses. Su diseño suelto te ofrece mayor libertad de movimiento y puedes usarlo en diferentes ocasiones en las que quieras sentirte absolutamente cómodo.', '- Bóxer suelto para mayor comodidad\r\n- Abertura frontal con botón\r\n- Elaborado en algodón para mayor frescura\r\n- Elástico en cintura que no talla\r\n- Composición de la tela: 89% Algodón, 7% Poliéster, 4% Caucho', 180.96, 'si'),
(300, 'Brasier reductor para busto grande y pesado Perfect Support', '91022', 'mujer', 'leonisa', 'Este brasier reductor para busto grande y pesado reduce tu busto hasta 1 pulgada. Sus copas triangulares lo cubren completamente siendo ideal para mujeres que buscan controlar su volumen. Las copas en doble tela sin cortes ni costuras le dan una apariencia invisible bajo tu ropa exterior. ', 'Brasier triangular reductor de buen cubrimiento para busto pesado y con volumen.\r\nSoporte al interior de las copas que reemplaza los arcos. Abertura tipo bolsillo en el lateral interno para usarlo con copas removibles y evitar que el pez', 278.4, 'si'),
(301, 'Bralette triangular en encaje y tul con detalle de ojal en escote', '91025', 'mujer', 'leonisa', 'Bralette sin estructuras, elaborado en encaje y en tul con diseño en rombos. Está pensado para mujeres de busto pequeño y regular que buscan estar cómodas y sexies al mismo tiempo. Su silueta triangular se ajusta a tu busto generando una modelación muy natural. En el centro del escote cuenta con un ojal que deja ver tu piel y le agrega estilo y seducción a la prenda. Cuenta con un elástico en la base que ayuda a soportar tu busto y además le agrega un toque muy juvenil. Su espalda de poco cubrimiento te encantará ya que el tul y el encaje se mezclan para hacerte lucir muy ligera y sexy.', '- Bralette triangular elaborado en encaje y tul con transparencias.\r\n- Ideal para busto pequeño y mediano.\r\n- Elástico ancho en la base que soporta tu busto y le da un toque juvenil.\r\n- Espalda de poco cubrimiento en encaje y tul para que luzcas muy sexy.\r\n- Cargaderas graduables para que lo ajustes a tu medida.\r\n- Las copas cuentan con transparencias que permiten ver el pezón.\r\n- Abrochadura de 2 ganchos y 4 niveles de ajuste.\r\n- Composición: 81% poliamida, 19% elastano, composición forro: 91% poliamida, 9% elastano.', 292.32, 'si'),
(302, 'Brasier con cubrimiento total del busto Comfort Fit', '91026', 'mujer', 'leonisa', 'Brasier triangular con arco y cubrimiento total del busto. Está elaborado con la nueva tecnología de encaje con diseño cebra que genera transparencias y es ultra cómoda; se ajusta perfectamente al busto evitando espacios entre tu piel y el brasier. Las copas están elaboradas en espuma suave (sin relleno), ligera y liviana, tienen mayor capacidad y profundidad, y además de adaptarse a tu busto, lo hará lucir más redondeado, haciendo que tu escote se vea mejor que nunca. Su espalda cuenta con doble capa de encaje brindando mayor soporte y ajuste. No cuenta con elásticos en la parte superior de la espalda evitando marcas en la piel y rollitos bajo el brazo.', '- Brasier triangular con arco y cubrimiento total del busto.\r\n- Elástico ultraplano en la base para mayor ajuste.\r\n- Copas elaboradas en espuma suave (sin relleno).\r\n- Cargaderas anchas fijas a las copas en la parte frontal. En la parte de la espalda puedes graduarlas y \r\n  usarlas de forma convencional o cruzadas.\r\n- Apariencia invisible sin elásticos en la parte superior de la espalda.', 480.24, 'si'),
(303, 'Brasier ultraliviano sin arco con copas en espuma y tul sexy fresh bra', '91028', 'mujer', 'leonisa', 'Este brasier es cómodo y sexy al mismo tiempo. Su silueta básica le da a tu busto una modelación más redondeada. Sus copas están recubiertas en tul, que además de darle un toque de diseño diferenciado, se adhiere a la piel evitando los espacios entre la copa y el busto. Su elástico recubierto ancho y suave en la base, te da mayor soporte de busto para que te sientas más segura. No tiene arcos ni varillas laterales ¡es una prenda muy ligera y cómoda! Su espalda lisa en doble capa de tela, cuenta con un complemento espectacular en tul en la base de las cargaderas; las cuales son de aspecto invisible, ultrasuaves y cuentan con accesorios dorados que te encantarán. Es un bra muy versátil: úsalo en el día a día, para salir o en los momentos en los que quieras sentirte muy sexy.', 'Brasier ultraliviano con copas en espuma, sin arcos ni varillas.\r\nIdeal para mujeres de busto pequeño, mediano y grande.\r\nCopas recubiertas en un delicado tul que le agrega mucho estilo a la prenda y evita espacios entre la copa y el escote.\r\nEspalda lisa y suave en doble capa de tela, con detalle de tul en la base de las cargaderas.\r\nCargaderas graduables y fijas con accesorios dorados. Su proceso tecnológico las hace ultrasuaves, invisibles y livianas.\r\nAbrochadura de 3 ganchos y 4 niveles de ajuste.\r\nComposición: 81% poliamida, 19% elastano, composición forro: 88% poliamida, 12% elastano.', 306.24, 'si'),
(304, 'Brasier de soporte de espalda con cargaderas ajustables multi-support bra', '91029', 'mujer', 'leonisa', 'Este brasier te encantará porque tiene buen cubrimiento de sisa y espalda perfecto para disimular los rollitos de esta zona. Es una prenda fácil de poner gracias a su abrochadura frontal. Cuenta con soporte de espalda y cargaderas ultra cómodas graduables, ¡es la última versión de tu brasier multifuncional favorito! Úsalo para el día a día, para dormir, hacer deporte, mantener una postura más recta o como postquirúrgico. Está libre de elásticos en los hombros y cuenta con un elástico recubierto en tela lisa en la base del busto que le da mayor soporte. Es una prenda muy ligera y suave al tacto que se ajusta a tu piel sin dejar marcas. ¡Un brasier que te da más de lo que esperas en tu ropa interior!', 'Espalda en PowerSlim: ayuda a adoptar una mejor postura gracias a su espalda elaborada en un material de máximo ajuste y compresión.\r\nSoporte de espalda en forma de X: tu postura aún más recta con el refuerzo en forma de X, en tela termofusionada de última tecnología.\r\nMayor cubrimiento: moldea, estiliza y disimula los rollitos de la sisa y la espalda. Además, cuenta con cubrimiento alto del escote.\r\nBusto en su lugar: Corte diagonal en la parte delantera que ayuda a centrarlo.\r\nAbrochadura frontal con 6 broches y 2 niveles de ajuste: ¡Qué mejor que ponerse fácilmente un brasier!\r\nCargaderas ajustables y con PowerSlim interno: además de un innovador broche con 5 niveles de ajuste en forma de ojales, también tendrás mayor soporte del busto gracias a la capa interna de PowerSlim en las cargaderas.\r\nCopas extraíbles: para que lo uses como más te gusta, con una modelación más redondeada o más natural. Sus copas son suaves, ligeras y livianas.\r\nSuavidad al tacto: cada detalle es tan suave y diseñado para tu confort, que la prenda no se marcará en tu piel.\r\nComposición: 71.6% poliamida, 28.4% elastano, composición forro: 76.6% poliamida, 23.4% elastano.', 431.52, 'si'),
(306, 'BÓXER-UP LEO QUE AUMENTA Y LEVANTA LOS GLÚTEOS', '33280', 'hombre', 'leo', 'Bóxer largo Leo diseñado con cortes especiales que ayudan a levantar los glúteos. Está elaborado en su interior con PowerSlim?, material que ejerce una compresión suave en zonas específicas para darte excelente modelación y control en las piernas y la cadera. Tiene almohadillas removibles que te permiten aumentar el tamaño de los glúteos de forma natural. Por fuera está elaborado en DuraFit?, una tela lisa elástica de absoluta comodidad, frescura, suavidad y duración.', '\"Bóxer largo Leo ajustado\r\nCortes especiales que dan un realce natural\r\nAlmohadillas removibles para graduar el nivel de realce\r\nDoble capa: PowerSlim? y DuraFit? que ayudan a controlar en piernas y cadera\r\nElástico ancho en cintura\r\nExcelente modelación y ajuste perfecto\r\nComposición: poliamida 86.00%, elastano 14.00%, Composición Forro: poliamida 84.00%, elastano 16.00%.\"', 417.6, 'si'),
(307, 'Brastop de copas extraíbles light top comodidad total', '91031', 'mujer', 'leonisa', 'La comodidad y suavidad son los principales beneficios de este brasier tipo top, ¡las copas son tan livianas que no las vas a sentir! Está elaborado en DuraFit, una tela lisa y suave al contacto con la piel. Es copa completa, es decir que tiene buen cubrimiento de busto. Sus copas cuentan con doble capa de tela y funcionan como un bolsillo para poner las copas removibles (modelación más redondeada) o retirarlas (modelación más natural). No tiene arcos ni varillas laterales, para que te sientas muy cómoda las 24 horas del día. Su espalda ancha, con doble capa de tela tiene más ajuste estilizando esta zona. Sus cargaderas son fijas y graduables en espalda, para uso convencional o cruzado. Su elástico recubierto ancho y suave en la base del busto, te da mayor soporte.', 'Brastop ultra suave LIGHT TOP sin varillas ni arcos: comodidad total.\r\nCopas extraíbles para que lo uses como quieras.\r\nIdeal para mujeres con busto regular y grande.\r\nBuen cubrimiento del escote, sisa y espalda.\r\nSu espalda tiene gran capacidad de elongación por lo que se adapta a espaldas más anchas.\r\nAbrochadura con 3 posiciones y 4 niveles de ajuste.\r\nComposición: 82% poliamida, 18% elastano, composición forro: 80% poliamida, 20% elastano.', 361.92, 'si'),
(308, 'BÓXER LEO CORTO DE AJUSTE INTELIGENTE', '33296', 'hombre', 'leo', 'Bóxer corto ajustado. Elaborado en DuraFit® un material muy suave, ligero y de gran durabilidad, que se ajusta perfectamente al cuerpo, brindando mejor modelación y confort total. Sus costuras son ultraplanas, lo que las hace imperceptibles para que te sientas totalmente cómodo.', '\"Bóxer corto y ajustado elaborado en DuraFit\r\nSecado más rápido, ideal para uso diario\r\nCosturas ultraplanas e imperceptibles\r\nElástico metalizado y suave en la cintura\r\nComposición: poliamida 87%, elastano 13%\"', 174, 'si'),
(309, 'BÓXER BRIEF CON DOBLE REALCE', '33297', 'hombre', 'leo', 'Bóxer Leo ajustado. Elaborado en DuraFit? un material muy suave, ligero y de gran durabilidad, que se ajusta perfectamente al cuerpo, brindando mejor modelación y confort total. Diseñado con cortes especiales y costuras planas ergonómicas, que no se marcan.', '\"Bóxer corto Leo ajustado\r\nElástico metalizado y suave en la cintura\r\nElaborado en DuraFit? con tecnología de ajuste inteligente\r\nSecado más rápido\r\nCosturas planas ergonómicas\r\nComposición: poliamida 74.00%, elastano 16.00%, poliéster 10.00%, Composición Forro: poliamida 72.00%, elastano 28.00%.\"', 264.48, 'si'),
(310, 'Brasier ultracómodo con encaje en la base y espalda Comfy Bra', '91032', 'mujer', 'leonisa', 'La combinación perfecta entre copas lisas y encaje la encuentras en este brasier. Es ligero y ultracómodo: no cuenta con arcos, ni relleno en copas, ni varillas laterales. ', 'Detalles del producto:\r\n\r\n- Brasier de escote profundo, con toques de encaje en la base, laterales y espalda.\r\n- Ideal para mujeres de busto pequeño y mediano.\r\n- Copas lisas en espuma sin relleno ni realce interno.\r\n- Cómodo y liviano. Sin arcos ni varillas.\r\n- Cargaderas graduables y fijas.', 375.84, 'si'),
(311, 'BÓXER CORTO CON DOBLE REALCE', '33298', 'hombre', 'leo', 'Este bóxer brief Leo está elaborado en tela ultraliviana y suave para hacerte sentir máxima frescura durante todo el día. Su diseño en la parte delantera tiene malla interior recoge y da realce natural. Los elásticos son adheridos a la tela con tecnología de fusión, que te brinda una apariencia invisible. Además, en la parte trasera, tiene elásticos incorporados para realzar los glúteos con total comodidad.', '\"Bóxer Leo estilo brief\r\nElástico metalizado y suave en la cintura\r\nRealce delantero natural\r\nTela ultraliviana y malla interior transpirable y fresca\r\nRealce confortable de glúteos\r\nComposición: poliamida 75.00%, elastano 18.00%, poliéster 7.00%, Composición Forro: poliamida 72.00%, elastano 28.00%.\"\r\n\r\n', 278.4, 'si'),
(312, 'Brasier de escote profundo con realce suave sin arco perfect comfort bra', '91035', 'mujer', 'leonisa', 'Este brasier sin arcos, tiene copas en espuma suave y liviana con una tela interna que le dará soporte y sostenimiento a tu busto, realzándolo de forma natural como más te gusta. ¡Sexy y cómoda a la vez! Lo mejor de todo es que tiene un escote profundo y un detalle muy seductor en el centro, para que puedas usarlo con prendas escotadas.', '¡Sexy y cómoda! Con este brasier sin arcos de escote profundo con un detalle muy sexy entre las copas.\r\n¡Realce suave! Ideal para mujeres de busto pequeño y mediano.\r\nSoporte perfecto: tela interna en las copas que sostiene y realza el busto.\r\nSiéntete muy sexy: realza tu busto de forma natural.\r\nSiempre cómoda: cargaderas suaves y elásticas para uso convencional o cruzado.\r\nToque de tendencia: cortes redondeados en la espalda y en la base.\r\nAjuste perfecto: espalda con tres broches y cuatro niveles de ajuste.\r\nComposición: 73% poliamida, 27% elastano, composición forro: 65% poliamida, 35% elastano.\r\nSticker Nuevo	\r\nSi\r\n', 341.04, 'si'),
(313, 'BÓXER MEDIO IDEAL COMO DEPORTIVO', '33305', 'hombre', 'leo', 'Bóxer medio, elaborado en un material elástico que te hace sentir más cómodo y que te permite moverte libremente a la hora de hacer ejercicio. Además, cuenta con una amplia pinza de mayor capacidad y costuras planas que no tallan ni se marcan en la ropa.', '\"Bóxer medio, deportivo con gran cubrimiento en el área de las piernas\r\nElaborado en un material elástico, que permite mayor libertad de movimientos\r\nPinza de mayor capacidad que lo hace más cómodo\r\nElástico grueso y suave para un ajuste perfecto\r\nCosturas planas que no tallan y no se marcan en la ropa\r\nComposición: 50% poliamida, 43% poliéster, 7% elastano\"', 194.88, 'si'),
(314, 'Brasier doble realce con escote profundo en espalda sexy back', '91040', 'mujer', 'leonisa', 'Este brasier doble realce te encantará ya que podrás lucir un escote muy seductor. Sus copas tienen arcos y dos pads fijos de espuma, uno en la parte lateral y otro en la parte inferior, que centran, levantan y realzan el busto. El escote profundo cuenta con un ojal que deja ver tu piel y los accesorios dorados en el centro de las copas y las cargaderas, le dan un toque romántico y único. El elástico ancho en la base que ayudará a soportar tu busto cómodamente y al estar recubierto en encaje, lograrás un look muy seductor. ', 'Brasier de realce doble con escote profundo.\r\nIdeal para ti, si eres amante del realce y te gusta darle mayor volumen a tu busto.\r\nCopas con arco y dos pads de espuma que centran, levantan y realzan el busto.\r\nEl escote profundo con un ojal y los accesorios dorados en el centro de las copas y las cargaderas, le dan un toque sexy y único.\r\nCuenta con un elástico ancho en la base que ayudará a soportar tu busto cómodamente y además, al estar recubierto en encaje, lograrás un look muy seductor.\r\nCargaderas graduables y abrochadura con 3 posiciones y 4 niveles de ajuste.\r\nComposición: 86% poliamida, 14% elastano, composición forro: 84% poliamida, 16% elastano.', 501.12, 'si'),
(315, 'BÓXER MEDIO CON PINZA DE REALCE NATURAL', '33307', 'hombre', 'leo', 'Bóxer medio ideal para practicar deporte, debido a que está elaborado en DuraFit®: un material suave, ligero y cómodo. Además, es transpirable y de secado rápido, lo que lo hace muy práctico. Realce muy natural.', '\"Bóxer medio, ideal para practicar deportes\r\nElaborado en DuraFit®: un material suave, ligero y cómodo\r\nEs transpirable y de secado rápido para mayor practicidad\r\nPinza con realce natural\r\nCortes ergonómicos y malla transpirable\r\nElástico ancho y suave que no se enrolla\r\nComposición: poliamida 78%, elastano 16%, poliéster 6%\"', 243.6, 'si'),
(316, 'Brasier triple realce efecto 3d escote profundo', '91043', 'mujer', 'leonisa', 'una talla y media el volumen de tu busto, gracias a su espuma incorporada. Cuenta con elástico antideslizante en la parte interna superior de las copas, para evitar que se deslicen y para darte más seguridad al usarlo. Las varillas laterales le darán mayor ajuste y ayudan a que la prenda se mantenga en su lugar. Su escote es muy profundo, y es ideal para ti, si te gusta usar ropa más escotada o camisas abiertas en la parte delantera.', 'Brasier de escote profundo con arco interno.\r\nIdeal para busto pequeño y mediano y para usar con escotes profundos.\r\nCopa de triple realce que centra y levanta el busto aumentando hasta 1 1/2 talla de copa.\r\nElástico antideslizante en la parte interna de las copas que se adhiere al busto para evitar que se deslice y varillas suaves en los laterales para un mejor ajuste.\r\nEspalda ancha con un encaje tecnológico que revela un tejido de distintos colores.\r\nCargaderas graduables y removibles.\r\nAbrochadura doble y cuatro niveles de ajuste.\r\nComposición: 83.9% poliamida, 15.2% elastano, 0.9% silicona, composición forro: 84.6% poliamida, 15.4% elastano.', 410.64, 'si'),
(318, 'Brasier tipo top multiusos en algodón all in one bra', '91044', 'mujer', 'leonisa', 'Este brasier tipo top multiusos está elaborado en algodón elástico para brindarte frescura y mucha comodidad siendo ideal para usar las 24 horas del día. Sin arcos ni realce y con copas extraíbles que evitan que se marque el pezón y le dan una modelación más redondeada al busto.', 'Brasier tipo top elaborado en algodón sin arcos ni realces.\r\nRefuerzo en X en la espalda, en un material de compresión que facilita una mejor postura.\r\nPerfecto para mujeres de busto mediano, grande y muy grande. Banda elástica ancha en la base que da todo el soporte al peso del busto durante todo el día.\r\nCopas extraíbles que dan una modelación más redondeada y evitan que se marque el pezón. También puedes usarlo sin ellas para un look más natural.\r\nIdeal para usarlo las 24 horas del día, para dormir, hacer ejercicio o alguna actividad física; también como brasier de lactancia.\r\nPráctica abrochadura frontal de 8 posiciones y 2 niveles de ajuste.\r\nCargaderas ergonómicas abullonadas y con 3 niveles de ajuste.\r\nComposición: 44% poliéster, 24% algodón, 21% poliamida, 11% elastano, composición forro: 36% poliamida, 34% poliéster, 18% algodón, 12% elastano.', 417.6, 'si'),
(319, 'Brasier tipo top de copas extraíbles totalmente cómodo y liviano Flexi Brastop', '91048', 'mujer', 'leonisa', '<b>Por qué te encantará</b>\r\n\r\n- Brasier tipo top sin arcos ni varillas. Detalles en tul en escote, laterales y espalda.\r\n- Copas extraíbles para que lo uses como quieras.\r\n- Ideal para mujeres de busto pequeño, mediano y grande.\r\n- Alto cubrimiento en escote, sisa y espalda.\r\n- Su espalda tiene gran capacidad de elongación por lo que se adapta a espaldas más anchas.\r\n- Cargaderas fijas que se mantienen en su lugar.\r\n- Ideal para el día a día, para dormir, para los momentos de descanso o para looks más relajados.\r\n- Abrochadura con 3 posiciones y 4 niveles de ajuste.', 'El Flexi Brastop es un brasier tipo top elaborado en una tela lisa muy fresca y suave al tacto ¡y es una prenda que no necesita arcos para soportar tu busto! Cuenta con muy buen cubrimiento en la sisa y en la espalda para disimular los rollitos de esta zona y la base es ultraplana y sin costuras para que además de soportar tu busto te sientas totalmente cómoda. Sus copas cuentan con doble capa de tela y funcionan como un bolsillo para las copas removibles (incluidas). Úsalo con ellas para una modelación más redondeada y para que no se marque el pezón o sin ellas para una modelación natural. El detalle en tul con transparencia en el centro del escote, en los laterales y en la espalda, le da un toque sofisticado y fresco. Se convertirá en tu preferido para el uso diario, para dormir o para los momentos de descanso ¡el bra para las que amamos la comodidad!', 487.2, 'si'),
(320, 'Brasier sin arco ultracómodo de alto soporte y cubrimiento Everyday Bra', '91054', 'mujer', 'leonisa', 'El Everyday Bra es la combinación perfecta entre soporte, confort y cubrimiento. Su tacto es muy suave y su estructura muy liviana: lo amarás cuando te lo pongas. Cuenta con unas costuras sin arco que soportan tu busto con total comodidad, y las copas fijas en espuma le dan una modelación redondeada a tu busto y evitan que se marque el pezón. ', '<b>Detalles del producto:</b>\r\n\r\n- Brasier tipo brastop ideal para el uso diario.\r\n- Máximo soporte de busto con costuras en vez de arcos.\r\n- Alto cubrimiento en espalda y sisa: luce más estilizada.\r\n- Menos costuras para una apariencia más sutil.\r\n- Tacto ultrasuave. Estructura liviana.\r\n- Copas fijas en espuma para una modelación redondeada.\r\n- PowerSlim interno que genera compresión y ajuste.', 459.36, 'si'),
(321, 'Brasier tipo bustier ideal como strapless', '91060', 'mujer', 'leonisa', 'Este brasier strapless tipo bustier de espalda escotada es todo lo que tus hombros necesitan para lucir espectaculares con un vestido de novia o de fiesta. Su base es ancha y de muy buen cubrimiento, y sus varillas laterales y frontales le dan firmeza a la prenda y hacen que esta zona del cuerpo luzca más estilizada. Además, cuenta con una capa interna de nuestro material de compresión PowerSlim tanto en la espalda como en la base de las copas, que moldea más tu cuerpo.', 'Detalles del producto:\r\n\r\n- Brasier strapless tipo bustier de muy buen cubrimiento en la base del busto.\r\n- Copas de gran capacidad ideal para mujeres de busto mediano y grande.\r\n- Arcos internos que brindan un realce suave.\r\n- Doble capa: una interna en material de compresión PowerSlim   una tela con brillo externa para un toque sofisticado \r\n  y sexy.\r\n- Varillas laterales y frontales para un buen ajuste de la prenda.\r\n- Bandas siliconadas internas en copas y espalda para mayor ajuste. Uso strapless o convencional.', 417.6, 'si'),
(322, 'Brasier strapless ideal para busto pequeño y mediano Oh So Light', '91071', 'mujer', 'leonisa', 'Este será tu nuevo strapless favorito y justo lo que estabas esperando: un bra ligero y con pocas estructuras ideal para mostrar tus hombros o lucir tus vestidos y camisetas de tiritas. No cuenta con arcos bajo el busto ni relleno, y tiene un elástico antideslizante interno que le da más ajuste a la prenda y hace que se mantenga en su lugar.\r\n', 'etalles del producto:\r\n\r\n- Brasier strapless sin estructuras ni realce ¡hombros al aire!\r\n- Copas prehormadas en espuma suaves y livianas. Sin realce, ni estructuras ¡Todo lo que quieres!\r\n- Elástico siliconado interno en escote y espalda para mayor sujeción ¡Soporte perfecto para tus escotes!\r\n- PowerSlim interno en espalda: nuestro material de compresión que te brindará más ajuste.\r\n- ¡Fresco, ligero, cómodo y suave!', 327.12, 'si'),
(323, 'Brasier sin arco total comodidad Elemental Bra', '91076', 'mujer', 'leonisa', 'Este es el brasier que querrás elegir para el día a día ya que es cómodo, liviano y sus copas son muy suaves. No tiene arcos ni varillas, sin embargo su estructura interna soporta bien tu busto, además la profundidad en las copas lo convierte en un bra ideal para busto mediano y grande.', '- Brasier ideal para el día a día: comodidad y estructura ligera.\r\n- Sin arcos ni varillas.\r\n- Copas suaves y de buena capacidad: ideal para busto mediano y grande.\r\n- Elástico en la base que le da buen soporte al busto.\r\n- PowerSlim interno en la espalda: nuestro material de compresión que da mayor ajuste al bra estilizando esta zona de \r\n  tu cuerpo.\r\n- Copas lisas y suaves.', 431.52, 'si'),
(324, 'Brasier media copa con arco y base elaborada en encaje Sexy Essential', '91077', 'mujer', 'leonisa', '<b>Por qué te encantará</b>\r\n\r\n- Brasier con arco y base en encaje.\r\n- Ideal para busto mediano.\r\n- Arcos internos   elástico en base para buen soporte de busto.\r\n- Copas suaves sin realce.\r\n- Media copa ¡escote wow!\r\n- Cargaderas graduables removibles en espalda para uso convencional o cruzado.', '¿Tienes ganas de verte increíble? Este nuevo brasier con arco, copas lisas triangulares y base en encaje hará que te enamores a primera vista. Al tener arco le da muy buen soporte a tu busto y al ser media copa hace que tu escote se vea ¡increíble! Su base y espalda están elaborados en encaje para darle ese toque sexy que te gusta y que hace que digas ¡wow, amo cómo se me ve este bra! Sus cargaderas son graduables y removibles para que las uses de forma convencional o cruzada. Su espalda es delgada, sutil, de poco cubrimiento y cuenta con una abrochadura de 2 broches y 4 ajustes ¡antójate de este bra y quiérelo para siempre!', 313.2, 'si'),
(325, 'Bustier Siempre Sexy en encaje elástico', '91078', 'mujer', 'leonisa', '<b>Por qué te encantará</b>\r\n\r\n- Bustier elaborado en encaje elástico.\r\n- Ideal para busto pequeño y mediano.\r\n- Arcos internos para mayor soporte de busto.\r\n- Varillas laterales flexibles para darle un ajuste cómodo al brasier.\r\n- Sin espuma ni relleno en las copas (las copas cuentan con transparencias que permiten ver el pezón).\r\n- Espalda de buen cubrimiento.', 'Este brasier tipo bustier es perfecto para verte irresistible todos los días ¡te hará sentir imparable, romántica, segura y más sexy! Bustier quiere decir que tiene más cubrimiento en la base de busto, por lo cual es una silueta diferente a tus otros bra con un diseño más sofisticado. Tiene arcos que le dan mayor soporte a tu busto, y las varillas laterales cuentan con un diseño interno de espiral, es decir que son más flexibles y se adaptan a tu cuerpo. Su escote es profundo y las copas no tienen espuma ni relleno. Su encaje es muy suave al tacto y flexible y la transparencia que genera es espectacular. La espalda es de muy buen cubrimiento y cuenta con una abrochadura de 3 ganchos y 4 niveles de ajuste. Te contamos un secreto: ¡Cuando lo pruebes te enamorarás!', 285.36, 'si'),
(326, 'Daily Bralette cómodo y desestructurado', '91097', 'mujer', 'leonisa', '<b>Por qué te encantará</b>\r\n\r\n- Desestructurado, ligero, cómodo.\r\n- Bolsillo en tul interno para ponerle copas en espuma (no incluidas).\r\n- Cargaderas graduables para que las ajustes a tu cuerpo. No son removibles.\r\n- Las copas cuentan con transparencias (es posible que el pezón se marque).\r\n- Abrochadura de 2 broches, 4 ajustes.', 'Si te encanta sentirte libre y cómoda con la ropa interior que usas, este bralette es perfecto para usarlo todos los días. No tiene arcos ni varillas, es liviano, ligero y su material elástico se ajusta a tu cuerpo. Sus cargaderas no removibles, son ajustables para que las adaptes a tu contorno. Sus copas cuentan con doble capa de tela: encaje externo   tul interno que funciona como un bolsillo si quieres ponerle copas en espuma (no incluidas)', 299.28, 'si'),
(327, 'Boxer con mallas transpirables elaborado con PET reciclado', '33326', 'hombre', 'leo', 'Una vez pruebes este boxer deportivo no querrás ningún otro. Su diseño ergonómico te brindará mayor soporte, ajuste y comodidad cuando estés en movimiento, haciéndolo ideal para deportes de alto impacto. También es ideal para uso diario, post-quirúrgico y para dolores testiculares. Está elaborado a partir de fibras que provienen de botellas PET recicladas, por lo que estarás ayudando con el cuidado del medio ambiente con su compra. Cuenta con mallas transpirables en la zona de la entrepierna y la ingle que ayudan al paso del aire para una mayor sensación de frescura y ligereza.', 'Boxer medio elaborado con PET reciclado.\r\n2.5 botellas de PET reciclado = 1 boxer.\r\nDiseño ergonómico para un mayor ajuste y soporte.\r\nMaterial transpirable en la zona de la entrepierna y la ingle.\r\nDeporte, uso diario, post-quirúrgico, dolores testiculares.', 160.08, 'si'),
(328, 'Brasier triangular en algodón liviano y cómodo', '91099', 'mujer', 'leonisa', '- Copas triangulares de escote profundo.\r\n- Cómodo y fresco.\r\n- Elástico suave en base para más soporte.\r\n- Cargaderas graduables (uso convencional o cruzado).\r\n- Copas removibles.\r\n- 2 broches, 4 ajustes.', 'Si te gustan los brasieres en algodón que sean ligeros y livianos ¡encontraste lo que estabas buscando! Es tan cómodo y se ajusta tan bien al cuerpo que este bra triangular será tu nuevo favorito. Al estar elaborado con algodón, es muy fresco con tu piel, de tacto suave y perfecto para el día a día. Cuenta con copas removibles en espuma que le dan una modelación más redondeada a tu busto, o puedes quitarlas para que se vea más natural. El elástico suave en la base del busto le da más ajuste y soporte a la prenda. En la espalda cuenta con una abrochadura de 2 broches y 4 ajustes, y sus cargaderas graduables puedes usarlas de forma convencional o cruzada.', 320.16, 'si'),
(329, 'Brasier media copa con detalles de encaje en escote y espalda', '91142', 'mujer', 'leonisa', '- Con arco en la base. Sin varillas laterales.\r\n- Cubrimiento medio en copas. Espalda delgada de poco cubrimiento.\r\n- Su estructura brinda un realce medio de busto (sin realce incorporado en las copas).\r\n- Copas en espuma delgada y liviana.\r\n- Encaje elástico y suave al tacto en copas y espalda con bordes redondeados: el toque perfecto de seducción.', 'Este brasier está diseñado para sacar tu lado más sexy. Es media copa, es decir que tu escote muestra la parte superior del busto y esto sumado al encaje en las copas y la espalda ¡es irresistible! Sus copas están elaboradas en una espuma muy liviana y flexible que se adapta a tu busto. Aunque no tiene realce incorporado en las copas, sí le da un realce medio a tu busto gracias a los arcos y a su estructura. Sus cargaderas son graduables y removibles para uso convencional o cruzado. La seducción es tuya, ¡revélala con este bra!', 417.6, 'si'),
(330, 'Brasier sexy media copa con espalda en tul', '91145', 'mujer', 'leonisa', '- Copas en tul y encaje, sin copas en espuma: ¡Una combinación irresistible!\r\n- Arcos que soportan tu busto y también son protagonistas en tu escote.\r\n- Escote en V media copa: cubre lo necesario pero también resalta la forma superior de tu busto.\r\n- Cargaderas no removibles, graduables para que las ajustes a tu contorno.\r\n- Espalda en tul con detalles triangulares en encaje ¡seducción en cada centímetro del bra!', 'Las copas y la espalda de este brasier son para decir ¡sí a sentirme segura y sexy! El escote es profundo y cuenta con un detalle en tul que une las dos copas. La doble capa de tela en copas está elaborada con encaje externo y tul interno. La espalda también es en tul y tiene dos ojales antes de la abrochadura que dejan ver tu piel ¡el toque extra de seducción! Sus cargaderas son graduables para que las ajustes a tu contorno. Su abrochadura de 2 ganchos y 4 niveles de ajuste permite que lo adaptes a tu contorno.', 452.4, 'si'),
(331, 'Bustier en encaje con transparencias en la base y espalda', '91146', 'mujer', 'leonisa', '- Copas en encaje   escote profundo: la combinación perfecta de la seducción.\r\n- Laterales y espalda en tul: totalmente sexy.\r\n- Silueta bustier: más ancho en la base del busto.\r\n- Arcos internos que soportan tu busto y espuma fija interna en las copas.\r\n- Varillas laterales para más ajuste a tu piel.', 'La combinación del encaje, el tul y la silueta bustier (más ancho en la base) son los detalles de seducción y romanticismo de este brasier para derretirse y decir ¡lo quiero ya! Sus copas en encaje son de cubrimiento medio y tienen espuma suave fija al interior. La espalda con su estilo en U y su doble abrochadura es única y muy sexy. Es un bra que también puedes hacerlo parte de tus looks de exterior al usarlo con camisas o chaquetas abiertas o prendas con transparencias.\r\n\r\n', 570.72, 'si'),
(332, 'Brasier escote profundo en encaje y tul', '91147', 'mujer', 'leonisa', '- Sus copas son en tul y encaje, sin espuma interna ¡seducción pura!\r\n- Copas triangulares de escote profundo, una silueta infaltable en tu lencería.\r\n- Ojal decorativo en el centro del escote ¡irresistible!\r\n- Encaje suelto en espalda cerca a la abrochadura: un detalle de romanticismo puro.\r\n- Cargaderas delgadas, graduables y removibles en espalda.\r\n- Abrochadura en espalda de 2 broches, 4 niveles de ajuste.', 'Este brasier es todo lo que una prenda de seducción tiene que tener: copas con transparencias en encaje y tul, escote profundo y contraste de texturas. Es perfecto para esos momentos en los que no quieres dudar ni un segundo de tu poder y de lo sexy que puedes lucir con tu ropa interior. Los laterales y la espalda en encaje son el detalle extra de romanticismo y sutileza que tu bra necesita. Las cargaderas puedes usarlas de forma convencional o cruzada y su abrochadura es de 2 ganchos y 4 niveles de ajuste, para que lo adaptes a tu contorno.', 438.48, 'si'),
(333, 'Brasier en encaje sin arcos', '91149', 'mujer', 'leonisa', '- Copas en espuma delgada y suave.\r\n- Sin arcos ni varillas ¡total comodidad!\r\n- Elaborado en encaje ¡muéstralo con tus looks de exterior!\r\n- Elástico en la base para buen soporte.\r\n- Muéstralo con tus looks de exterior.', 'Te enamorarás de la comodidad y la modelación de este brasier. Se ajusta muy bien a tu cuerpo, es ligero y es perfecto para usarlo con transparencias y para hacerlo parte de tus looks de exterior. Sus copas en espuma son fijas, muy suaves al tacto y le dan una modelación redondeada a tu busto. Está libre de varillas y arcos y en la base del busto cuenta con un elástico que le da buen soporte al busto. Su abrochadura en la espalda cuenta con 3 broches con 4 niveles de ajuste, y sus cargaderas puedes usarlas de forma convencional o cruzada.\r\n\r\n', 570.72, 'si'),
(334, 'Bralette triangular en doble capa de tul: sexy touch', '981BYC', 'mujer', 'leonisa', 'Este bralette se adapta a diferentes volúmenes del busto gracias a la gran capacidad de ajuste y elongación que tienen sus copa en doble capa de tul. Al no tener arcos ni realces incorporados, es perfecto para quienes buscan una modelación natural y prendas más delicadas. Tiene muy buen cubrimiento en el escote y espalda. ', 'Brallete ideal para busto pequeño, regular y grande.\r\nBuen cubrimiento en escote, sisa y espalda.\r\nSin arcos ni estructuras.\r\nElástico ancho en la base.\r\nDoble capa de tul en copas.\r\nCargaderas anchas.\r\nAbrochadura de dos posiciones y cuatro niveles de ajuste.\r\nEncuentra dos copas en una misma talla.\r\nComposición: poliamida 74.00%, elastano 26.00%, Composición Forro: poliamida 87.00%, elastano 13.00%.', 208.8, 'si'),
(335, 'PANTY CLÁSICO DE GRAN CUBRIMIENTO EN GLÚTEOS', '11206L', 'mujer', 'leonisa', 'Este panty clásico alto en cintura y con excelente cubrimiento de los glúteos te proporciona comodidad, frescura y suavidad todos los días. Está elaborado en lycra y nylon que te garantizan la mejor calidad y tiene el refuerzo inferior en algodón para mayor higiene y frescura. ¡Es ideal para tu día a día!', '\"Panty de diseño clásico\r\nAlto en la cintura y piernas entradas para mayor comodidad\r\nGran cubrimiento de glúteos y cadera\r\nElaborado en lycra y nylon de excelente calidad\r\nRefuerzo inferior en algodón\"', 132.24, 'si'),
(336, 'Calzones Clásicos con Toques de Encaje', '118', 'mujer', 'leonisa', 'Son más altos en la cintura, con muy buen cubrimiento del abdomen, caderas y glúteos. Es un diseño que combina la comodidad con los detalles femeninos, están elaborados en tela elástica lisa DuraFit® que es suave con la piel. En la cintura cuentan con un elástico ancho en encaje SmartLace® que se adapta a tu cuerpo resaltando tu belleza, los elásticos de las piernas son más delgados y también están elaborados en este encaje. Este es un diseño pensado exclusivamente para darte el mayor confort posible.', 'Calzon clásico con muy buen cubrimiento\r\nElaborado en tela elástica lisa DuraFit® con excelente ajuste al cuerpo y suave con la piel\r\nEncaje elástico SmartLace® ancho en la cintura que te da una apariencia más delicada\r\nElásticos delgadoS planos en encaje en las piernas que no se marcan\r\nRefuerzo inferior 100% en algodón para mayor comodidad\r\nComposición de la tela: 79% Poliamida, 21% Elastano', 125.28, 'si'),
(337, 'PAQUETE X 3 PANTIES CLÁSICOS CON TOQUES DE ENCAJE', '118X3', 'mujer', 'leonisa', 'Paquete x 3 panties clásicos, son más altos en la cintura, con muy buen cubrimiento del abdomen, caderas y glúteos. Es un diseño que combina la comodidad con los detalles femeninos, están elaborados en tela elástica lisa DuraFit? que es suave con la piel.', 'En la cintura cuentan con un elástico ancho en encaje SmartLace? que se adapta a tu cuerpo resaltando tu belleza, los elásticos de las piernas son más delgados y también están elaborados en este encaje. Este es un diseño pensado exclusivamente para darte el mayor confort posible.\r\n\"3 panties clásicos con muy buen cubrimiento\r\nElaborados en tela elástica lisa DuraFit? con excelente ajuste al cuerpo y suave con la piel\r\nEncaje elástico SmartLace? ancho en la cintura que te da una apariencia más delicada\r\nElásticos delgados planos en encaje en las piernas que no se marcan\r\nRefuerzo inferior 100% en algodón para mayor comodidad\r\nComposición de la tela: 79% Poliamida, 21% Elastano\"', 341.04, 'si'),
(338, 'PANTY CLÁSICO DE CONTROL SUAVE EN ABDOMEN', '1214', 'mujer', 'leonisa', 'Este panty clásico de tiro alto es una excelente alternativa para mantener el abdomen controlado durante todo el día. Es cómodo, no tiene elásticos y las costuras son ultraplanas lo que evita que se marquen en tu ropa.', '-Panty clásico con excelente ajuste que controla suavemente el abdomen\r\n-Ideal para: uso diario y para usar con prendas ajustadas\r\n-Ausencia de elásticos en piernas y cintura para evitar que se marquen en la ropa\r\n-Costuras ultraplanas que son más suaves al contacto con la piel\r\n-Elaborado en algodón elástico que se ajusta al cuerpo cómodamente\r\n-Cortes especiales adelante y atrás, que enmarcan los glúteos y aplanan el abdomen\r\n-Refuerzo inferior 100% en algodón para que te sientas fresca durante todo el día\r\n-Composición: ALGODÓN 44.20%, elastano 29.60%, poliamida 26.20%.', 208.8, 'si'),
(339, 'Panty Clásico en Algodón de Control Suave', '1214A', 'mujer', 'leonisa', 'Este panty clásico de tiro alto es una excelente alternativa para mantener el abdomen controlado durante todo el día.', 'Panty clásico con excelente ajuste que controla suavemente el abdomen\r\nIdeal para: uso diario y para usar con prendas ajustadas\r\nAusencia de elásticos en piernas y cintura para evitar que se marquen en la ropa\r\nCosturas ultraplanas que son más suaves al contacto con la piel\r\nElaborado en algodón elástico que se ajusta al cuerpo cómodamente\r\nCortes especiales adelante y atrás, que enmarcan los glúteos y aplanan el abdomen\r\nRefuerzo inferior 100% en algodón para que te sientas fresca durante todo el día\r\nComposición: ALGODÓN 44.20%, elastano 29.60%, poliamida 26.20%.', 208.8, 'si'),
(340, 'PAQUETE X 2 PANTIES CLÁSICOS DE CONTROL SUAVE EN ABDOMEN', '1214X2', 'mujer', 'leonisa', 'Estos panties son una excelente alternativa para mantener el abdomen controlado durante todo el día. Son cómodos, no tienen elásticos y las costuras son ultraplanas, lo que evita que se marquen en tu ropa.', '\"Paquete x 2 panties clásicos con control moderado\r\nSin elásticos en pierna ni cintura, para evitar que se marquen en la ropa\r\nElaborado en DuraFit®, con costuras ultraplanas y suaves al contacto con la piel\r\nCortes especiales que enmarcan los glúteos y aplanan el abdomen\r\nRefuerzo inferior 100% en algodón\r\nComposición: poliamida 79.10%, elastano 20.90%.\"', 167.04, 'si'),
(341, 'Pantie Clásico con Excelente Cubrimiento', '1238', 'mujer', 'leonisa', 'Este pantie clásico te ofrece la comodidad que estás buscando, con cubrimiento total de la cola y del abdomen medio-bajo. Está elaborado en algodón y poliéster que te brindan muy buen ajuste al cuerpo y con un grabado de rayas que les agrega mucho estilo.', 'Total cubrimiento de la cola y abdomen medio-bajo.\r\nElaborados con algodón/poliéster grabado con rayas en delantero y trasero, un diseño más moderno.\r\nElásticos en las piernas y la cintura elaborados en nylon/spandex para ofrecer un ajuste perfecto.\r\nEstos panties son ideales para uso diario, brindan comodidad y frescura durante todo el día.\r\nRefuerzo inferior 100% en algodón.\r\nComposición de la tela: poliéster 56.00%, ALGODÓN 30.00%, poliamida 12.00%, elastano 2.00%, Composición Forro: poliéster 65.00%, ALGODÓN 35.00%.\r\n', 111.36, 'si'),
(342, 'PAQUETE X 3 PANTIES CLÁSICOS CON EXCELENTE CUBRIMIENTO', '1238x3', 'mujer', 'leonisa', 'Este paquete de 3 panties clásicos te ofrece la comodidad que estás buscando, con cubrimiento total de la cola y del abdomen medio-bajo. Están elaborados en algodón y poliéster que te brindan muy buen ajuste al cuerpo y con un grabado de rayas que les agrega mucho estilo. Los elásticos son suaves y se ajustan perfectamente a tu cuerpo brindándote una modelación ideal para que te sientas segura, fresca y muy cómoda.', '-Paquete x 3 panties clásicos\r\n-Total cubrimiento de la cola y abdomen medio-bajo\r\n-Elaborados con algodón/poliéster grabado con rayas en delantero y trasero, un diseño más moderno\r\n-Elásticos en las piernas y la cintura elaborados en nylon/spandex para ofrecer un ajuste perfecto\r\n-Estos panties son ideales para uso diario, brindan comodidad y frescura durante todo el día\r\n-Refuerzo inferior 100% en algodón', 292.32, 'si'),
(343, 'PANTY CLÁSICO INVISIBLE CON AJUSTE PERFECTO', '12499', 'mujer', 'leonisa', '¡Todas tenemos esos días en los que no podemos parar ni un segundo! Y para esos momentos, este panty será tu mejor aliado. Controla suavemente tu abdomen y moldea tus glúteos, gracias a un sutil corte trasero.', 'Controla suavemente tu abdomen con este lindo panty clásico\r\nSiéntete cómoda siempre, ya que es alto en pierna y cintura, para darte más comodidad\r\n¡No se marca en tu ropa! Termofusionado en pierna, que reemplaza los elásticos\r\nRefuerzo 100% en algodón, para que te sientas fresca todo el tiempo\r\nComposición: poliamida 62%, elastano 38%', 236.64, 'si'),
(344, 'Pantie Clásico con Máximo Cubrimiento', '1255', 'mujer', 'leonisa', 'pantie clásico que te ofrecen cubrimiento total de la cola y del abdomen medio-bajo. Está elaborado con nylon y lycra que te garantizan un ajuste perfecto al cuerpo y la modelación que siempre buscas en tus prendas íntimas. Puedes usarlos a diario y disfrutar de la gran comodidad y frescura que sólo estos panties te pueden dar.\r\n', 'Cubrimiento total de la cola y del abdomen medio-bajo.\r\nEstán elaborados con hilos en nylon y lycra que te ofrecen un ajuste perfecto al cuerpo.\r\nTe garantiza perfecta adaptación, comodidad y excelente modelación.\r\nEstos panties son ideales para uso diario, brindan comodidad y frescura durante todo el día.Refuerzo inferior 100% en algodón.\r\nComposición de la tela: poliamida 80.00%, elastano 20.00%.\r\n', 104.4, 'si'),
(345, 'PAQUETE X4 PANTIES CLÁSICOS CON MAXIMO CUBRIMIENTO', '1255X4', 'mujer', 'leonisa', 'Paquete x 4 panties clásicos que te ofrecen cubrimiento total de la cola y del abdomen medio-bajo. Están elaborados con nylon y lycra que te garantizan un ajuste perfecto al cuerpo y la modelación que siempre buscas en tus prendas íntimas. Puedes usarlos a diario y disfrutar de la gran comodidad y frescura que sólo estos panties te pueden dar.', '\"Paquete x 4 panties clásicos\r\nCubrimiento total de los glúteos y del abdomen medio bajo\r\nElaborados con hilos elásticos en nylon que se ajustan perfectamente al cuerpo\r\nIdeales para uso diario, brindan comodidad y frescura durante todo el día\r\nRefuerzo inferior 100% en algodón\r\nComposición: poliamida 80.00%, elastano 20.00%.\"', 361.92, 'si'),
(346, 'PANTY CLÁSICO PARA EL EMBARAZO', '12594', 'mujer', 'leonisa', 'Este panty clásico fue creado exclusivamente para mujeres embarazadas, elaborado en DuraFit®, una tela suave, fresca, cómoda y resistente, con un refuerzo externo que sostiene el abdomen con comodidad, sus elásticos son suaves y sus cortes laterales no tallan.', 'Panty clásico ideal para los meses más avanzados del embarazo.\r\nElaborado en DuraFit® para tu comodidad y seguridad.\r\nRefuerzo externo que ayuda sostener el abdomen.\r\nAyuda a prevenir dolores de espalda causados por el peso.\r\nElástico suave que ayuda a sostener la prenda.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición de la tela: 86.6% Poliamida, 13.4% Elastano.', 208.8, 'si'),
(348, 'Tanga de Algodón con Refuerzo en Abdomen', '12632', 'mujer', 'leonisa', 'tanga elaborada 100% en algodón elástico, con refuerzo que controla suavemente tu abdomen y costuras ultraplanas que no se marcan en tu piel ni en tu ropa. Te ofrecen máxima comodidad para que te sientas perfecta durante todo el día.\r\n', 'Elaborada con algodón elástico.\r\nElásticos en microfibra y costuras ultraplanas que no marcan tu piel.\r\nRefuerzo en abdomen que te brinda un control suave.\r\nCubrimiento medio de cadera.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición de la tela: ALGODÓN 64.00%, poliéster 17.00%, elastano 13.00%, poliamida 6.00%.\r\n', 125.28, 'si'),
(349, 'PANTY TIPO BIKINI EN ALGODON CON TOTAL CUBRIMIENTO', '12633', 'mujer', 'leonisa', 'Panty tipo bikini, elaborado en algodón elástico que se ajusta perfectamente a tu figura, con costuras ultraplanas que no marcan la piel y con un excelente cubrimiento de cadera para tu comodidad.', 'Detalles de la prenda\r\n\r\nPanty estilo bikini\r\nElaborado con algodón elástico.\r\nElásticos en microfibra y costuras ultraplana que no se marcan ni tallan tu piel\r\nPanty medio alto en cintura y con buen cubrimiento de cadera\r\nCostura en el centro del trasero que enmarca la cadera\r\nRefuerzo inferior 100% en algodón para mayor comodidad\r\nComposición: ALGODÓN 67.00%, poliéster 15.00%, elastano 12.00%, poliamida 6.00%.', 153.12, 'si'),
(350, 'Paquete x 3 panties tipo Bikini en Algodón con Total Cubrimiento', '12633x3', 'mujer', 'leonisa', 'Paquete x 3 panties tipo bikini, elaborados en algodón elástico que se ajusta perfectamente a tu figura, con costuras ultraplanas que no marcan la piel y con un excelente cubrimiento de cadera para tu comodidad.\r\n', 'Paquete de 3 panties estilo bikini.\r\nElaborados con algodón elástico.\r\nElásticos en microfibra y costuras ultraplanas que no se marcan ni tallan tu piel.\r\nPanty medio alto en cintura y con buen cubrimiento de cadera.\r\nCostura en el centro del trasero que enmarca la cadera.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición de la tela: ALGODÓN 67.00%, poliéster 15.00%, elastano 12.00%, poliamida 6.00%.\r\n', 431.52, 'si'),
(351, 'Bóxer corto con algodón elástico', '12634', 'mujer', 'leonisa', 'Bóxer corto ultracómodo ideal para el uso diario. Es una silueta de tiro alto y cuenta con muy buen cubrimiento en el abdomen y en los glúteos, dándote una sensación de mayor seguridad y que todo está en su lugar. Sin elásticos en piernas y con buena capacidad de ajuste. El corte en el centro de los glúteos hace que tengan una modelación más redondeada. Su refuerzo interno 100% en algodón te da mayor frescura y suavidad al tacto.', 'Detalles del producto:\r\n\r\n- Panty silueta bóxer corto.\r\n- Elaborado con algodón elástico que te da máximo ajuste y frescura.\r\n- Sin elásticos en pierna para más comodidad y suavidad.\r\n- Tiro alto.\r\n- Buen cubrimiento en abdomen y glúteos.\r\n- Refuerzo inferior 100% en algodón.\r\n- Ideal para el día a día o para dormir.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 83% algodón, 10% elastano, 7% poliamida.', 160.08, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(352, 'Paquete x 3 bóxers cortos con algodón elástico', '12634x3', 'mujer', 'leonisa', 'Paquete x 3 bóxers cortos ultracómodos ideales para el uso diario. Es una silueta de tiro alto y cuenta con muy buen cubrimiento en el abdomen y en los glúteos, dándote una sensación de mayor seguridad y que todo está en su lugar. Sin elásticos en piernas y con buena capacidad de ajuste. El corte en el centro de los glúteos hace que tengan una modelación más redondeada. Su refuerzo interno 100% en algodón te da mayor frescura y suavidad al tacto.', 'Detalles del producto:\r\n\r\n- Paquete x 3 panties silueta bóxer corto.\r\n- Elaborados con algodón elástico que te da máximo ajuste y frescura.\r\n- Sin elásticos en pierna para más comodidad y suavidad.\r\n- Tiro alto.\r\n- Buen cubrimiento en abdomen y glúteos.\r\n- Refuerzo inferior 100% en algodón.\r\n- Ideal para el día a día o para dormir.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 83% algodón, 10% elastano, 7% poliamida.', 431.52, 'si'),
(353, 'BÓXER DE AJUSTE PERFECTO', '12640', 'mujer', 'leonisa', 'Panty tipo bóxer corto en DuraFit® que brinda ajuste perfecto y máxima comodidad. Su diseño sin marcas moldea la silueta con suavidad y se adapta al cuerpo para uso diario.', 'Panty Bóxer Corto en DuraFit®\r\n• Composición: 77% poliamida – 23% elastano\r\n• Ajuste ergonómico que se adapta al cuerpo con efecto moldeador\r\n• Diseño sin costuras laterales para evitar marcas bajo la ropa\r\n• Costuras planas cubiertas en cintura y piernas que no tallan\r\n• Tela DuraFit® suave, elástica y de alta durabilidad\r\n• Sensación de comodidad y libertad de movimiento durante todo el día\r\n• Refuerzo inferior 100% en algodón para mayor frescura e higiene', 194.88, 'si'),
(354, 'PANTY DE CONTROL SUAVE Y AJUSTE PERFECTO', '12657', 'mujer', 'leonisa', 'Panty clásico alto en cintura de control suave, diseñado especialmente para cubrir todas tus necesidades en cuanto a comodidad, seguridad y modelación. Panty con gran ajuste y máximo confort. Elaborado en DuraFit®.', 'Panty clásico alto en la cintura.\r\nControl suave de abdomen medio y bajo.\r\nBandas elásticas al rededor de la cintura y las piernas con excelente ajuste.\r\nCosturas ultraplanas que lo hacen imperceptible debajo de la ropa.\r\nPanty clásico con apariencia de tanga brasilera.\r\nTrasero con corte y leve recogido que ayuda a realzar el derriere.\r\nEfecto invisible: no se marca, ni te talla.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición de la tela: 79% Poliamida, 21% Elastano.', 243.6, 'si'),
(355, 'Bóxer con Excelente Cubrimiento de Cola y Abdomen', '12669', 'mujer', 'leonisa', 'Bóxer con buen cubrimiento para que te sientas cómoda y segura, están elaborados en algodón elástico que te brinda máximo confort y además es mucho más suave con la piel. Éste es un diseño pensado exclusivamente para darte el mayor confort posible.', 'Elaborado con algodón elástico\r\nCubrimiento total de la cola y el abdomen\r\nAjuste perfecto al cuerpo\r\nSin elásticos y con costuras planas que no se marcan ni tallan\r\nRefuerzo inferior 100% en algodón para mayor comodidad\r\nComposición de la tela: 90% Algodón, 10% Elastano', 180.96, 'si'),
(356, 'PAQUETE X 3 BÓXERS CON EXCELENTE CUBRIMIENTO DE COLA Y ABDOMEN', '12669x3', 'mujer', 'leonisa', 'Paquete de 3 bóxers con buen cubrimiento para que te sientas cómoda y segura, están elaborados en algodón elástico que te brinda máximo confort y además es mucho más suave con la piel. Éste es un diseño pensado exclusivamente para darte el mayor confort posible.', 'Paquete de 3 panties estilo bóxer\r\nElaborado con algodón elástico\r\nCubrimiento total de la cola y el abdomen\r\nAjuste perfecto al cuerpo\r\nSin elásticos y con costuras planas que no se marcan ni tallan\r\nRefuerzo inferior 100% en algodón para mayor comodidad\r\nComposición de la tela: 90% Algodón, 10% Elastano', 501.12, 'si'),
(357, ' BRASILERAS DE ALGODÓN COMODIDAD EXTREMA', '12677x3', 'mujer', 'leonisa', 'Paquete de 3 panties brasileras, en algodón elástico que se ajustan perfectamente a tu figura, te mantienen fresca y cómoda durante todo el día. Sus costuras ultraplanas te brindan un contacto suave con la piel.\r\n\r\n', 'Paquete de 3 panties estilo brasilera.\r\nElaboradas con algodón elástico.\r\nElásticos y costuras ultraplanas que no se marcan ni tallan.\r\nDiseño semi-descaderado para que las uses con tu ropa favorita.\r\nRefuerzo inferior 100% en algodón para mayor comodidad.\r\nComposición de la tela: 66% Algodón, 24% Poliamida, 10% Elastano.', 229.68, 'si'),
(358, 'PAQUETE X 3 BRASILERAS DESCADERADAS', '12682x3', 'mujer', 'leonisa', 'Paquete por 3 tangas brasileras descaderadas, elaboradas en DuraFit® y con elásticos ultraplanos que no se marcan en la ropa ni maltratan la piel. Estas prendas te garantizan el mejor ajuste, comodidad y modelación para que te sientas mucho más segura. Además, son invisibles debajo de tu ropa.\r\n\r\n', 'Paquete por 3 tangas brasileras descaderadas, elaboradas en DuraFit® y con elásticos ultraplanos que no se marcan en la ropa ni maltratan la piel. Estas prendas te garantizan el mejor ajuste, comodidad y modelación para que te sientas mucho más segura. Además, son invisibles debajo de tu ropa.\r\n\r\n', 250.56, 'si'),
(359, 'HIPSTER INVISIBLE CON BUEN CUBRIMIENTO', '12686', 'mujer', 'leonisa', 'Panty hipster en microfibra suave que brinda ajuste perfecto y excelente cubrimiento. Su diseño sin marcas moldea la figura con comodidad y frescura durante todo el día.', 'Panty Hipster de Microfibra Suave\r\n• Composición: 90% poliamida – 10% elastano\r\n• Excelente cubrimiento de cadera para mayor seguridad y confort\r\n• Costuras ultraplanas que evitan roces y marcas en la piel\r\n• Diseño sin costura trasera para efecto invisible bajo la ropa\r\n• Tela de microfibra suave, ligera y fresca al tacto\r\n• Ajuste que se adapta al cuerpo brindando modelación natural\r\n• Refuerzo inferior 100% en algodón para mayor higiene y comodidad', 153.12, 'si'),
(360, 'PANTY CLÁSICO DE REALCE - MAGIC BENEFIT', '12688', 'mujer', 'leonisa', 'Panty de realce que aumenta el tamaño de tu derriere por medio de unas almohadillas prehormadas removibles y le da una forma natural a la cola. Costuras y elásticos ultraplanos que no se marcan y se ajustan perfectamente a tu figura. Elaborado en DuraFit® para mayor frescura y durabilidad.', 'Panty hipster levantacolas.\r\nAlmohadillas prehormadas que aumentan el tamaño de la cola.\r\nCosturas y elásticos ultraplanos y suaves.\r\nElaborado en DuraFit®.\r\nAlmohadillas removibles para facilitar el lavado del panty.\r\nRefuerzo inferior 100% en algodón para mayor comodidad y frescura.\r\nComposición de la tela: 78% Poliamida, 22% Elastano.', 375.84, 'si'),
(361, 'PAQUETE X 5 PANTALONCILLOS CLÁSICOS EN ALGODON', '927X5', 'hombre', 'leo', 'Paquete de cinco pantaloncillos de corte clásico, con suave elástico que rodea el torso y ajusta las piernas, para lograr un ajuste perfecto. Dos cortes ergonómicos en la parte frontal, crean una silueta en donde la pinza es muy cómoda y de gran capacidad.', '\"Paquete por cinco pantaloncillos clásicos para una silueta muy masculina\r\nCortes ergonómicos para mayor comodidad en la pinza\r\nElástico en cintura y piernas\r\nAbertura para mayor comodidad\r\nComposición: ALGODÓN 100.00%.\"', 452.4, 'si'),
(362, 'Pantalón largo en algodón cómodo y funcional para hombre', '33334', 'hombre', 'leo', 'Este pantalón largo multiusos elaborado en algodón y tejido plano, es ideal para complementar tu pijama o simplemente para estar cómodo en casa. Disfruta del confort que tus días y noches necesitan con este pantalón. Su tacto suave con tu piel te hará sentir ligero y fresco, y su buen cubrimiento hará que no sientas frío en ningún momento. Su abertura delantera facilita su uso, además, su elástico recubierto en la pretina cuenta con un cordón para que lo ajustes a tu cintura. ¡Tienes que tenerlo porque este pantalón será el perfecto para disfrutar tus momentos de descanso!', 'Pantalón largo en algodón de máxima comodidad.\r\nAbertura delantera que facilita su uso diario.\r\nPrenda ligera y de tacto suave.\r\nElástico recubierto en cintura y cordón para ajustarlo.\r\nEs tan cómodo que lo puedes usar para dormir o estar en casa en tus momentos de descanso.\r\nBotón decorativo en frente.\r\nComposición: 100% algodón', 361.92, 'si'),
(363, 'Legging de tiro alto de control en abdomen y piernas', '12901', 'mujer', 'leonisa', 'Cuando decimos que este legging es de tiro alto, ¡lo decimos de verdad! Está elaborado en microfibra, un material suave que deja respirar tu piel y que al mismo tiempo controla desde tu abdomen hasta tus tobillos, ayudando a disimular la celulitis y a estilizar tus piernas.', '- Legging de tiro alto elaborado en microfibra una capa interna de PowerSlim para estilizar más tu figura.\r\n- Control fuerte en abdomen medio y bajo.\r\n- Control moderado en abdomen alto y piernas.\r\n- Material transpirable para que te sientas más fresca.\r\n- Usos recomendados: como prenda de control, para el día a día con tu ropa exterior, recuperación postparto o para\r\nhacer deporte.\r\n- Elástico interno antideslizante en la base que facilita que la prenda permanezca en su luga', 410.64, 'si'),
(364, 'Legging deportivo tiro alto de control en abdomen y piernas', '195498', 'mujer', 'leonisa', 'Legging deportivo tiro alto de control en abdomen y piernas', 'Leggings deportivos de control, doble capa en pretina para más compresión.\r\nControl fuerte en abdomen medio y bajo. Control moderado en muslos.\r\nMás poder en tus rutinas: tecnología Copper con iones de cobre que eliminan las bacterias que causan malos olores.\r\nInnovación en cada paso que das: los iones de cobre ayudan a mantener tu temperatura corporal y a combatir los radicales libres que causan el envejecimiento en la piel.\r\nTiro alto perfecto crear el efecto de una silueta más definida y para sentir todo en su lugar.\r\nElaborado en DuraFit, un material suave al tacto que se ajusta a tu cuerpo.\r\nMaterial transpirable y de secado rápido, para una sensación de frescura todo el tiempo.\r\nPerfecto para actividades de alto impacto. Úsalo también como legging con tu ropa exterior.\r\nComposición: 74% poliamida, 26% elastano, composición forro: 74% poliamida, 26% elastano.', 278.4, 'no'),
(365, 'Leggings de control con transparencia', '195509', 'mujer', 'leonisa', 'Seguridad, comodidad y frescura, este legging lo tiene para ti.\r\n\r\n\r\n', 'Pretina con doble capa de DuraFit que brinda mayor control en abdomen y cintura.\r\nMallas alrededor de las rodillas que facilitan la transpiraci\r\n\r\n', 382.8, 'si'),
(366, 'Legging deportivo tiro alto sin costuras con fajón doble en cintura y mallas transpirables', '195550N', 'mujer', 'leonisa', 'Legging deportivo de control fuerte en el abdomen medio y control suave en los muslos. Es de tiro alto y cuenta con doble capa de tela en la cintura, perfecto para crear el efecto de una silueta más definida. Al estar elaborado en nuestra tecnología SkinFuse sin costuras, te sentirás tan cómoda como en una segunda piel. Es ideal para actividades de impacto medio como yoga y pilates, pues no lo sentirás mientras realizas tus posturas. Su material de secado rápido y el detalle en mallas transpirables en la parte baja de las piernas, lo convierten en una prenda muy fresca, perfecta para las rutinas más exigentes, además cuenta con un diseño ergonómico que realza los glúteos. Tienes todo en una sola prenda: comodidad, frescura y la tecnología para moldear tus curvas.', '- Legging deportivo con doble capa en cintura que afina tus curvas.\r\n- Control fuerte en abdomen medio y control suave en los muslos.\r\n- Tecnología seamless SkinFuse: sin costuras, mayor ajuste al cuerpo, ligereza y libertad de\r\nmovimiento.\r\n- Tiro alto perfecto para controlar el abdomen medio, bajo y cintura.\r\n- Material de secado rápido y mallas transpirables en piernas: siempre fresca.\r\n- Diseño ergonómico que realza los glúteos.\r\n- Producido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 95% poliamida, 5% elastano.', 208.8, 'si'),
(367, 'Legging deportivo de tiro alto sin costuras con fajón doble tela en cintura y mallas transpirables.', '195550P', 'mujer', 'leonisa', 'Legging deportivo de silueta ajustada, con control fuerte en el abdomen medio y control suave en los muslos. Es de tiro alto y cuenta con doble capa de tela en la cintura.', 'Legging deportivo con doble capa en cintura que afina tus curvas.\r\nControl fuerte en abdomen medio y control suave en muslos.\r\n\r\n', 222.72, 'si'),
(368, 'Legging deportivo de control y tiro alto en tecnología seamless sin costuras', '195572', 'mujer', 'leonisa', 'Legging deportivo elaborado con nuestra tecnología SkinFuse sin costuras, perfecto para que no lo sientas mientras realizas posturas exigentes en actividades de impacto medio como yoga o pilates. Al ser de tiro alto y tener doble capa en la cintura lucirás más estilizada: cuenta con control fuerte en el abdomen medio y control moderado en los muslos. Su material de secado rápido te hará sentir fresca y cómoda todo el tiempo. Úsalo para trotar, bailar, ir al gimnasio, hacer yoga o simplemente para cuando quieras sentirte cómoda en el día a día. Al entrenar con este legging te sentirás tan cómoda como con una segunda piel.', 'Legging deportivo elaborado con nuestra tecnología SkinFuse sin costuras, perfecto para que no lo sientas mientras realizas posturas exigentes en actividades de impacto medio como yoga o pilates. Al ser de tiro alto y tener doble capa en la cintura lucirás más estilizada: cuenta con control fuerte en el abdomen medio y control moderado en los muslos. Su material de secado rápido te hará sentir fresca y cómoda todo el tiempo. Úsalo para trotar, bailar, ir al gimnasio, hacer yoga o simplemente para cuando quieras sentirte cómoda en el día a día. Al entrenar con este legging te sentirás tan cómoda como con una segunda piel.', 243.6, 'si'),
(369, 'Legging deportivo tiro alto con corte en gl', '195607', 'mujer', 'leonisa', ' Tiro alto que estiliza visualmente la figura.\r\n- Corte en glúteos tipo corazón para que luzcan realzados y redondeados.\r\n- Sin costura en parte frontal: no se marca en la entrepierna.\r\n- Secado rápido: fresca y seca todo el tiempo.\r\n- Composición: 83% poliéster, 17% elastano.', 'Este legging de tiro alto estiliza tu cuerpo visualmente ya que el fajón en la pretina, disimula tu abdomen bajo. En los glúteos tiene un corte tipo corazón que les da un efecto más realzado y redondeado y en la parte frontal no tiene costura frontal vertical para que no se marque en la entrepierna ¡Un buen legging deportivo hace la diferencia en tu outfit! Si horma bien en tu cadera, en tu abdomen y en tus piernas no solo te dará toda la comodidad y libertad de movimiento que necesitas; también te hará verte increíble y sentirte muy motivada para dar siempre lo mejor de ti.', 243.6, 'si'),
(370, 'BRASILERA INVISIBLE CON TELA INTELIGENTE', '12720', 'mujer', 'leonisa', 'Brasilera invisible en DuraFit®, sin costuras ni elásticos, ultra suave y ligera. Se adapta al cuerpo sin marcar ni enrollarse. Ideal para máxima comodidad y efecto segunda piel en el día a día.', 'Panty Brasilera Invisible DuraFit® Sin Costuras\r\n• Composición: 58% poliamida – 42% elastano / refuerzo 100% algodón\r\n• Tecnología DuraFit® que aporta ajuste, frescura y mayor durabilidad\r\n• Diseño sin costuras ni elásticos para un efecto invisible total\r\n• Tela inteligente que no se enrolla ni se marca en la piel o la ropa\r\n• Ajuste tipo segunda piel que se adapta al cuerpo con suavidad\r\n• Refuerzo inferior en algodón que brinda mayor higiene y confort\r\n• Sensación ultra ligera, suave y de libertad de movimiento\r\n• Ideal para uso diario y prendas ajustadas por su acabado invisible', 187.92, 'si'),
(371, 'BÓXER LARGO LEO EN ALGODÓN AJUSTADO', '33253', 'hombre', 'leo', 'Bóxer con gran cubrimiento de las piernas, se ajusta perfectamente dándote máximo confort. Está elaborado en algodón spandex para que sientas mayor frescura. Tiene buena capacidad en la parte delantera y te da un realce natural.', ' Bóxer largo Leo\r\n- Mayor cubrimiento de las piernas y gran ajuste al cuerpo\r\n- Elaborados en algodón/spandex para granatizarte máxima comodidad y frescura\r\n- Buena capacidad y realce natural en la parte delantera\r\n- Suave elástico que se ajusta en la cintura sin dejar marcas\r\n- Costuras planas que no tallan y evitan que se marquen en la ropa\r\n- Diseño anatómico que se adapta a tu cuerpo\r\n- Composición de la tela: 52% Poliéster, 28% Algodón, 12% Poliamida, 8% Elastano\r\n\r\n', 215.76, 'si'),
(372, 'BRIEF TECNOLOGIA ADVANCED', '33278n', 'hombre', 'leo', 'Brief elaborado en DuraFit? que te ofrece máxima comodidad, transpiración, suavidad, perfecto ajuste y durabilidad muy superiores para usarlo en cualquier ocasión. Con este bóxer tendrás una mejor transpiración y 100% ajuste perfecto. Elaborado con materiales de alta calidad para tu confort.', '- Brief ajustado de secado rápido\r\n- Elaborado en tela tecnológica DuraFit?\r\n- Tacto suave y fresco\r\n- Suave elástico ancho metalizado en cintura\r\n- Pinza delantera que te brinda realce natural\r\n- Composición: poliamida 88.00%, elastano 12.00%, Composición Forro: poliamida 88.00%, elastano 12.00%.', 417.6, 'si'),
(373, 'Bóxer largo deportivo de máxima frescura en microfibra', '33290N', 'hombre', 'leo', '- Bóxer ideal para actividades deportivas como jugar futbol, baloncesto, trotar, correr, entrenar en el gimnasio.\r\n- Silueta: bóxer largo.\r\n- Con FitTech: nuestro material poroso, transpirable, de peso liviano y total suavidad.\r\n- Tecnología de secado rápido y transpirable.\r\n- Elástico ancho y suave en cintura que no se enrolla.', 'Lleva tus entrenamientos a otro nivel con este bóxer largo de mayor cubrimiento que evita el roce entre las piernas. Está elaborado con FitTech, nuestro material exclusivo poroso y de tacto ultrasuave que al ser ligero y transpirable hace que olvides que llevas un bóxer puesto. Además, su tecnología de secado rápido, te hará sentir seco en todo momento. Sus costuras ultraplanas no se marcarán en tu piel; gracias a su largo en piernas evitarás esa la fricción entre ellas, haciéndolo perfectos para salir a caminar, correr o ir al gimnasio. Esta será tu prenda favorita para todas tus actividades deportivas, ¡es perfecto para usar bajo pantalonetas sueltas! Incluso, en climas fríos puedes usarlo bajo jeans o pantalones largos.\r\n\r\n', 278.4, 'si'),
(374, 'Bóxer Para Niños Largo en Algodón', '33294', 'ninos', 'leo', 'Bóxer largo con buen cubrimiento de los muslos, está elaborado en algodón spandex, se ajusta al cuerpo con gran comodidad, ofreciendo máxima frescura y libertad de movimiento. Suave elástico ancho en la cintura con excelente ajuste.', 'Bóxer para niño con buen cubrimiento de los muslos\r\nTotal confort y excelente modelación\r\nPinza anatómica\r\nSuave elástico ancho en la cintura\r\nRefuerzo inferior 100% en algodón\r\nComposición: ALGODÓN 71.00%, poliamida 21.00%, elastano 8.00%, Composición Forro: ALGODÓN 94.00%, elastano 6.00%.\r\n\r\n', 146.16, 'si'),
(375, 'BÓXER MEDIO DE SECADO RAPIDO', '33300', 'hombre', 'leo', 'Bóxer medio elaborado en DuraFit®: un material suave, ligero y cómodo. Es ideal para practicar deporte, ya que es transpirable, de secado rápido y evita la fricción entre las piernas. Además, cuenta con un cómodo elástico ancho y suave que no se enrolla.', '\"Bóxer medio ideal para practicar deportes\r\nElaborado en DuraFit®: un material suave, ligero y cómodo\r\nTranspirable, de secado rápido y antifricción\r\nPinza ergonómica con mayor profundidad\r\nElástico ancho y suave que no se enrolla\r\nComposición: 82% Poliamida, 11% Elastano, 7% Poliester\"', 243.6, 'si'),
(376, 'Bóxer medio diseño ergonómico ultrafresco y cómodo en microfibra', '33300N', 'hombre', 'leo', ' Bóxer ultracómodo elaborado con tela texturizada que permite el paso del aire.\r\n- Silueta: bóxer medio.\r\n- Con FitTech: nuestro material exclusivo poroso, transpirable, de peso liviano y total suavidad.\r\n- Diseño frontal ergonómico: más ajuste y soporte para más comodidad.\r\n- Material de secado rápido: frescura total.\r\n- Suave al tacto.', '¡La comodidad y la frescura van primero! Este bóxer medio cuenta con diseño frontal ergonómico que garantiza mayor ajuste y soporte con total comodidad. Está elaborado con FitTech, nuestro material exclusivo poroso y de tacto ultrasuave que al ser ligero y transpirable hace que olvides que llevas un bóxer puesto. El largo en las piernas evita el roce entre ellas y su elástico en cintura es ultraplano y muy suave, evitando que se enrolle. Es de secado rápido y su tela texturizada permite el paso del aire para que te sientas muy fresco todo el tiempo. Es tan suave al tacto que notarás la diferencia con tus otros bóxers. Úsalo para el día a día, o para hacer deporte.', 243.6, 'si'),
(377, 'BÓXER MEDIO DEPORTIVO CON BOLSILLO LATERAL', '33309', 'hombre', 'leo', 'Este bóxer medio es ideal para hacer ejercicio o para uso diario. Tiene un bolsillo incorporado en la parte lateral, para que puedas guardar tus objetos personales, como celular, dinero, documentos, llaves o lo que necesites; para mantenerlos contigo todo el tiempo. El largo de las piernas, evita el roce entre ellas y lo hace muy cómodo. Está elaborado en microfibra: un material muy suave y resistente. Su tela tiene un efecto antimicrobiano, que te mantiene seco, cómodo y libre de olores.', '\"Bóxer medio, ideal para hacer ejercicio o para uso diario\r\nPráctico bolsillo lateral para guardar tus objetos personales: dinero, celular, etc.\r\nElaborado en microfibra: un material suave y resistente\r\nTela antimicrobiana: te mantiene seco y libre de olores\r\nAjuste perfecto y largo que evita el roce entre las piernas\r\nTranspirable y de secado rápido\r\nPinza para mayor soporte\r\nComposición: 76% poliamida, 16% elastano, 8% poliéster\"\r\n', 292.32, 'si'),
(380, 'BRASIER WOW DE TRIPLE REALCE ', '11968', 'mujer', 'leonisa', 'Este increíble brasier de triple realce, aumenta una talla y media de tu busto, logrando un efecto irresistible. Además del arco, los tres pads de espuma en la copa, centran y aumentan el busto para un efecto más redondeado y realzado. ¡Es perfecto como strapless! Ya que cuenta con suaves varillas laterales y una espalda con bandas antideslizantes, que te garantizan que la prenda permanezca en su lugar. Abróchalo en cualquiera de sus cuatro niveles y verás cómo se ajusta a tu silueta a la perfección. ¡Luce un escote que va a hacer que todos digan: WOW!\r\n\r\n', 'Brasier WOW de triple realce que aumenta una talla y media de copa.\r\n3 pads de espuma internos en la copa: mega realce.\r\nEs ideal para busto pequeño y mediano, ya que genera el realce extremo que siempre quisiste.\r\nEscote profundo con detalle en x para darle un toque diferenciado y llamativo.\r\nArcos que la dan buen soporte a tu busto.\r\nVarillas laterales y bandas antideslizantes en espalda, que te aseguran que el bra permanezca en su lugar.\r\nEspalda ancha, con tres broches y cuatro niveles graduables para un ajuste perfecto.\r\nOjales en copas y espalda para usar con cargaderas (incluidas).\r\nProducido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\nComposición: 72% poliamida, 19% elastano, 9% silicona. Composición forro: 83% poliamida, 17% elastano.', 647.28, 'si'),
(381, 'BODY FAJA PANTALON INVISIBLE', '12727', 'mujer', 'leonisa', 'Este panty faja tiro alto está elaborado con tecnología SkinFuse sin costuras que moldean tu cuerpo: siéntete cómoda y estilizada al mismo tiempo. Su material es perfecto para disimular la celulitis. Controla el abdomen alto, medio y bajo, la cintura, los muslos y la parte baja de las piernas, además le dará a tu cintura un efecto reloj de arena gracias a sus cortes estratégicamente localizados. Cubre tu cuerpo desde el abdomen hasta los tobillos sin marcarse, además, su tejido tiene más elongación en los tobillos para facilitar que la prenda se adapte al ancho de tus piernas. Esta faja pantalón tiene diferentes tensiones en el tejido que hacen que la compresión sea mucho más fuerte en la parte lateral de los muslos y debajo de los glúteos para generar un efecto de realce. Es invisible bajo tu ropa y lo mejor es que puedes usarla con tu brasier favorito. Es perfecta para usar con pantalones ajustados.', 'Panty faja invisible de control moderado en abdomen alto, medio y bajo.\r\nDisimula la celulitis en glúteos y piernas.\r\nTecnología SkinFuse sin costuras que genera control y se siente como una segunda piel.\r\nCortes estratégicos para una cintura efecto reloj de arena. Tensiones inteligentes que ejercen más control en la parte lateral de los muslos y bajo los glúteos para un efecto levanta cola.\r\nSin control sobre los glúteos para no aplanarlos y tejido inferior que los realza.\r\nCargaderas graduables y removibles para uso convencional o cruzadas.\r\nSe adapta al ancho de las piernas gracias a la elongación del tejido.\r\nPráctica abertura inferior que facilita ir al baño.\r\nHemos realizado una actualización en la tecnología de medición de nuestras prendas de control, por lo que el nivel de control comunicado en las etiquetas puede ser diferente a la descripción de la prenda. Guíate por esta y no por la etiqueta y si tienes dudas contáctanos.\r\nProducido de manera sostenible en Colombia, bajo prácticas laborales justas.\r\nComposición: 80% poliamida, 20% elastano.', 334.08, 'si'),
(382, 'BRASIER ESTAMPADO CON COPA  ', '0406061', 'mujer', 'touche', 'Con copa y varilla estampado en Lycra nylon.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 49, 'no'),
(383, 'BRASIER CON COPA Y ENCAJE ', '0464061', 'mujer', 'touche', 'Con copa en Lycra nylon con encaje.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 389.76, 'si'),
(384, 'BRASIER BUSTIER CON COPA Y ARO ENCAJE DE MOTIVOS FLORALES ', '111001', 'mujer', 'ellipse', 'Bustier con copa y aro, en encaje francés de motivos florales.', 'Descripción del ProductoBustier con copa y aro, en encaje francés de motivos florales que cubre la copa espuma y el contorno de la espalda, elástico transparente en base que permite mostrar la belleza de la mora del encaje, delicados sesgos brillantes en curvatura de base de copas y en contorno de sisas. En parte inferior de la base de encaje tienen tulle transparente que se funde con la piel, sobre este en el frente, flores  de encaje delicadamente cortadas y pegadas manualmente para garantizar su durabilidad dando la apariencia de estar flotando sobre el cuerpo.', 626.4, 'si'),
(385, 'BRASIER CON BROCHE DELANTERO Y DISEÑO EN ESPALDA ', '111011', 'mujer', 'ellipse', 'Tul en copa con broche frontal metálico dorado. Espalda en encaje francés bordado.', 'Descripción del ProductoBrasier romántico, tul en copa con broche frontal metálico dorado. Espalda en delicado encaje francés bordado.', 556.8, 'si'),
(386, 'BRASIER CON FLORES EN TERCIOPELO ', '111068', 'mujer', 'ellipse', 'Bustier copa y aro en tul elástico transparente bordado, con flores en terciopelo y cargaderas en elástico de terciopelo de estampado floral.', 'Descripción del ProductoBustier copa y aro en tul elástico transparente bordado, con flores en terciopelo y cargaderas en elástico de terciopelo de estampado floral.', 522, 'si'),
(387, 'BRALETTE FLORAL ', '111069', 'mujer', 'ellipse', 'Bralette en encaje elástico con aplique floral flotante en copa, cargadera decorada.', 'Descripción del ProductoBralette en encaje elástico con aplique floral flotante en copa, cargadera decorada.', 466.32, 'si'),
(388, 'BUSTIER SIN COPA ', '111075', 'mujer', 'ellipse', 'Bustier sin copa con aro en tul elástico transparente con apliques cortados a láser en la copa y con sesgos en terciopelo.', 'Descripción del ProductoBustier sin copa con aro en tul elástico transparente con apliques cortados a láser en la copa y con sesgos en terciopelo.', 382.8, 'si'),
(389, 'BRASIER ARO SIN COPA ', '111078', 'mujer', 'ellipse', 'Bra aro sin copa en encaje elástico de picos con recogido en cargadera y cristales SWAROVSKI.', 'Descripción del ProductoBra aro sin copa en encaje elástico de picos con recogido en cargadera y cristales SWAROVSKI.', 528.96, 'si'),
(390, 'BUSTIER ARO SIN COPA ', '111079', 'mujer', 'ellipse', 'Bustier aro sin copa en encaje elástico de picos con pieza de encaje en el hombro y cristales SWAROVSKI.', 'Descripción del ProductoBustier aro sin copa en encaje elástico de picos con pieza de encaje en el hombro y cristales SWAROVSKI.', 535.92, 'si'),
(391, 'BRASIER PUSH UP ', '111086', 'mujer', 'ellipse', 'Push up triangular largo aro y copa, con triangulo invertido en espalda, en encaje elástico de picos y cristales SWAROVSKI.', 'Descripción del ProductoPush up triangular largo aro y copa, con triangulo invertido en espalda, en encaje elástico de picos y cristales SWAROVSKI.', 542.88, 'si'),
(392, 'BRASIER TRIANGULAR DE REALCE ALTO CON ARCO  ', '11892', 'mujer', '', 'Brasier con arco y copas triangulares que cubren muy bien el busto; realce alto incorporado, copas con diseño especial en la espuma para dar el realce. El interior de las copas es más ancho, un diseño con cortes atrevidos, un look retro, más fresco y joven. Suaves varillas laterales y frontales que le dan una modelación excelente al busto y mayor soporte.', 'Descripción del ProductoEspalda ancha elaborada en tela ultraliviana que da sensación máxima de frescura, suavidad y ligereza.Se adapta al cuerpo con delicadeza para dar un confort extremo.Elástico plano en la base y espalda que da mayor ajuste.Espalda más ancha con buen cubrimiento.Cargaderas integradas a la copa son graduables y brindan excelente soporte', 334.08, 'no'),
(393, 'BRASIER CON BROCHE DELANTERO Y DISEÑO EN ESPALDA ', '11905', 'mujer', 'ellipse', 'Romántico brasier, con copa y aro, broche delantero de gran seguridad.', 'Descripción del ProductoRomántico brasier, con copa y aro, broche delantero de gran seguridad. Tulle al tono que se sobrepone en la copa y pequeño encaje en escote.  Costados en  lycra y espalda decorativa con detalle de bordado, esta pieza esta forrada con tulle de gran suavidad brindando mejor confort, ideal para que lo uses con prendas de hombros abiertos, transparencias leves, espaldas descubiertas y vestidos.', 556.8, 'si'),
(394, 'BRASIER TRIANGULAR SIN ESPUMA Y APLIQUE BORDADO ', '11906E', 'mujer', 'ellipse', 'Brasier triangular, sin copa espuma, con copas en tulle piel.', 'Brasier triangular, sin copa espuma, con copas en tulle piel para ambos colores, con elástico en base de copas forrado en lycra navy, con tulle y aplique bordado pegado a mano, cargadera y escote en cinta velvet y abrochadura de 4 posiciones en espalda.', 459.36, 'si'),
(395, 'BRASIER SUBLIME STRAPLESS CON TULLE ', '11925', 'mujer', 'ellipse', 'Brasier Bustier en color crudo, con tulle doble al tono en copas, copa de espuma.', 'Descripción del ProductoBrasier Bustier en color crudo, con tulle doble al tono en copas, encaje importado en base completa, la copa es de espuma, con aro y cargadera multiusos removible .', 459.36, 'si'),
(396, 'BRASIER COPAS EN TULLE CON ENCAJE CON HEBRAS SUELTAS ', '11929E', 'mujer', 'ellipse', 'Brasier en color crudo, copa en tulle, con encaje con hebras sueltas en bordes de mora al tono del tulle en base completa.', 'Descripción del ProductoBrasier en color crudo, copa en tulle, con encaje con hebras sueltas en bordes de mora al tono del tulle en base completa. Puntilla al tono en escote, copa espuma cruda y gris, complemento de cargadera en encaje, con broche en cargadera para cruzar en espalda.', 410.64, 'si'),
(397, 'BRASIER DE REALCE ALTO CON ARCO FLEXIBLE ', '11943', 'mujer', '', 'Este es un brasier como ningún otro, ya que el poder que tiene en sus copas, es inigualable: cuenta con una espuma incorporada de última tecnología que genera un sexy y natural realce alto. Este bra no tiene arco interno, el cual es reemplazado por una malla flexible que te da el mismo soporte que el arco pero con absoluta comodidad. Además, tiene una silueta cuadrada que te va a encantar, ya que al ser más horizontal, te permite lucir escotes mucho más pronunciados. Úsalo, encanta y déjate encantar.', 'Descripción del ProductoBrasier triangular media copa de realce alto y escote cuadradoUna malla flexible reemplaza el arco, creando un soporte con comodidadCopas con espuma incorporada que generan un realce altoBuen cubrimiento en la sisa, que minimiza esos molestos gorditosEspalda con muy pocas costuras, lo que le da una apariencia muy limpiaCargaderas graduables y removibles para uso convencional, cruzadas o halterAbrochadura doble con cuatro niveles de ajusteComposición: poliamida 80%, elastano 20%', 382.8, 'no'),
(398, 'BRASIER TRIANGULAR TIPO TOP CON ENCAJE ', '11951', 'mujer', 'ellipse', 'Brasier triangular tipo top en colores crudo y rosado, sin copa espuma.', 'Descripción del ProductoBrasier triangular tipo top en colores crudo y rosado, sin copa espuma, con encaje en casi todas sus piezas, tiene forro de copas y complemento de espalda, espalda racer back con elástico en todo el contorno y en sisa.', 382.8, 'si'),
(399, 'BRASIER BUSTIER CON ENCAJE EN RELIEVE ', '11976E', 'mujer', 'ellipse', 'Brasier bustier sin copa espuma, con varilla y con encaje jackard en alto relieve.', 'Descripción del ProductoBrasier bustier en color crudo y negro, sin copa espuma, con varilla y con encaje jackard en alto relieve, complemento de cargadera en encaje sobre hombro y abrochadura de 4 posiciones.', 591.6, 'si'),
(400, 'BRASIER CON COPA Y ARO EN BLONDA NEGRA ', '11979', 'mujer', 'leonisa', 'Brasier balconet en blonda negra, con copa espuma moca haciendo contraste.', 'Brasier balconet en blonda negra, con copa espuma moca haciendo contraste. Detalles de franja escote y puntillas en centro de copa y cargaderas negras. El brasier va forrado en cotilla y espaldas en tulle color moca, las cargaderas tienen Z en espalda para segunda opción cruzado, abrochadura con 4 posiciones.', 487.2, 'si'),
(401, 'BRASIER SIN COPA CON ARO EN ENCAJE ', '11988', 'mujer', 'leonisa', 'Brasier con copa y aro, copas forradas en encaje.', 'Descripción del ProductoBrasier con copa y aro, copas forradas en encaje con motivos florales en crudo. Encaje con diseño en espalda.', 522, 'si'),
(402, 'BRASIER REALCE GEMA ', '15040', 'mujer', 'leonisa', 'Brasier que brinda soporte, realce y cubrimiento. Liso en su corte delantero, un básico infaltable, es ideal para lucir una figura única y perfecta.', 'Color: MarfilGénero: Mujer Nivel de control: MediaZona de control: BustoMecanismos de ajuste: Liso', 264.48, 'si'),
(403, 'BRASIER REALCE RUBI ', '15042', 'mujer', 'fajate', 'Brasier que brinda soporte, realce y cubrimiento.', 'Color: MarfilGénero: MujerNivel de control: MediaZona de control: BustoMecanismos de ajuste: Liso', 348, 'si'),
(404, 'BRASIER REALCE DIAMANTE ', '15048', 'mujer', 'leonisa', 'Brasier diseñado para resaltar con la sutileza más armónica tus curvas, entalla tu torso mientras centra y realza tú busto.', 'Descripción del ProductoBrasier diseñado para resaltar con la sutileza más armónica tus curvas, entalla tu torso mientras centra y realza tú busto.', 348, 'no'),
(405, 'BRASIER CON COPA EN ENCAJE ', '2453062', 'mujer', 'touche', 'Brasier con copa en encaje y lycra nylon.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 403.68, 'si'),
(406, 'BRASILERA ESTAMPADA ', '0106061', 'mujer', 'touche', 'Brasilera estampada en Lycra nylon.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 167.04, 'no'),
(407, 'BRASILERA CON ENCAJE ', '0116M61', 'mujer', 'touche', 'Brasilera en Lycra nylon con encaje.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 180.96, 'si'),
(408, 'BRASILERA CON ENCAJE ', '0127061', 'mujer', 'touche', 'Brasilera en Lycra nylon con encaje.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 243.6, 'si'),
(409, 'BRASILERA CON ENCAJE EN CINTURA ', '0145061', 'mujer', 'touche', 'Brasilera en lycra nylon con encaje en cintura.', 'Descripción del ProductoLencería fina y exclusiva en tonos suaves con encajes delicados. Son la clave para que la mujer se sienta sexy, joven, atractiva y romántica en su día a día. Expresa al máximo tu femineidad en todas las ocasiones. La importancia de usar lencería perfecta es sentirte linda y no para que otros la vean.', 222.72, 'si'),
(410, 'PANTY CON CRISTALES SWAROVSKI ', '121080', 'mujer', 'ellipse', 'Slip en encaje elastico de picos y tela de corte limpio con abertura en posterior y crsitales Swarovski.', 'Si necesitas un poco de soporte y realce este es para ti. Panty  de encaje elástico de picos y tela de corte limpio con abertura en posterior y cristales Swarovski', 264.48, 'si'),
(411, 'PANTY HIPSTER INVISIBLE MÁS CÓMODO ', '12603', 'mujer', 'leonisa', 'Panty hipster en DuraFit® de máxima comodidad, con ajuste suave y efecto invisible. Su diseño sin costuras ni elásticos se adapta al cuerpo sin marcar, brindando libertad total en cada movimiento.', 'Panty Hipster Invisible en DuraFit®\r\n• Composición: 76.9% poliamida – 23.1% elastano\r\n• Diseño sin costuras ni elásticos que evita marcas y roces\r\n• Tecnología termofusionada que mejora el ajuste y la durabilidad\r\n• Corte láser que proporciona acabados limpios y efecto invisible\r\n• Tela DuraFit® suave, elástica y de alta adaptación al cuerpo\r\n• Sensación ligera y cómoda para uso prolongado\r\n• Refuerzo inferior 100% en algodón para mayor frescura e higiene', 153.12, 'si'),
(412, '3 TANGAS SEMI-DESCADERADAS EN ALGODÓN ', '12676X3', 'mujer', 'leonisa', 'Paquete de 3 tangas con variedad de estampados y colores, se ajustan perfectamente a tu cuerpo y te mantienen fresca y cómoda durante todo el día. Sus costuras ultraplanas no te marcan la piel ni se marcan en la ropa.', 'Paquete x 3 tangas.Elaboradas con algodón elástico.Elásticos y costuras ultraplanas que no se marcan.Diseño semidescaderado.Máxima comodidad y suavidad al contacto con la piel.Refuerzo inferior 100% en algodón para tu comodidad.Composición de la tela: 69% Algodón, 21% Poliamida, 10% Elastano.', 229.68, 'si'),
(413, 'Pack x2 calzón colaless invisible ultraplano sin elásticos ', '12720X2 ', 'mujer', 'leonisa', 'Pack x2 de panty colaless invisible de tiro medio, ultraligero y suave. Su diseño sin elásticos ni costuras se adapta al cuerpo sin marcar, brindando máxima comodidad.', 'Pack x2 Panty Colaless Invisible Ultraplano\r\n• Composición: 90% poliamida – 10% elastano\r\n• Tiro medio con ajuste cómodo que se adapta al cuerpo\r\n• Diseño sin elásticos y con pocas costuras para efecto invisible\r\n• Tela ligera, suave y ultraplano que no se marca en la ropa\r\n• Acabados de alta tecnología que mejoran la comodidad y durabilidad\r\n• Sensación de libertad total, como no llevar nada puesto\r\n• Ideal para prendas ajustadas por su efecto imperceptible', 278.4, 'si'),
(414, 'TANGA INVISIBLE CON TELA INTELIGENTE ', '12721', 'mujer', 'leonisa', 'Tanga invisible en DuraFit®, suave y ligera, con tecnología de termofusión sin costuras. No se marca ni se enrolla bajo la ropa. Ideal para un efecto segunda piel con máximo confort diario.', 'Tanga Invisible DuraFit® sin Costuras\r\n• Composición: 58% poliamida – 42% elastano / refuerzo 100% algodón\r\n• Tecnología DuraFit® que aporta suavidad, frescura y durabilidad\r\n• Diseño sin costuras con unión por termofusión (sellado por calor)\r\n• Corte láser que evita marcas visibles bajo la ropa\r\n• No se enrolla ni se desplaza durante el uso\r\n• Ajuste tipo segunda piel que se adapta al cuerpo con suavidad\r\n• Refuerzo inferior en algodón que brinda comodidad e higiene\r\n• Sensación ligera, fresca y de máxima libertad de movimiento\r\n• Ideal para uso diario y prendas ajustadas gracias a su efecto invisible', 187.92, 'si'),
(415, 'HIPSTER INVISIBLE CON TELA INTELIGENTE ', '12722', 'mujer', 'leonisa', 'Panty hipster invisible en DuraFit® que brinda ajuste perfecto y comodidad extrema. Su diseño sin costuras ni elásticos se adapta al cuerpo sin marcar, ofreciendo una sensación ligera y suave.', 'Panty Hipster Invisible en DuraFit® Alta Tecnología\r\n• Composición: 58% poliamida – 42% elastano\r\n• Diseño sin costuras ni elásticos que evita marcas y roces\r\n• Tecnología DuraFit® que ofrece ajuste firme, ligero y resistente\r\n• Tela inteligente que no se enrolla y se mantiene en su lugar\r\n• Material fresco, suave y elástico que se adapta al cuerpo\r\n• Sensación de comodidad extrema y libertad de movimiento\r\n• Refuerzo inferior 100% en algodón para mayor frescura e higiene', 187.92, 'si'),
(416, 'PAQUETE X 2 HIPSTERS INVISIBLES CON TELA INTELIGENTE ', '12722X2', 'mujer', 'leonisa', 'Experimenta la comodidad extrema con este hipster invisible, elaborado en DuraFit? sin costuras y con una novedosa tecnología que no permite que se marque en la piel o en la ropa.', 'Descripción del Producto\"Panty estilo hipster invisibleElaborado en DuraFit?, una tela fresca, resistente y livianaAlta tecnología, sin elásticos ni costurasTela inteligente que no se enrollaNo se marca en la ropa ni talla en la pielRefuerzo inferior 100% en algodón para mayor comodidadComposición de la tela: 58% Poliamida, 42% Elastano\"', 285.36, 'si'),
(417, 'Panties tipo Bikini Clásicos y Confortables ', '12744', 'mujer', 'leonisa', 'pantie elegante, alto en la cintura con buen cubrimiento del abdomen medio-bajo y cubrimiento medio de la cola. Están elaborados con algodón elástico que te ofrece gran suavidad y un ajuste perfecto al cuerpo lo que te brinda la modelación que estás buscando en tus prendas íntimas, las costuras son planas y los elásticos no se marcan en tu ropa y no maltratan la piel. Una encantadora prenda con delicados detalles en encaje elástico que realzan tu feminidad y brindan confort total.', 'Panties estilo bikini.Cubrimiento medio de la cola.Alto en la cintura para un mejor cubrimiento del abdomen medio-bajo.Elaborado en algodón elástico que te ofrece mayor suavidad y comodidad.Delicado encaje elástico en la parte delantera que te da un toque femenino.Elásticos y costuras planas que no se marcan en la ropa ni tallan la piel.Refuerzo inferior 100% en algodón para mayor comodidad.Composición de la tela: poliéster 57.00%, poliamida 20.00%, ALGODÓN 15.00%, elastano 8.00%.', 132.24, 'si'),
(418, 'PAQUETE X 3 PANTIES TIPO BIKINI CLÁSICOS Y CONFORTABLES ', '12744X3', 'mujer', 'leonisa', 'Paquete por 3 panties elegantes, altos en la cintura con buen cubrimiento del abdomen medio-bajo y cubrimiento medio de la cola. Están elaborados con algodón elástico que te ofrece gran suavidad y un ajuste perfecto al cuerpo lo que te brinda la modelación que estás buscando en tus prendas íntimas, las costuras son planas y los elásticos no se marcan en tu ropa y no maltratan la piel. Una encantadora prenda con delicados detalles en encaje elástico que realzan tu feminidad y brindan confort total.', 'Paquete de 3 panties estilo bikini-Cubrimiento medio de la cola-Alto en la cintura para un mejor cubrimiento del abdomen medio-bajo-Elaborado en algodón elástico que te ofrece mayor suavidad y comodidad-Delicado encaje elástico en la parte delantera que te da un toque femenino-Elásticos y costuras planas que no se marcan en la ropa ni tallan la piel-Refuerzo inferior 100% en algodón para mayor comodidad-Composición: poliéster 57.00%, poliamida 20.00%, ALGODÓN 15.00%, elastano 8.00%.', 354.96, 'si'),
(419, '3 Boxers con Excelente Cubrimiento de Abdomen y Cadera ', '12745X3', 'mujer', 'leonisa', 'Paquete de 3 bóxer altos en cintura, con muy buen cubrimiento del abdomen, la combinación de la delicadeza del encaje elástico y la suavidad del algodón te ofrecen una encantadora experiencia. Detalles simples que te harán sentir elegante y muy cómoda.', 'Descripción del Producto3 panties estilo bóxer con buen cubrimiento.Elaborado en algodón muy suave al tacto.Encaje elástico en cintura que te da una apariencia elegante.Costuras planas en pierna que no se marcan ni tallan.Refuerzo inferior 100% en algodón para mayor comodidad.Composición: poliéster 56.00%, poliamida 23.00%, ALGODÓN 14.00%, elastano 7.00%.', 348, 'si'),
(420, 'PAQUETE x 3 BOXERS SEMIDESCADERADOS EN ALGODON ', '12760X3', 'mujer', 'leonisa', 'Paquete x3 panties estilo boxer con elástico en cintura que no se marca en tu ropa ni te talla en la piel. Máximo confort con excelente modelación, perfectos para el día a día además su refuerzo inferior es 100% algodón para que te sientas más cómoda. Son ideales para los momentos en los cuales quieras descansar en casa, tomar un espacio para ti o para tus looks más descomplicados.', 'Paquete x 3 boxers cortos elaborados en algodón elástico.Panties de máxima comodidad y excelente modelación.Elástico en cintura que evita que se marque en la ropaRefuerzo inferior 100% en algodón para mayor comodidadComposición: ALGODÓN 79.00%, poliamida 11.00%, elastano 10.00%', 382.8, 'si'),
(421, 'PANTY FAJA BRASILERA DE CONTROL FUERTE ', '12766', 'mujer', 'leonisa', 'Brasilera alta en la cintura y con laterales anchos que te brindan más cubrimiento y control del abdomen. Diseño de alta tecnología que combina materiales como PowerSlim y DuraFit para ofrecerte los beneficios de control, total comodidad y frescura.', 'Descripción del Producto-Panty estilo brasilera con buen cubrimiento en los laterales-PowerSlim y DuraFit que generan control fuerte en abdomen-Tela brillante en abdomen que contrasta con la tela mate del fondo-Cortes ergonómicos en la parte delantera que ayudan a enmarcar la silueta-Refuerzo inferior 100% en algodón para mayor comodidad-Composición: poliamida 77.00%, elastano 23.00%.', 229.68, 'no'),
(422, 'Panty faja invisible de control moderado efecto brasilera ', '12769', 'mujer', 'leonisa', 'Por qué te encantará- Panty faja tipo short con apariencia de brasilera.- Silueta: short corto.- Control moderado en abdomen medio. Control suave en abdomen bajo.- Evita el roce entre los muslos: ideal para faldas o vestidos.- Recogido en el centro de los glúteos, que les da una modelación muy natural.- Menos costuras para mayor comodidad e invisibilidad.- Refuerzo inferior 100% en algodón.Hemos realizado una actualización en la tecnología de mediciónde nuestras prendas de control, por lo que el nivel de controlcomunicado en las etiquetas puede ser diferente a la descripciónde la prenda. Guíate por esta y no por la etiqueta y si tienes dudascontáctanos.', 'Panty faja tipo short con apariencia de brasilera.Control moderado en abdomen medio y bajo.Panel delantero que ofrece mayor control en el abdomen.Corte y recogido en el centro de los glúteos.', 194.88, 'si'),
(423, 'PANTY CLÁSICO DE MAXIMA COMODIDAD Y FRESCURA ', '12771', 'mujer', 'leonisa', 'Pantie tipo hipster, elaborados en algodón elástico que te ofrece gran comodidad, frescura y un contacto suave con tu piel. Esta es una silueta muy buscada por su estilo y por su increíble comodidad. Se ajustan perfectamente a tu cuerpo y te dan una modelación perfecta, sus elásticos planos en microfibra en la cintura te ofrecen gran suavidad y no marcan la piel.', 'Panties estilo clásicoAjuste perfecto, excelente modelación y máxima comodidadBuen cubrimiento de la colaElaborados en algodón elástico supersuaveComposición: algodón 63%, poliamida 26%, elastano 11%Elásticos en microfibra en cintura que no marcan la pielRefuerzo inferior 100% en algodón para mayor comodidad', 146.16, 'si');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`) VALUES
(424, 'Panty estilo cachetero en encaje con transparencias y bordes redondeados ', '12969', 'mujer', 'leonisa', 'Panty cachetero en encaje elástico con transparencias que brinda ajuste suave y efecto invisible. Su diseño delicado realza la figura con un toque romántico y cómodo.', 'Panty Cachetero en Encaje con Transparencias y Moras\r\n• Composición: 86.1% poliamida – 13.9% elastano\r\n• Ajuste cómodo que se adapta al cuerpo con total suavidad\r\n• Diseño sin elásticos en cintura y piernas para evitar marcas\r\n• Encaje elástico con transparencias y bordes tipo moras de acabado delicado\r\n• Corte central trasero que brinda modelación natural a los glúteos\r\n• Sensación ligera, fresca y confortable durante todo el día\r\n• Refuerzo inferior 100% en algodón para mayor higiene y comodidad\r\n• Elaborado bajo prácticas sostenibles que garantizan calidad y responsabilidad', 111.36, 'si'),
(425, 'Panty faja clásico invisible con transparencias en glúteos y laterales ', '12984 ', 'mujer', 'leonisa', 'Por qué te encantaráPanty clásico con control moderado en abdomen.¡Es invisible bajo tu ropa! No tiene elásticos en la pierna.Gracias a su costura central recogida de la parte trasera, le da una forma más redondeada a los glúteos.Costuras planas que la hacen más suave y cómoda.Refuerzo 100% en algodón para que te sientas fresca todo el día.', 'El panty perfecto sí existe y por eso querrás usarlo todos los días, ya que controla tu abdomen y moldea tu figura. Es un panty clásico alto en cintura y sus costuras son ultraplanas para un aspecto invisible bajo tu ropa. Cuenta con un increíble tul con diseño de cebra, en los laterales y glúteos, que le da un toque femenino y muy sexy. Es efecto brasilera y tus glúteos lucirán con una modelación más redondeada. Gracias a su comodidad y sensualidad vas a querer uno para cada día.', 229.68, 'si'),
(426, 'Panty estilo tanga brasilera con laterales y encaje ', '12985', 'mujer', 'leonisa', 'Esta tanga brasilera semidescaderada, cuenta con laterales anchos y parte trasera en encaje que la hacen muy femenina y sexy. En la parte delantera el detalle triangular en tul, le da un toque de mucho estilo y de última tendencia. También está elaborada en microfibra, un material muy suave al tacto. Sus elásticos planos en cintura y pierna son muy delicados con tu piel y de apariencia invisible. Sus laterales te brindan mayor cubrimiento. Su refuerzo interno en algodón 100% es muy cómodo y fresco.', 'Tanga estilo brasilera elaborada en microfibra, tul y encaje.Laterales anchos con más cubrimiento en cadera y glúteos.Elásticos ultraplanos en cintura y parte delantera de las piernas para mayor comodidad y apariencia invisible.Refuerzo en algodón 100% para mayor comodidad.Composición: 81.4% poliamida, 18.6% elastano.', 160.08, 'si'),
(427, 'Panty tipo tanga en tul con refuerzo interno en algodón ', '12991', 'mujer', 'leonisa', 'Tanga de tiro medio y apariencia invisible con elástico ultra plano en cintura. Este panty hará que te sientas sexy y cómoda a la vez, ya que está elaborado en tul y microfibra, materiales muy suaves y livianos. El cómodo elástico ultra plano de la cintura se ajusta a tu cuerpo, y el poco cubrimiento en los laterales, le da ese toque de diseño diferente y de tendencia. El elástico en el centro de los glúteos hace que tengan una modelación más natural ¡Si te gusta usar brasileras, este también podría encantarte por su poco cubrimiento en los glúteos! Es ideal para que lo uses con prendas ajustadas ya que no se notará en tu ropa exterior. Su refuerzo en algodón la hace una prenda muy cómoda ¡Enamórate de una silueta 100% única y diferente!', 'Panty invisible tipo tanga de tiro medio.Elaborado en el frente en tul y tela lisa, y en los glúteos solo en tul, creando sensuales transparencias.Prenda invisible, ideal para usar con pantalones ajustados.El elástico recogido en el centro de los glúteos les da una modelación más natural.Elástico plano en la cintura, el cual permite un excelente ajuste y es muy suave al contacto con la piel.Refuerzo interno 100% en algodón para mayor comodidad.Composición: 79% poliamida, 21% elastano, composición forro: 69% poliamida, 31% elastano.', 104.4, 'si'),
(428, 'Panty short invisible de control de abdomen efecto levanta cola ', '12992', 'mujer', 'leonisa', 'Por qué te encantaráPanty short invisible ultrasuave y de tacto frío para que estés muy fresca todo el día.Silueta: short medio.Efecto invisible en piernas.Control moderado en abdomen y laterales de cintura. Elástico recubierto en cintura suave al contacto con la piel.Cortes que bordean los glúteos y los realzan. Disimula la celulitis en glúteos y piernas.Elaborado en DuraFit, un material fresco, ligero, suave y liviano. Doble capa en abdomen y espalda.Es ideal para usar bajo vestidos o pantalon.', 'Este panty short moldea tu figura, disimula la celulitis y realza tus glúteos. Es muy suave con tu piel ya que está elaborado en Durafit, un material fresco, ligero y de tacto frío. Su doble capa en abdomen y espalda baja, genera un control moderado en esta zona para que te veas más estilizada en segundos. Los cortes alrededor de los glúteos y el elástico recogido en el centro, dan un efecto levanta cola y una modelación más redondeada, ¡te encantará! Al no tener costuras en las piernas es de apariencia invisible bajo tu ropa, por lo que es ideal para usar con vestidos o pantalones ajustados sin que se note ni se marque. Cuenta con un refuerzo interno 100% en algodón para más comodidad ¡Este panty short invisible es el complemento perfecto para tus looks!', 452.4, 'si'),
(429, 'Panty cachetero de tiro medio en tul y encaje ', '12996', 'mujer', 'leonisa', 'Panty cachetero de tiro medio que combina comodidad y sensualidad. Su diseño sin elásticos y efecto moldeador realza la figura con un ajuste suave y natural.', 'Panty Cachetero de Modelación Natural\r\n• Composición: 90% poliamida – 10% elastano\r\n• Tiro medio con cubrimiento equilibrado en glúteos\r\n• Diseño sin elásticos en la parte trasera para mayor comodidad\r\n• Corte central posterior que realza y da forma natural a los glúteos\r\n• Tela suave, ligera y elástica que se adapta al cuerpo\r\n• Sensación fresca, cómoda y de libertad de movimiento\r\n• Refuerzo inferior 100% en algodón para mayor higiene y frescura\r\n• Elaborado bajo prácticas sostenibles que garantizan calidad y responsabilidad', 139.2, 'si'),
(430, 'Panties estilo hipster ', '12999', 'mujer', 'leonisa', 'Estos panties tipo hipster son ultracómodos y perfectos para el día a día. Su elástico en la cintura con logotipo, no se marca en tu ropa ni en tu piel. Son ultracómodos, suaves al tacto y de excelente ajuste. Su refuerzo inferior 100% en algodón hará que te sientas muy fresca. Son ideales para los momentos en los cuales quieras descansar en casa, para dormir o para tus looks más relajados todos los días de la semana.', 'Panties estilo hipster.Tiro medio.Máxima comodidad, suavidad al tacto.¡Uno para cada día de la semana!Elástico en cintura que no se marca en tu piel ni en tu ropa.Refuerzo inferior 100% en algodón.Composición: 58% poliéster, 16% poliamida, 15% algodón, 10% elastano, 1% silicona', 104.4, 'si'),
(431, 'PANTY BRASILERA EN ENCAJE CON ELÁSTICOS DECORATIVOS  ', '131001', 'mujer', 'ellipse', 'Romántica brasilera en encaje francés de motivos florales.', 'Romántica brasilera en encaje francés de motivos florales forrado con tulle color piel de gran suavidad y elásticos en cartera dos, con femenino detalle de  elásticos flotantes en cintura entrelazados en posterior, moños en laterales delanteros. Con refuerzo en algodón 100% para proteger tu zona íntima.', 243.6, 'si'),
