(580, 'KIMONO EN ENCAJE  ', '251005', 'mujer', 'ellipse', 'Kimono en encaje color blanco, transparente.', 'Kimono romántico en encaje color blanco, transparente, con motivos florales. Se cierra con el cinturón.', 807.36, 'si'),
(581, 'KIMONO LARGO FLORAL ', '251068', 'mujer', 'ellipse', 'Kimono largo en tejido plano de micro fibra elástico con estampado floral, para ajustar en cintura.', 'Descripción del ProductoKimono largo en tejido plano de micro fibra elástico con estampado floral, para ajustar en cintura.', 744.72, 'si'),
